const ProfiledLock = struct {
    mutex: *std.atomic.Mutex,
    stats: *MutexContentionStats,
    hold_start_ns: u64,
    profiled: bool,

    fn unlock(self: *@This()) void {
        if (!self.profiled) {
            self.mutex.unlock();
            self.* = undefined;
            return;
        }
        const hold_ns = elapsedSince(self.hold_start_ns);
        self.mutex.unlock();
        _ = self.stats.hold_ns.fetchAdd(hold_ns, .monotonic);
        atomicMaxU64(&self.stats.max_hold_ns, hold_ns);
        self.* = undefined;
    }
};

const ProfiledApplyLock = struct {
    rw_lock: *apply_rw_lock_mod.ApplyRwLock,
    stats: *MutexContentionStats,
    hold_start_ns: u64,
    profiled: bool,

    fn unlock(self: *@This()) void {
        if (!self.profiled) {
            self.rw_lock.unlockExclusive();
            self.* = undefined;
            return;
        }
        const hold_ns = elapsedSince(self.hold_start_ns);
        self.rw_lock.unlockExclusive();
        _ = self.stats.hold_ns.fetchAdd(hold_ns, .monotonic);
        atomicMaxU64(&self.stats.max_hold_ns, hold_ns);
        self.* = undefined;
    }
};

