var bench_metrics_enabled_cache: std.atomic.Value(u8) = .init(0);
var open_profile_enabled_cache: std.atomic.Value(u8) = .init(0);
var async_index_profile_enabled_cache: std.atomic.Value(u8) = .init(0);

fn envBoolEnabled(raw: []const u8) bool {
    return !(std.mem.eql(u8, raw, "0") or
        std.ascii.eqlIgnoreCase(raw, "false") or
        std.ascii.eqlIgnoreCase(raw, "no"));
}

fn waitForCachedBool(cache: *std.atomic.Value(u8)) bool {
    while (true) {
        switch (cache.load(.acquire)) {
            1 => return false,
            2 => return true,
            else => std.atomic.spinLoopHint(),
        }
    }
}

fn benchMetricsEnabled() bool {
    const cached = bench_metrics_enabled_cache.load(.monotonic);
    if (cached == 1 or cached == 2) return cached == 2;
    if (cached == 3) return waitForCachedBool(&bench_metrics_enabled_cache);
    if (bench_metrics_enabled_cache.cmpxchgStrong(0, 3, .acq_rel, .monotonic) != null) {
        return waitForCachedBool(&bench_metrics_enabled_cache);
    }
    if (comptime builtin.os.tag == .freestanding) {
        bench_metrics_enabled_cache.store(1, .release);
        return false;
    }
    const raw_z = getenv("ANTFLY_BENCH_METRICS") orelse
        getenv("ANTFLY_BENCH_BATCH_PROFILE") orelse {
        bench_metrics_enabled_cache.store(1, .release);
        return false;
    };
    const enabled = envBoolEnabled(raw_z);
    bench_metrics_enabled_cache.store(if (enabled) 2 else 1, .release);
    return enabled;
}

fn openProfileEnabled() bool {
    const cached = open_profile_enabled_cache.load(.monotonic);
    if (cached == 1 or cached == 2) return cached == 2;
    if (cached == 3) return waitForCachedBool(&open_profile_enabled_cache);
    if (open_profile_enabled_cache.cmpxchgStrong(0, 3, .acq_rel, .monotonic) != null) {
        return waitForCachedBool(&open_profile_enabled_cache);
    }
    if (comptime builtin.os.tag == .freestanding) {
        open_profile_enabled_cache.store(1, .release);
        return false;
    }
    const raw_z = getenv("ANTFLY_DB_OPEN_PROFILE") orelse
        getenv("ANTFLY_BENCH_METRICS") orelse {
        open_profile_enabled_cache.store(1, .release);
        return false;
    };
    const enabled = envBoolEnabled(raw_z);
    open_profile_enabled_cache.store(if (enabled) 2 else 1, .release);
    return enabled;
}

fn asyncIndexProfileEnabled() bool {
    const cached = async_index_profile_enabled_cache.load(.monotonic);
    if (cached == 1 or cached == 2) return cached == 2;
    if (cached == 3) return waitForCachedBool(&async_index_profile_enabled_cache);
    if (async_index_profile_enabled_cache.cmpxchgStrong(0, 3, .acq_rel, .monotonic) != null) {
        return waitForCachedBool(&async_index_profile_enabled_cache);
    }
    if (comptime builtin.os.tag == .freestanding) {
        async_index_profile_enabled_cache.store(1, .release);
        return false;
    }
    const enabled = if (getenv("ANTFLY_ASYNC_INDEX_PROFILE")) |raw_z|
        envBoolEnabled(raw_z)
    else
        benchMetricsEnabled();
    async_index_profile_enabled_cache.store(if (enabled) 2 else 1, .release);
    return enabled;
}

fn nsToMs(ns: u64) u64 {
    return ns / std.time.ns_per_ms;
}

fn logOpenProfile(path: []const u8, open_mode: OpenOptions.OpenMode, start_index_workers: bool, profile: OpenProfile) void {
    std.log.info(
        "db_open_profile path={s} mode={s} start_index_workers={} primary_store_ns={} core_resources_ns={} init_async_infrastructure_ns={} init_optional_runtimes_ns={} load_indexes_ns={} replay_pending_derived_ns={} start_index_workers_ns={} start_optional_runtimes_ns={} total_ns={}",
        .{
            path,
            @tagName(open_mode),
            start_index_workers,
            profile.primary_store_ns,
            profile.core_resources_ns,
            profile.init_async_infrastructure_ns,
            profile.init_optional_runtimes_ns,
            profile.load_indexes_ns,
            profile.replay_pending_derived_ns,
            profile.start_index_workers_ns,
            profile.start_optional_runtimes_ns,
            profile.total_ns,
        },
    );
}

fn logReplayCatchUpProfile(index_ref: index_manager_mod.ManagedIndexRef, applied_sequence: u64, stats: derived_worker.CatchUpStats) void {
    std.log.info(
        "db_replay_catch_up_profile index={s} kind={s} applied_sequence={} last_sequence={} scanned_entries={} applied_entries={} window_collect_ns={} apply_ns={}",
        .{
