var temp_path_nonce: u64 = 0;
var split_replay_artifact_nonce: u64 = 0;
const small_derived_text_compact_segment_threshold: usize = 6;
const derived_text_compact_segment_threshold: usize = 128;

fn threadedIo() if (builtin.os.tag == .freestanding) void else std.Io.Threaded {
    if (builtin.os.tag == .freestanding) return;
    return std.Io.Threaded.init(std.heap.page_allocator, .{});
}

fn monotonicTimeNs() u64 {
    return platform_time.monotonicNs();
}

fn elapsedSince(start_ns: u64) u64 {
    return monotonicTimeNs() - start_ns;
}

fn restoreIntentMarkerPathAlloc(alloc: Allocator, path: []const u8) ![]u8 {
    return try std.fmt.allocPrint(alloc, "{s}/.restore-intent", .{path});
}

fn restoreStateMarkerPathAlloc(alloc: Allocator, path: []const u8) ![]u8 {
    return try std.fmt.allocPrint(alloc, "{s}/.restore-state", .{path});
}

fn restoreImportMarkerPathAlloc(alloc: Allocator, path: []const u8) ![]u8 {
    return try std.fmt.allocPrint(alloc, "{s}/.restore-importing", .{path});
}

fn restoreRepairMarkerPathAlloc(alloc: Allocator, path: []const u8) ![]u8 {
    return try std.fmt.allocPrint(alloc, "{s}/.restore-runtime-repair-complete", .{path});
}

fn fileExists(path: []const u8) !bool {
    var io_impl = threadedIo();
    defer io_impl.deinit();
    std.Io.Dir.cwd().access(io_impl.io(), path, .{}) catch |err| switch (err) {
        error.FileNotFound => return false,
        else => return err,
    };
    return true;
}

fn deleteFileIfExists(io: Io, path: []const u8) !void {
    std.Io.Dir.cwd().deleteFile(io, path) catch |err| switch (err) {
        error.FileNotFound => {},
        else => return err,
    };
}

pub const RestoreState = struct {
    backup_id: []u8,
    location: []u8,
    snapshot_path: []u8,
    group_id: u64,
    phase: []u8,
    primary_restored: bool,
    runtime_repair_complete: bool,
    last_error: []u8,

    pub fn deinit(self: *@This(), alloc: Allocator) void {
        alloc.free(self.backup_id);
        alloc.free(self.location);
        alloc.free(self.snapshot_path);
        alloc.free(self.phase);
        alloc.free(self.last_error);
        self.* = undefined;
    }
};

pub const RestoreIdentity = struct {
    backup_id: []const u8,
    location: []const u8,
    snapshot_path: []const u8,
    group_id: u64,
};

fn restoreStateAlloc(
    alloc: Allocator,
    backup_id: []const u8,
    location: []const u8,
    snapshot_path: []const u8,
    group_id: u64,
    phase: []const u8,
    primary_restored: bool,
    runtime_repair_complete: bool,
    last_error: []const u8,
) !RestoreState {
    const backup_id_owned = try alloc.dupe(u8, backup_id);
    errdefer alloc.free(backup_id_owned);
    const location_owned = try alloc.dupe(u8, location);
    errdefer alloc.free(location_owned);
    const snapshot_path_owned = try alloc.dupe(u8, snapshot_path);
    errdefer alloc.free(snapshot_path_owned);
    const phase_owned = try alloc.dupe(u8, phase);
    errdefer alloc.free(phase_owned);
    const last_error_owned = try alloc.dupe(u8, last_error);
    errdefer alloc.free(last_error_owned);

    return .{
        .backup_id = backup_id_owned,
        .location = location_owned,
        .snapshot_path = snapshot_path_owned,
        .group_id = group_id,
        .phase = phase_owned,
        .primary_restored = primary_restored,
        .runtime_repair_complete = runtime_repair_complete,
        .last_error = last_error_owned,
    };
}

const RestoreImportState = struct {
    snapshot_root: []u8,
    identity: ?RestoreState = null,

    fn deinit(self: *@This(), alloc: Allocator) void {
        alloc.free(self.snapshot_root);
        if (self.identity) |*identity| identity.deinit(alloc);
        self.* = undefined;
    }
};

fn parseRestoreStateBool(value: []const u8) !bool {
    if (std.mem.eql(u8, value, "1")) return true;
    if (std.mem.eql(u8, value, "0")) return false;
    return error.InvalidRestoreState;
}

fn readRestoreStateForPathAlloc(alloc: Allocator, path: []const u8) !?RestoreState {
    const state_path = try restoreStateMarkerPathAlloc(alloc, path);
    defer alloc.free(state_path);

    var io_impl = threadedIo();
    defer io_impl.deinit();
    const raw = std.Io.Dir.cwd().readFileAlloc(io_impl.io(), state_path, alloc, .limited(64 * 1024)) catch |err| switch (err) {
        error.FileNotFound => return null,
        else => return err,
    };
    defer alloc.free(raw);

    var backup_id: ?[]u8 = null;
    errdefer if (backup_id) |value| alloc.free(value);
    var location: ?[]u8 = null;
    errdefer if (location) |value| alloc.free(value);
    var snapshot_path: ?[]u8 = null;
    errdefer if (snapshot_path) |value| alloc.free(value);
    var group_id: ?u64 = null;
    var phase: ?[]u8 = null;
    errdefer if (phase) |value| alloc.free(value);
    var primary_restored: ?bool = null;
    var runtime_repair_complete: ?bool = null;
    var last_error: ?[]u8 = null;
    errdefer if (last_error) |value| alloc.free(value);

    var lines = std.mem.splitScalar(u8, raw, '\n');
    const version = lines.next() orelse return error.InvalidRestoreState;
    if (!std.mem.eql(u8, version, "restore_state_v2")) return error.InvalidRestoreState;
    while (lines.next()) |line| {
        if (line.len == 0) continue;
        const eq = std.mem.indexOfScalar(u8, line, '=') orelse return error.InvalidRestoreState;
        const key = line[0..eq];
        const value = line[eq + 1 ..];
        if (std.mem.eql(u8, key, "backup_id")) {
            if (backup_id) |old| alloc.free(old);
            backup_id = null;
            backup_id = try alloc.dupe(u8, value);
        } else if (std.mem.eql(u8, key, "location")) {
            if (location) |old| alloc.free(old);
            location = null;
            location = try alloc.dupe(u8, value);
        } else if (std.mem.eql(u8, key, "snapshot_path")) {
            if (snapshot_path) |old| alloc.free(old);
            snapshot_path = null;
            snapshot_path = try alloc.dupe(u8, value);
        } else if (std.mem.eql(u8, key, "group_id")) {
            group_id = try std.fmt.parseInt(u64, value, 10);
        } else if (std.mem.eql(u8, key, "phase")) {
            if (phase) |old| alloc.free(old);
            phase = null;
            phase = try alloc.dupe(u8, value);
        } else if (std.mem.eql(u8, key, "primary_restored")) {
            primary_restored = try parseRestoreStateBool(value);
        } else if (std.mem.eql(u8, key, "runtime_repair_complete")) {
            runtime_repair_complete = try parseRestoreStateBool(value);
        } else if (std.mem.eql(u8, key, "last_error")) {
            if (last_error) |old| alloc.free(old);
            last_error = null;
            last_error = try alloc.dupe(u8, value);
        }
    }

    if (backup_id == null) backup_id = try alloc.dupe(u8, "");
    if (location == null) location = try alloc.dupe(u8, "");
    if (snapshot_path == null) snapshot_path = try alloc.dupe(u8, "");
    if (phase == null) phase = try alloc.dupe(u8, "accepted");
    if (last_error == null) last_error = try alloc.dupe(u8, "");

    return .{
        .backup_id = backup_id.?,
        .location = location.?,
        .snapshot_path = snapshot_path.?,
        .group_id = group_id orelse 0,
        .phase = phase.?,
        .primary_restored = primary_restored orelse false,
        .runtime_repair_complete = runtime_repair_complete orelse false,
        .last_error = last_error.?,
    };
}

fn writeRestoreStateForPath(alloc: Allocator, path: []const u8, state: RestoreState) !void {
    try ensureDirPath(path);
    const state_path = try restoreStateMarkerPathAlloc(alloc, path);
    defer alloc.free(state_path);
    const raw = try std.fmt.allocPrint(
        alloc,
        "restore_state_v2\nbackup_id={s}\nlocation={s}\nsnapshot_path={s}\ngroup_id={d}\nphase={s}\nprimary_restored={d}\nruntime_repair_complete={d}\nlast_error={s}\n",
        .{
            state.backup_id,
            state.location,
            state.snapshot_path,
            state.group_id,
            state.phase,
            @as(u8, if (state.primary_restored) 1 else 0),
            @as(u8, if (state.runtime_repair_complete) 1 else 0),
            state.last_error,
        },
    );
    defer alloc.free(raw);
    var io_impl = threadedIo();
    defer io_impl.deinit();
    try std.Io.Dir.cwd().writeFile(io_impl.io(), .{
        .sub_path = state_path,
        .data = raw,
    });
}

fn readRestoreImportStateAlloc(alloc: Allocator, path: []const u8) !?RestoreImportState {
    const import_marker_path = try restoreImportMarkerPathAlloc(alloc, path);
    defer alloc.free(import_marker_path);

    var io_impl = threadedIo();
    defer io_impl.deinit();
    const raw = std.Io.Dir.cwd().readFileAlloc(io_impl.io(), import_marker_path, alloc, .limited(64 * 1024)) catch |err| switch (err) {
        error.FileNotFound => return null,
        else => return err,
    };
    defer alloc.free(raw);

    var snapshot_root: ?[]u8 = null;
    errdefer if (snapshot_root) |value| alloc.free(value);
    var backup_id: ?[]u8 = null;
    errdefer if (backup_id) |value| alloc.free(value);
    var location: ?[]u8 = null;
    errdefer if (location) |value| alloc.free(value);
    var snapshot_path: ?[]u8 = null;
    errdefer if (snapshot_path) |value| alloc.free(value);
    var group_id: ?u64 = null;

    var lines = std.mem.splitScalar(u8, raw, '\n');
    while (lines.next()) |line| {
        if (line.len == 0 or std.mem.eql(u8, line, "restore_import_v1")) continue;
        const eq = std.mem.indexOfScalar(u8, line, '=') orelse return error.InvalidRestoreImportMarker;
        const key = line[0..eq];
        const value = line[eq + 1 ..];
        if (std.mem.eql(u8, key, "snapshot_root")) {
            if (snapshot_root) |old| alloc.free(old);
            snapshot_root = null;
            snapshot_root = try alloc.dupe(u8, value);
        } else if (std.mem.eql(u8, key, "backup_id")) {
            if (backup_id) |old| alloc.free(old);
            backup_id = null;
            backup_id = try alloc.dupe(u8, value);
        } else if (std.mem.eql(u8, key, "location")) {
            if (location) |old| alloc.free(old);
            location = null;
            location = try alloc.dupe(u8, value);
        } else if (std.mem.eql(u8, key, "snapshot_path")) {
            if (snapshot_path) |old| alloc.free(old);
            snapshot_path = null;
            snapshot_path = try alloc.dupe(u8, value);
        } else if (std.mem.eql(u8, key, "group_id")) {
            group_id = try std.fmt.parseInt(u64, value, 10);
        }
    }

    const root = snapshot_root orelse return error.InvalidRestoreImportMarker;
    snapshot_root = null;
    const identity = if (backup_id != null or location != null or snapshot_path != null or group_id != null) blk: {
        const backup = backup_id orelse return error.InvalidRestoreImportMarker;
        const loc = location orelse return error.InvalidRestoreImportMarker;
        const snap = snapshot_path orelse return error.InvalidRestoreImportMarker;
        const gid = group_id orelse return error.InvalidRestoreImportMarker;
        backup_id = null;
        location = null;
        snapshot_path = null;
        errdefer alloc.free(backup);
        errdefer alloc.free(loc);
        errdefer alloc.free(snap);
        const phase = try alloc.dupe(u8, "runtime_repair");
        errdefer alloc.free(phase);
        const last_error = try alloc.dupe(u8, "");
        errdefer alloc.free(last_error);
        break :blk RestoreState{
            .backup_id = backup,
            .location = loc,
            .snapshot_path = snap,
            .group_id = gid,
            .phase = phase,
            .primary_restored = true,
            .runtime_repair_complete = false,
            .last_error = last_error,
        };
    } else null;

    return .{
        .snapshot_root = root,
        .identity = identity,
    };
}

fn spinOrYield() void {
    if (builtin.os.tag == .freestanding) {
        std.atomic.spinLoopHint();
    } else {
        std.Thread.yield() catch {};
    }
}

fn atomicMaxU64(value: *AtomicU64, candidate: u64) void {
    var current = value.load(.monotonic);
    while (candidate > current) {
        current = value.cmpxchgWeak(current, candidate, .monotonic, .monotonic) orelse return;
    }
}

fn setDenseCatchUpProgress(ctx: *AsyncContext, progress: ReplayProgress) void {
    ctx.stats.dense_catch_up.active.store(if (progress.active) 1 else 0, .monotonic);
    ctx.stats.dense_catch_up.phase.store(@intFromEnum(if (progress.active) types.DenseCatchUpStats.Phase.replay else types.DenseCatchUpStats.Phase.idle), .monotonic);
    ctx.stats.dense_catch_up.current_sequence.store(progress.sequence, .monotonic);
    ctx.stats.dense_catch_up.current_target_sequence.store(progress.target_sequence, .monotonic);
    ctx.stats.dense_catch_up.current_scanned_entries.store(progress.scanned_entries, .monotonic);
    ctx.stats.dense_catch_up.current_applied_entries.store(progress.applied_entries, .monotonic);
    _ = ctx.stats.dense_catch_up.progress_updates.fetchAdd(1, .monotonic);
}

fn setDenseCatchUpPhase(ctx: *AsyncContext, phase: types.DenseCatchUpStats.Phase) void {
    ctx.stats.dense_catch_up.phase.store(@intFromEnum(phase), .monotonic);
    _ = ctx.stats.dense_catch_up.progress_updates.fetchAdd(1, .monotonic);
}

fn noteDenseBulkFinishProgress(ctx_ptr: *anyopaque, progress: backend_types.BulkIngestFinishOptions.Progress) void {
    const ctx: *AsyncContext = @ptrCast(@alignCast(ctx_ptr));
    const phase: types.DenseCatchUpStats.Phase = switch (progress.phase) {
        .begin => .bulk_finish,
        .split => .bulk_split,
        .publish => .bulk_publish,
        .complete => .bulk_finish,
    };
    ctx.stats.dense_catch_up.phase.store(@intFromEnum(phase), .monotonic);
    ctx.stats.dense_catch_up.bulk_finish_current_window.store(progress.publish_window, .monotonic);
    ctx.stats.dense_catch_up.bulk_finish_current_window_split_steps.store(progress.split_steps, .monotonic);
    ctx.stats.dense_catch_up.bulk_finish_deferred_leaf_splits.store(progress.deferred_leaf_splits, .monotonic);
    ctx.stats.dense_catch_up.bulk_finish_current_window_ns.store(progress.elapsed_ns, .monotonic);
    atomicMaxU64(&ctx.stats.dense_catch_up.bulk_finish_max_window_ns, progress.elapsed_ns);
    if (progress.phase == .publish) {
        _ = ctx.stats.dense_catch_up.bulk_finish_windows.fetchAdd(1, .monotonic);
        _ = ctx.stats.dense_catch_up.bulk_finish_split_steps.fetchAdd(progress.split_steps, .monotonic);
        if (progress.elapsed_ns > std.time.ns_per_s) {
            std.log.info(
                "dense catch-up bulk finish publish window window={} split_steps={} deferred_leaf_splits={} elapsed_ms={}",
                .{ progress.publish_window, progress.split_steps, progress.deferred_leaf_splits, progress.elapsed_ns / std.time.ns_per_ms },
            );
        }
    }
    _ = ctx.stats.dense_catch_up.progress_updates.fetchAdd(1, .monotonic);
}

fn lockAtomicWithBackoff(mutex: *std.atomic.Mutex) void {
    var attempts: usize = 0;
    while (!mutex.tryLock()) : (attempts += 1) {
        if (builtin.os.tag == .freestanding or builtin.single_threaded) {
            std.atomic.spinLoopHint();
            continue;
        }
        if (attempts < 64) {
            std.atomic.spinLoopHint();
            continue;
        }
        if (attempts < 128) {
            std.Thread.yield() catch {};
            continue;
        }
        const backoff_step = @min(attempts - 128, 5);
        const sleep_ns = @min(@as(u64, 50_000) << @intCast(backoff_step), @as(u64, 1_000_000));
        sleepNs(sleep_ns);
    }
}

fn lockAtomicWithBackoffProfiled(mutex: *std.atomic.Mutex, stats: *MutexContentionStats) ProfiledLock {
    if (!asyncIndexProfileEnabled()) {
        lockAtomicWithBackoff(mutex);
        return .{
            .mutex = mutex,
            .stats = stats,
            .hold_start_ns = 0,
            .profiled = false,
        };
    }
    _ = stats.lock_calls.fetchAdd(1, .monotonic);
    if (mutex.tryLock()) {
        return .{
            .mutex = mutex,
            .stats = stats,
            .hold_start_ns = monotonicTimeNs(),
            .profiled = true,
        };
    }

    _ = stats.contended_calls.fetchAdd(1, .monotonic);
    const current_waiters = stats.current_waiters.fetchAdd(1, .monotonic) + 1;
    atomicMaxU64(&stats.max_waiters, current_waiters);
    defer _ = stats.current_waiters.fetchSub(1, .monotonic);

    const wait_start_ns = monotonicTimeNs();
    var attempts: usize = 0;
    var spin_loops: u64 = 0;
    var yield_loops: u64 = 0;
    var sleep_loops: u64 = 0;
    while (!mutex.tryLock()) : (attempts += 1) {
        if (builtin.os.tag == .freestanding or builtin.single_threaded) {
            std.atomic.spinLoopHint();
            spin_loops += 1;
            continue;
        }
        if (attempts < 64) {
            std.atomic.spinLoopHint();
            spin_loops += 1;
            continue;
        }
        if (attempts < 128) {
            std.Thread.yield() catch {};
            yield_loops += 1;
            continue;
        }
        const backoff_step = @min(attempts - 128, 5);
        const sleep_ns = @min(@as(u64, 50_000) << @intCast(backoff_step), @as(u64, 1_000_000));
        sleepNs(sleep_ns);
        sleep_loops += 1;
    }

    const wait_ns = elapsedSince(wait_start_ns);
    _ = stats.spin_loops.fetchAdd(spin_loops, .monotonic);
    _ = stats.yield_loops.fetchAdd(yield_loops, .monotonic);
    _ = stats.sleep_loops.fetchAdd(sleep_loops, .monotonic);
    _ = stats.wait_ns.fetchAdd(wait_ns, .monotonic);
    atomicMaxU64(&stats.max_wait_ns, wait_ns);
    return .{
        .mutex = mutex,
        .stats = stats,
        .hold_start_ns = monotonicTimeNs(),
        .profiled = true,
    };
}

fn lockApplyWithBackoffProfiled(rw_lock: *apply_rw_lock_mod.ApplyRwLock, stats: *MutexContentionStats) ProfiledApplyLock {
    if (!asyncIndexProfileEnabled()) {
        rw_lock.lockExclusive();
        return .{
            .rw_lock = rw_lock,
            .stats = stats,
            .hold_start_ns = 0,
            .profiled = false,
        };
    }
    _ = stats.lock_calls.fetchAdd(1, .monotonic);
    if (rw_lock.tryLockExclusive()) {
        return .{
            .rw_lock = rw_lock,
            .stats = stats,
            .hold_start_ns = monotonicTimeNs(),
            .profiled = true,
        };
    }

    _ = stats.contended_calls.fetchAdd(1, .monotonic);
    const current_waiters = stats.current_waiters.fetchAdd(1, .monotonic) + 1;
    atomicMaxU64(&stats.max_waiters, current_waiters);
    defer _ = stats.current_waiters.fetchSub(1, .monotonic);

    const wait_start_ns = monotonicTimeNs();
    var attempts: usize = 0;
    var spin_loops: u64 = 0;
    var yield_loops: u64 = 0;
    var sleep_loops: u64 = 0;
    while (!rw_lock.tryLockExclusive()) : (attempts += 1) {
        if (builtin.os.tag == .freestanding or builtin.single_threaded) {
            std.atomic.spinLoopHint();
            spin_loops += 1;
            continue;
        }
        if (attempts < 64) {
            std.atomic.spinLoopHint();
            spin_loops += 1;
            continue;
        }
        if (attempts < 128) {
            std.Thread.yield() catch {};
            yield_loops += 1;
            continue;
        }
        const backoff_step = @min(attempts - 128, 5);
        const sleep_ns = @min(@as(u64, 50_000) << @intCast(backoff_step), @as(u64, 1_000_000));
        sleepNs(sleep_ns);
        sleep_loops += 1;
    }

    const wait_ns = elapsedSince(wait_start_ns);
    _ = stats.spin_loops.fetchAdd(spin_loops, .monotonic);
    _ = stats.yield_loops.fetchAdd(yield_loops, .monotonic);
    _ = stats.sleep_loops.fetchAdd(sleep_loops, .monotonic);
    _ = stats.wait_ns.fetchAdd(wait_ns, .monotonic);
    atomicMaxU64(&stats.max_wait_ns, wait_ns);
    return .{
        .rw_lock = rw_lock,
        .stats = stats,
        .hold_start_ns = monotonicTimeNs(),
        .profiled = true,
    };
}

fn denseLsmWriteStatsSnapshot(ctx: *AsyncContext, index_name: []const u8) ?hbc_mod.LsmWriteStats {
    const entry = ctx.index_manager.denseIndex(index_name) orelse return null;
    return entry.index.snapshotLsmWriteStats();
}

fn denseLsmWriteStatsDelta(after: hbc_mod.LsmWriteStats, before: hbc_mod.LsmWriteStats) hbc_mod.LsmWriteStats {
    var delta = after;
    inline for (std.meta.fields(hbc_mod.LsmWriteStats)) |field| {
        if (field.type == u64) {
            @field(delta, field.name) = @field(after, field.name) -| @field(before, field.name);
        }
    }
    return delta;
}

fn sleepNs(duration_ns: u64) void {
    if (comptime builtin.os.tag == .freestanding) {
        return;
    }

    var req = std.posix.timespec{
        .sec = @intCast(duration_ns / std.time.ns_per_s),
        .nsec = @intCast(duration_ns % std.time.ns_per_s),
    };
    while (true) switch (std.posix.errno(std.posix.system.nanosleep(&req, &req))) {
        .SUCCESS => return,
        .INTR => continue,
        else => return,
    };
}

fn groupCreatedAtMetadataKeyAlloc(alloc: Allocator, group_id: u64) ![]u8 {
    return try std.fmt.allocPrint(alloc, "\x00\x00__metadata__:data_group_created_at:{d}", .{group_id});
}

fn sleepPollInterval() void {
    platform_clock.Clock.real().sleepMs(10);
}

fn yieldToBackground() void {
    var spins: usize = 0;
    while (spins < 16) : (spins += 1) {
        spinOrYield();
    }
    sleepPollInterval();
}

const PrimaryStoreOpenPlan = union(enum) {
    lmdb: struct {
        map_size: usize,
        no_sync: bool,
    },
    mem: mem_backend_mod.Options,
    lsm_memory: lsm_backend_mod.Options,
    lsm: lsm_backend_mod.Options,
};

const SplitDestinationStorePlan = union(enum) {
    lmdb,
    lsm: lsm_backend_mod.Options,
    unsupported,
};

fn primaryStoreOpenPlan(opts: db_config.CoreOpenOptions) PrimaryStoreOpenPlan {
    return switch (opts.primary_backend) {
        .lmdb => .{
            .lmdb = .{
                .map_size = opts.map_size,
                .no_sync = opts.no_sync,
            },
        },
        .mem => |mem_opts| .{ .mem = mem_opts },
        .lsm_memory => |lsm_opts| .{ .lsm_memory = db_config.mergedLsmOptions(opts.storage, opts.lsm_cache, opts.resource_manager, opts.no_sync, lsm_opts) },
        .lsm => |lsm_opts| .{ .lsm = db_config.mergedLsmOptions(opts.storage, opts.lsm_cache, opts.resource_manager, opts.no_sync, lsm_opts) },
    };
}

fn openModeRequiresReadOnlyBackends(open_mode: OpenOptions.OpenMode) bool {
    return open_mode == .query_readonly or open_mode == .status_only;
}

fn makeLsmOptionsReadOnly(options: *lsm_backend_mod.Options) void {
    options.backend.read_only = true;
    options.backend.create_if_missing = false;
    options.background_executor = null;
}

fn applyReadOnlyToPrimaryBackend(primary_backend: *PrimaryBackend) void {
    switch (primary_backend.*) {
        .lsm => |*lsm_opts| makeLsmOptionsReadOnly(lsm_opts),
        .lsm_memory => |*lsm_opts| makeLsmOptionsReadOnly(lsm_opts),
        .lmdb, .mem => {},
    }
}

fn applyReadOnlyToIndexBackends(index_backends: *db_config.IndexBackendOptions) void {
    makeLsmOptionsReadOnly(&index_backends.text_main_lsm_options);
    makeLsmOptionsReadOnly(&index_backends.text_wal_lsm_options);
    makeLsmOptionsReadOnly(&index_backends.dense_lsm_options);
    makeLsmOptionsReadOnly(&index_backends.sparse_lsm_options);
    makeLsmOptionsReadOnly(&index_backends.graph_reverse_lsm_options);
}

fn splitDestinationStorePlan(self: *DB) SplitDestinationStorePlan {
    return switch (self.primary_backend) {
        .lmdb => .lmdb,
        .lsm => |opts| .{ .lsm = db_config.splitLsmOptions(.{ .lsm = opts }, self.primary_lsm_storage, opts.cache).? },
        .mem, .lsm_memory => .unsupported,
    };
}

fn makeLsmBackgroundExecutor(runtime: *background_runtime_mod.BackendRuntime, owner_id: u64) lsm_backend_mod.BackgroundExecutor {
    return lsm_backend_mod.BackgroundExecutor.init(runtime, owner_id);
}

fn openPrimaryStore(alloc: Allocator, path: []const u8, opts: db_config.CoreOpenOptions) !db_core.OpenedPrimaryStore {
    const zpath = try alloc.dupeZ(u8, path);
    defer alloc.free(zpath);

    return switch (primaryStoreOpenPlan(opts)) {
        .lmdb => |lmdb_opts| .{
            .store = try docstore_mod.DocStore.open(alloc, zpath, .{
                .map_size = lmdb_opts.map_size,
                .no_sync = lmdb_opts.no_sync,
            }),
        },
        .mem => |mem_opts| mem_blk: {
            const backend = try alloc.create(mem_backend_mod.Backend);
            errdefer alloc.destroy(backend);
            backend.* = mem_backend_mod.Backend.init(alloc, mem_opts);
            errdefer backend.close();

            var runtime_store = try backend.runtimeStore(alloc, .{ .name = "docs" });
            errdefer runtime_store.deinit();

            break :mem_blk .{
                .store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store),
                .owner = .{ .mem = backend },
            };
        },
        .lsm_memory => |lsm_opts| lsm_mem_blk: {
            var handle = try lsm_backend_mod.BackendHandle.init(alloc, lsm_opts);
            errdefer handle.close();

            var runtime_store = try handle.backend.runtimeStore(alloc, .{ .name = "docs" });
            errdefer runtime_store.deinit();

            break :lsm_mem_blk .{
                .store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store),
                .owner = .{ .lsm = .{
                    .handle = handle,
                    .split_options = null,
                } },
            };
        },
        .lsm => |lsm_opts| lsm_blk: {
            var handle = try lsm_backend_mod.BackendHandle.open(alloc, path, lsm_opts);
            errdefer handle.close();

            var runtime_store = try handle.backend.runtimeStore(alloc, .{ .name = "docs" });
            errdefer runtime_store.deinit();

            break :lsm_blk .{
                .store = try docstore_mod.DocStore.openRuntime(alloc, runtime_store),
                .owner = .{ .lsm = .{
                    .handle = handle,
                    .split_options = db_config.splitLsmOptions(opts.primary_backend, opts.storage, opts.lsm_cache),
                } },
            };
        },
    };
}

const ShadowState = struct {
    manager: *index_manager_mod.IndexManager,
    base_path: []u8,
    indexes_path: []u8,
    range_start: []u8,
    range_end: []u8,
};

pub const DB = struct {
    alloc: Allocator,
    runtime_alloc: Allocator,
    open_mode: OpenOptions.OpenMode,
    primary_backend: PrimaryBackend,
    primary_lsm_storage: ?lsm_backend_mod.Storage,
    index_backends: db_config.IndexBackendOptions,
    core: db_core.DBCore,
    async_context: *AsyncContext,
    backend_runtime: *background_runtime_mod.BackendRuntime,
    backend_owner_id: u64,
    owned_backend_runtime: ?background_runtime_mod.BackendRuntimeHandle,
    executor: *derived_executor_mod.Executor,
    start_index_workers: bool,
    secret_store: ?*common_secrets.FileStore,
    remote_content: ?*const scraping.RemoteContentConfig,
    enrichment_append_context: ?*EnrichmentAppendContext,
    enrichment_runtime: ?*enrichment_runtime_mod.EnrichmentRuntime,
    ttl_cleanup_context: ?*TtlCleanupContext,
    ttl_runtime: ?*ttl_runtime_mod.TtlRuntime,
    transaction_recovery_identity_context: ?*db_core.TransactionRecoveryIdentityContext,
    transaction_runtime: ?*transaction_runtime_mod.Runtime,
    text_merge_runtime: ?*text_merge_runtime_mod.TextMergeRuntime,
    sparse_compaction_runtime: ?*sparse_compaction_runtime_mod.SparseCompactionRuntime,
    shadow: ?ShadowState,
    bulk_ingest_coalescer: @This().BulkIngestCoalescer = .{},
    flushing_bulk_ingest_coalescer: bool = false,
    bulk_ingest_identity_all_new: bool = false,
    bulk_ingest_identity_state: doc_identity.AllNewTrustedState = .{},
    identity_visibility_summary_cache: ?doc_identity.VisibilitySummary = null,
    bulk_ingest_seen_doc_keys: std.StringHashMapUnmanaged(void) = .{},
    doc_set_planning_stats: DocSetPlanningRuntimeStats = .{},

    const engine_vtable = db_core.Engine.VTable{
        .batch = engineBatch,
        .lookup = engineLookup,
        .scan = engineScan,
        .search = engineSearch,
        .stats = engineStats,
        .list_indexes = engineListIndexes,
        .list_enrichments = engineListEnrichments,
    };

    fn batchContext(self: *DB) BatchExecutionContext {
        const resources = self.core.batchExecutionResources();
        return .{
            .alloc = self.alloc,
            .store = resources.store,
            .applied_sequence_checkpoint_path = resources.applied_sequence_checkpoint_path,
            .shard_manager = resources.shard_manager,
            .change_journal = resources.change_journal,
            .replay_source = resources.replay_source,
            .index_manager = resources.index_manager,
            .apply_mutex = resources.apply_mutex,
            .log_mutex = resources.log_mutex,
            .identity_namespace = resources.identity_namespace,
            .artifact_cleanup_maybe = resources.artifact_cleanup_maybe,
            .executor = self.executor,
            .io = self.backend_runtime.io(),
            .enrichment_runtime = self.enrichment_runtime,
            .async_context = self.async_context,
        };
    }

    fn hydrateAlgebraicObservationStatusBestEffort(self: *DB) void {
        for (self.core.index_manager.algebraic_indexes.items) |*entry| {
            entry.index.loadPersistedObservations(self.core.store) catch {};
        }
    }

    fn hydrateAlgebraicObservationStatusForIndexBestEffort(self: *DB, index_name: []const u8) void {
        const entry = self.core.index_manager.algebraicIndex(index_name) orelse return;
        entry.index.loadPersistedObservations(self.core.store) catch {};
    }

    const maintenance_driver_vtable = db_core.MaintenanceDriver.VTable{
        .pending_work_stats = maintenanceDriverPendingWorkStats,
        .run_derived_until = maintenanceDriverRunDerivedUntil,
        .run_enrichment_until = maintenanceDriverRunEnrichmentUntil,
        .run_maintenance_until = maintenanceDriverRunMaintenanceUntil,
        .run_until_idle = maintenanceDriverRunUntilIdle,
    };

    pub fn open(alloc: Allocator, path: []const u8, opts: OpenOptions) !DB {
        return blk: {
            const open_started_ns = monotonicTimeNs();
            var profile = OpenProfile{};
            const runtime_alloc = backgroundRuntimeAllocator(alloc);
            var owned_async_context: ?*AsyncContext = null;
            var owned_backend_runtime: ?background_runtime_mod.BackendRuntimeHandle = null;
            var owned_executor: ?*derived_executor_mod.Executor = null;
            errdefer {
                if (owned_executor) |ptr| runtime_alloc.destroy(ptr);
                if (owned_backend_runtime) |*handle| handle.deinit();
                if (owned_async_context) |ptr| runtime_alloc.destroy(ptr);
            }
            const backend_runtime = opts.backend_runtime orelse blk_runtime: {
                owned_backend_runtime = try background_runtime_mod.BackendRuntimeHandle.init(runtime_alloc, .{
                    .backend = opts.executor.backend,
                });
                break :blk_runtime owned_backend_runtime.?.runtime;
            };
            var effective_executor = opts.executor;
            if (backend_runtime.io_impl == null and effective_executor.backend == .io_threaded) {
                effective_executor.backend = .manual;
            }
            const backend_owner_id = backend_runtime.allocOwnerId();
            var primary_lsm_background_executor: lsm_backend_mod.BackgroundExecutor = undefined;
            var effective_primary_backend = opts.primary_backend;
            var effective_index_backends = opts.index_backends;
            if (openModeRequiresReadOnlyBackends(opts.open_mode)) {
                applyReadOnlyToPrimaryBackend(&effective_primary_backend);
                applyReadOnlyToIndexBackends(&effective_index_backends);
            }
            switch (effective_primary_backend) {
                .lsm => |*lsm_opts| {
                    lsm_opts.cache = opts.lsm_cache orelse lsm_opts.cache;
                    lsm_opts.root_generation = opts.lsm_root_generation;
                    primary_lsm_background_executor = makeLsmBackgroundExecutor(backend_runtime, backend_owner_id);
                    lsm_opts.background_executor = &primary_lsm_background_executor;
                },
                .lsm_memory => |*lsm_opts| {
                    lsm_opts.cache = opts.lsm_cache orelse lsm_opts.cache;
                    lsm_opts.root_generation = opts.lsm_root_generation;
                    primary_lsm_background_executor = makeLsmBackgroundExecutor(backend_runtime, backend_owner_id);
                    lsm_opts.background_executor = &primary_lsm_background_executor;
                },
                .lmdb, .mem => {},
            }
            const core_opts: db_config.CoreOpenOptions = .{
                .map_size = opts.map_size,
                .no_sync = opts.no_sync,
                .primary_backend = effective_primary_backend,
                .storage = opts.storage,
                .lsm_cache = opts.lsm_cache,
                .hbc_cache = opts.hbc_cache,
                .lsm_root_generation = opts.lsm_root_generation,
                .resource_manager = opts.resource_manager,
                .index_backends = effective_index_backends,
            };
            const resolved_config = db_config.ResolvedOpenConfig.init(
                effective_primary_backend,
                opts.storage,
                opts.lsm_cache,
                opts.hbc_cache,
                opts.lsm_root_generation,
                opts.resource_manager,
                effective_index_backends,
            );
            const open_primary_started_ns = monotonicTimeNs();
            const opened_primary = try openPrimaryStore(alloc, path, core_opts);
            profile.primary_store_ns = elapsedSince(open_primary_started_ns);
            const core_resources_started_ns = monotonicTimeNs();
            const core = try db_core.openCoreResourcesFromPrimaryStore(
                alloc,
                path,
                opts.map_size,
                opts.no_sync,
                resolved_config.primary_backend_kind,
                resolved_config.primary_lsm_storage,
                opts.change_journal_backend,
                opts.change_journal_storage,
                resolved_config.index_backends,
                opened_primary,
                opts.identity_namespace,
                false,
                if (opts.prefer_existing_identity_namespace) .use_existing else .reject,
            );
            profile.core_resources_ns = elapsedSince(core_resources_started_ns);
            const async_context = try runtime_alloc.create(AsyncContext);
            owned_async_context = async_context;
            const executor = try runtime_alloc.create(derived_executor_mod.Executor);
            owned_executor = executor;
            var stored_primary_backend = effective_primary_backend;
            switch (stored_primary_backend) {
                .lsm => |*lsm_opts| lsm_opts.background_executor = null,
                .lsm_memory => |*lsm_opts| lsm_opts.background_executor = null,
                .lmdb, .mem => {},
            }

            var db = DB{
                .alloc = alloc,
                .runtime_alloc = runtime_alloc,
                .open_mode = opts.open_mode,
                .primary_backend = stored_primary_backend,
                .primary_lsm_storage = resolved_config.primary_lsm_storage,
                .index_backends = resolved_config.index_backends,
                .core = db_core.DBCore.fromOpened(alloc, core),
                .async_context = async_context,
                .backend_runtime = backend_runtime,
                .backend_owner_id = backend_owner_id,
                .owned_backend_runtime = owned_backend_runtime,
                .executor = executor,
                .start_index_workers = opts.open_mode.allowsIndexWorkers() and opts.start_index_workers,
                .secret_store = opts.secret_store,
                .remote_content = opts.remote_content,
                .enrichment_append_context = null,
                .enrichment_runtime = null,
                .ttl_cleanup_context = null,
                .ttl_runtime = null,
                .transaction_recovery_identity_context = null,
                .transaction_runtime = null,
                .text_merge_runtime = null,
                .sparse_compaction_runtime = null,
                .shadow = null,
            };
            var executor_ready = false;
            owned_async_context = null;
            owned_backend_runtime = null;
            owned_executor = null;
            errdefer db.deinitWrapperState(executor_ready);
            db.core.setIndexOpenParallelism(opts.index_open_parallelism);
            const init_async_started_ns = monotonicTimeNs();
            try db.initAsyncInfrastructure(effective_executor, opts.resource_manager);
            profile.init_async_infrastructure_ns = elapsedSince(init_async_started_ns);
            executor_ready = true;
            if (opts.open_mode.allowsOptionalRuntimes()) {
                const init_optional_started_ns = monotonicTimeNs();
                try db.initOptionalRuntimes(opts);
                profile.init_optional_runtimes_ns = elapsedSince(init_optional_started_ns);
            }

            if (opts.open_mode == .status_only) {
                try db.core.loadIndexCatalogOnly();
            } else if (opts.open_mode == .query_readonly) {
                const load_indexes_started_ns = monotonicTimeNs();
                try db.core.loadIndexesNoBackfill();
                profile.load_indexes_ns = elapsedSince(load_indexes_started_ns);
            } else {
                const load_indexes_started_ns = monotonicTimeNs();
                try db.core.loadIndexes();
                profile.load_indexes_ns = elapsedSince(load_indexes_started_ns);
            }
            if (opts.open_mode != .status_only) {
                db.hydrateAlgebraicObservationStatusBestEffort();
            }
            if (opts.open_mode != .status_only) {
                try db.rebaseManagedIndexAppliedSequencesIfNeeded();
            }
            db.recordStartupOpenStats(profile);
            if (opts.open_mode.allowsReplay()) {
                const replay_started_ns = monotonicTimeNs();
                try replayPendingDerivedBatches(&db, null, null);
                profile.replay_pending_derived_ns = elapsedSince(replay_started_ns);
            }
            if (opts.open_mode.allowsOptionalRuntimes()) {
                try db.resumeGeneratedReplayFromJournalIfNeeded();
            }
            if (db.start_index_workers) {
                const start_workers_started_ns = monotonicTimeNs();
                try startAsyncWorkers(&db);
                if (opts.open_mode.allowsReplay()) {
                    db.resumeAsyncReplayFromJournalIfNeeded();
                }
                profile.start_index_workers_ns = elapsedSince(start_workers_started_ns);
            }
            if (opts.open_mode.allowsOptionalRuntimes()) {
                const start_optional_started_ns = monotonicTimeNs();
                try db.startOptionalRuntimes();
                profile.start_optional_runtimes_ns = elapsedSince(start_optional_started_ns);
            }
            profile.total_ns = monotonicTimeNs() - open_started_ns;
            if (openProfileEnabled()) {
                logOpenProfile(path, opts.open_mode, db.start_index_workers, profile);
            }
            break :blk db;
        };
    }

    pub fn close(self: *DB) void {
        self.deinitWrapperState(true);
    }

    fn resumeGeneratedReplayFromJournalIfNeeded(self: *DB) !void {
        const runtime = self.enrichment_runtime orelse return;
        if (!self.core.hasGeneratedEnrichmentTargets()) return;

        const target_sequence = self.core.nextEnrichmentSequence();
        if (target_sequence == 0) return;
        try runtime.resumeFrom(target_sequence, target_sequence);
    }

    fn resumeAsyncReplayFromJournalIfNeeded(self: *DB) void {
        const target_sequence = self.core.nextDerivedSequence();
        if (target_sequence == 0) return;
        self.executor.notifySequence(target_sequence);
    }

    pub fn maintenanceDriver(self: *DB) db_core.MaintenanceDriver {
        return .{
            .ptr = self,
            .vtable = &maintenance_driver_vtable,
        };
    }

    pub fn engine(self: *DB) db_core.Engine {
        return .{
            .ptr = self,
            .vtable = &engine_vtable,
        };
    }

    pub fn services(self: *DB) db_core.Services {
        return self.core.services(self.engine(), self.maintenanceDriver());
    }

    fn initAsyncInfrastructure(
        self: *DB,
        executor_config: derived_executor_mod.Config,
        resource_manager: ?*resource_manager_mod.ResourceManager,
    ) !void {
        const async_resources = self.core.asyncResources();
        self.async_context.* = .{
            .alloc = self.runtime_alloc,
            .store = async_resources.store,
            .applied_sequence_checkpoint_path = async_resources.applied_sequence_checkpoint_path,
            .index_manager = async_resources.index_manager,
            .apply_mutex = async_resources.apply_mutex,
            .io = self.backend_runtime.io(),
            .query_visibility_hook = null,
            .text_merge_runtime = null,
        };
        self.executor.* = try derived_executor_mod.init(
            self.runtime_alloc,
            executor_config,
            self.core.replaySource(),
            self.async_context,
            applyDerivedBatchToIndexAsync,
            persistAppliedSequenceAsync,
            truncateReplaySequenceAsync,
            beginDerivedCatchUpSessionAsync,
            finishDerivedCatchUpSessionAsync,
            canAdvanceDerivedToTargetAsync,
            resource_manager,
            self.backend_runtime,
        );
    }

    pub fn setQueryVisibilityHook(self: *DB, hook: ?QueryVisibilityHook) void {
        self.async_context.query_visibility_hook = hook;
        if (self.enrichment_runtime) |runtime| {
            runtime.setStatusHook(if (hook == null) null else .{
                .ptr = self.async_context,
                .on_change = notifyAsyncContextVisibilityHook,
            });
        }
    }

    fn notifyAsyncContextVisibilityHook(ptr: *anyopaque) void {
        const ctx: *AsyncContext = @ptrCast(@alignCast(ptr));
        if (ctx.query_visibility_hook) |hook| hook.notify(.invalidate);
    }

    fn initOptionalEnrichmentRuntime(self: *DB, enrichment_cfg: enrichment_runtime_mod.Config) !void {
        if (enrichment_cfg.dense_embedder == null and enrichment_cfg.sparse_embedder == null and enrichment_cfg.asset_producer == null and !enrichment_cfg.enable_without_producers) return;

        const append_ctx = try self.runtime_alloc.create(EnrichmentAppendContext);
        errdefer self.runtime_alloc.destroy(append_ctx);
        const resources = self.core.batchExecutionResources();
        append_ctx.* = .{
            .alloc = self.runtime_alloc,
            .store = resources.store,
            .applied_sequence_checkpoint_path = resources.applied_sequence_checkpoint_path,
            .shard_manager = resources.shard_manager,
            .index_manager = resources.index_manager,
            .apply_mutex = resources.apply_mutex,
            .change_journal = resources.change_journal,
            .replay_source = resources.replay_source,
            .executor = self.executor,
            .async_context = self.async_context,
            .log_mutex = resources.log_mutex,
        };

        const runtime = try self.runtime_alloc.create(enrichment_runtime_mod.EnrichmentRuntime);
        errdefer self.runtime_alloc.destroy(runtime);
        runtime.* = try enrichment_runtime_mod.EnrichmentRuntime.init(
            self.runtime_alloc,
            self.core.batchExecutionResources().store,
            self.core.batchExecutionResources().change_journal,
            self.core.replaySource(),
            self.core.batchExecutionResources().index_manager,
            append_ctx,
            appendDerivedBatchFromEnrichment,
            self.executor,
            notifyDerivedExecutorSequence,
            self.backend_runtime,
            enrichment_cfg,
        );
        errdefer runtime.deinit();
        self.enrichment_append_context = append_ctx;
        self.enrichment_runtime = runtime;
    }

    fn initOptionalTtlRuntime(self: *DB, cfg: ttl_runtime_mod.Config) !void {
        const ttl_ctx = try self.runtime_alloc.create(TtlCleanupContext);
        errdefer self.runtime_alloc.destroy(ttl_ctx);
        const batch_resources = self.core.batchExecutionResources();
        ttl_ctx.* = .{
            .batch = .{
                .alloc = self.runtime_alloc,
                .store = batch_resources.store,
                .applied_sequence_checkpoint_path = batch_resources.applied_sequence_checkpoint_path,
                .shard_manager = batch_resources.shard_manager,
                .change_journal = batch_resources.change_journal,
                .replay_source = batch_resources.replay_source,
                .index_manager = batch_resources.index_manager,
                .apply_mutex = batch_resources.apply_mutex,
                .log_mutex = batch_resources.log_mutex,
                .identity_namespace = batch_resources.identity_namespace,
                .executor = self.executor,
                .enrichment_runtime = self.enrichment_runtime,
            },
            .grace_period_ns = cfg.grace_period_ns,
        };
        const runtime = try self.runtime_alloc.create(ttl_runtime_mod.TtlRuntime);
        errdefer self.runtime_alloc.destroy(runtime);
        runtime.* = try ttl_runtime_mod.TtlRuntime.init(
            self.runtime_alloc,
            self.core.batchExecutionResources().store,
            ttl_ctx,
            deleteExpiredDocumentsFromCandidates,
            &self.async_context.text_merge_deferred,
            self.backend_runtime,
            cfg,
        );
        errdefer runtime.deinit();
        self.ttl_cleanup_context = ttl_ctx;
        self.ttl_runtime = runtime;
    }

    fn initOptionalTransactionRuntime(self: *DB, cfg: transaction_runtime_mod.Config) !void {
        const identity_ctx = try self.runtime_alloc.create(db_core.TransactionRecoveryIdentityContext);
        errdefer self.runtime_alloc.destroy(identity_ctx);
        identity_ctx.* = .{
            .store = self.core.store,
            .identity_namespace = self.core.identity_namespace,
            .alloc = self.runtime_alloc,
        };
        var effective_cfg = cfg;
        effective_cfg.resolution_extra_hooks = db_core.transactionRecoveryIdentityHooks(identity_ctx);

        const runtime = try self.runtime_alloc.create(transaction_runtime_mod.Runtime);
        errdefer self.runtime_alloc.destroy(runtime);
        runtime.* = try transaction_runtime_mod.Runtime.init(
            self.runtime_alloc,
            self.core.batchExecutionResources().store,
            self.backend_runtime,
            effective_cfg,
        );
        errdefer runtime.deinit();
        self.transaction_recovery_identity_context = identity_ctx;
        self.transaction_runtime = runtime;
    }

    fn initOptionalTextMergeRuntime(self: *DB, cfg: text_merge_runtime_mod.Config) !void {
        if (!self.start_index_workers) return;
        if (!cfg.enabled) return;
        const resources = self.core.asyncResources();
        const runtime = try self.runtime_alloc.create(text_merge_runtime_mod.TextMergeRuntime);
        errdefer self.runtime_alloc.destroy(runtime);
        runtime.* = try text_merge_runtime_mod.TextMergeRuntime.init(
            self.runtime_alloc,
            resources.index_manager,
            resources.apply_mutex,
            &self.async_context.text_merge_deferred,
            self.backend_runtime,
            cfg,
        );
        errdefer runtime.deinit();
        self.text_merge_runtime = runtime;
        self.async_context.text_merge_runtime = runtime;
    }

    fn initOptionalSparseCompactionRuntime(self: *DB, cfg: sparse_compaction_runtime_mod.Config) !void {
        if (!self.start_index_workers) return;
        if (!cfg.enabled) return;
        const resources = self.core.asyncResources();
        const runtime = try self.runtime_alloc.create(sparse_compaction_runtime_mod.SparseCompactionRuntime);
        errdefer self.runtime_alloc.destroy(runtime);
        runtime.* = try sparse_compaction_runtime_mod.SparseCompactionRuntime.init(
            self.runtime_alloc,
            resources.index_manager,
            resources.apply_mutex,
            self.backend_runtime,
            cfg,
        );
        errdefer runtime.deinit();
        self.sparse_compaction_runtime = runtime;
        self.async_context.sparse_compaction_runtime = runtime;
    }

    fn initOptionalRuntimes(self: *DB, opts: OpenOptions) !void {
        if (opts.enrichment) |raw_enrichment_cfg| {
            var enrichment_cfg = raw_enrichment_cfg;
            if (enrichment_cfg.secret_store == null) enrichment_cfg.secret_store = opts.secret_store;
            if (enrichment_cfg.remote_content == null) enrichment_cfg.remote_content = opts.remote_content;
            try self.initOptionalEnrichmentRuntime(enrichment_cfg);
        }
        if (opts.ttl_cleanup.enabled) {
            try self.initOptionalTtlRuntime(opts.ttl_cleanup);
        }
        if (opts.transaction_recovery.enabled) {
            try self.initOptionalTransactionRuntime(opts.transaction_recovery);
        }
        try self.initOptionalTextMergeRuntime(opts.text_merge);
        try self.initOptionalSparseCompactionRuntime(opts.sparse_compaction);
    }

    fn startOptionalRuntimes(self: *DB) !void {
        if (self.enrichment_runtime) |runtime| try runtime.start();
        if (self.ttl_runtime) |runtime| try runtime.start();
        if (self.transaction_runtime) |runtime| try runtime.start();
        if (self.text_merge_runtime) |runtime| try runtime.start();
        if (self.sparse_compaction_runtime) |runtime| try runtime.start();
    }

    fn deinitWrapperState(self: *DB, executor_ready: bool) void {
        // Close may flush/coalesce derived watermarks while workers are
        // stopping. That must not call back into the write/status cache after
        // optional runtimes or index state have started tearing down.
        self.setQueryVisibilityHook(null);
        self.bulk_ingest_coalescer.deinit(self.alloc);
        self.clearBulkIngestSeenDocKeysLocked();
        self.bulk_ingest_seen_doc_keys.deinit(self.alloc);
        self.closeShadowIndexManager() catch {};
        if (self.transaction_runtime) |runtime| {
            runtime.deinit();
            self.runtime_alloc.destroy(runtime);
        }
        if (self.transaction_recovery_identity_context) |ctx| self.runtime_alloc.destroy(ctx);
        if (self.ttl_runtime) |runtime| {
            runtime.deinit();
            self.runtime_alloc.destroy(runtime);
        }
        if (self.ttl_cleanup_context) |ctx| self.runtime_alloc.destroy(ctx);
        if (self.enrichment_runtime) |runtime| {
            runtime.deinit();
            self.runtime_alloc.destroy(runtime);
        }
        if (self.enrichment_append_context) |ctx| self.runtime_alloc.destroy(ctx);
        if (executor_ready) self.executor.deinit(self.runtime_alloc);
        self.runtime_alloc.destroy(self.executor);
        if (self.text_merge_runtime) |runtime| {
            self.async_context.text_merge_runtime = null;
            runtime.deinit();
            self.runtime_alloc.destroy(runtime);
        }
        if (self.sparse_compaction_runtime) |runtime| {
            self.async_context.sparse_compaction_runtime = null;
            runtime.deinit();
            self.runtime_alloc.destroy(runtime);
        }
        self.core.deinit();
        if (self.owned_backend_runtime) |*runtime| runtime.deinit();
        self.async_context.deinit(self.runtime_alloc);
        self.runtime_alloc.destroy(self.async_context);
        self.* = undefined;
    }

    pub fn runTransactionRecoveryOnce(self: *DB, config: transaction_runtime_mod.Config) !types.TransactionRecoveryStats {
        return try self.core.runTransactionRecoveryOnce(self.alloc, config);
    }

    pub fn beginBulkIngestSession(self: *DB) !void {
        self.async_context.text_merge_deferred.store(true, .release);
        errdefer self.async_context.text_merge_deferred.store(false, .release);
        beginExternalDenseBulkSessionTracked(self.async_context);
        errdefer finishExternalDenseBulkSessionTracked(self.async_context);
        lockApply(self);
        defer self.core.unlockApply();
        const resources = self.core.batchExecutionResources();
        try resources.store.beginBulkIngestSession();
        errdefer resources.store.abortBulkIngestSession();
        try resources.index_manager.beginDenseBulkIngestSessions();
        errdefer resources.index_manager.abortDenseBulkIngestSessions();
        try resources.index_manager.beginSparseBulkIngestSessions();
        errdefer resources.index_manager.abortSparseBulkIngestSessions();
        try resources.index_manager.beginAlgebraicBulkIngestSessions();
        self.configureBulkIngestIdentityAllNewLocked() catch |err| {
            resources.index_manager.abortAlgebraicBulkIngestSessions();
            return err;
        };
        errdefer self.clearBulkIngestIdentityAllNewLocked();
        self.bulk_ingest_coalescer.begin();
    }

    pub fn finishBulkIngestSessionWithOptions(self: *DB, options: backend_types.BulkIngestFinishOptions) !void {
        try self.flushBulkIngestCoalescerWithSyncLevel(.write, null);
        var external_session_tracked = true;
        defer if (external_session_tracked) finishExternalDenseBulkSessionTracked(self.async_context);
        {
            lockApply(self);
            defer self.core.unlockApply();
            const resources = self.core.batchExecutionResources();
            var first_err: ?anyerror = null;
            // External dense indexes may need to reload vectors from the primary
            // store while deferred leaf splits are normalized at finish time. Make
            // the primary-store bulk-ingest state visible before the dense finish
            // path runs so those reloads cannot see a half-published store.
            resources.index_manager.finishAlgebraicBulkIngestSessionsWithOptions(resources.store, options) catch |err| {
                first_err = err;
            };
            resources.store.finishBulkIngestSessionWithOptions(options) catch |err| {
                if (first_err == null) first_err = err;
            };
            resources.index_manager.finishSparseBulkIngestSessionsWithOptions(options) catch |err| {
                if (first_err == null) first_err = err;
            };
            resources.index_manager.finishDenseBulkIngestSessionsWithOptions(options) catch |err| {
                if (first_err == null) first_err = err;
            };
            self.bulk_ingest_coalescer.clear(self.alloc);
            self.clearBulkIngestIdentityAllNewLocked();
            if (first_err) |err| return err;
        }
        finishExternalDenseBulkSessionTracked(self.async_context);
        external_session_tracked = false;
        // External bulk finish is the user-visible publication boundary for the
        // staged batch. Publish the primary LSM session first so derived indexes
        // can read the coalesced documents, then force managed index catch-up
        // before returning.
        try self.waitForCurrentSyncLevel(.full_index);
        flushDeferredExternalBulkExecutorNotificationOrTarget(
            self.async_context,
            self.executor,
            self.core.nextDerivedSequence(),
        );
        if (self.async_context.query_visibility_hook) |hook| hook.notify(.publish);
    }

    pub fn beginDenseAutoBulkIngestSession(self: *DB) !void {
        beginExternalDenseBulkSessionTracked(self.async_context);
        errdefer finishExternalDenseBulkSessionTracked(self.async_context);
        lockApply(self);
        defer self.core.unlockApply();
        const resources = self.core.batchExecutionResources();
        try resources.index_manager.beginDenseBulkIngestSessions();
        self.bulk_ingest_coalescer.begin();
    }

    pub fn beginPrimaryStoreAutoBulkIngestSession(self: *DB) !void {
        beginExternalDenseBulkSessionTracked(self.async_context);
        errdefer finishExternalDenseBulkSessionTracked(self.async_context);
        lockApply(self);
        defer self.core.unlockApply();
        const resources = self.core.batchExecutionResources();
        try resources.store.beginBulkIngestSession();
        errdefer resources.store.abortBulkIngestSession();
        try resources.index_manager.beginDenseBulkIngestSessions();
        try self.configureBulkIngestIdentityAllNewLocked();
        errdefer self.clearBulkIngestIdentityAllNewLocked();
        self.bulk_ingest_coalescer.begin();
    }

    pub fn finishPrimaryStoreAutoBulkIngestSessionWithOptions(self: *DB, options: backend_types.BulkIngestFinishOptions) !void {
        try self.flushBulkIngestCoalescerWithSyncLevel(.write, null);
        var external_session_tracked = true;
        defer if (external_session_tracked) finishExternalDenseBulkSessionTracked(self.async_context);
        {
            lockApply(self);
            defer self.core.unlockApply();
            const resources = self.core.batchExecutionResources();
            var first_err: ?anyerror = null;
            resources.store.finishBulkIngestSessionWithOptions(options) catch |err| {
                first_err = err;
            };
            resources.index_manager.finishDenseBulkIngestSessionsWithOptions(options) catch |err| {
                if (first_err == null) first_err = err;
            };
            self.bulk_ingest_coalescer.clear(self.alloc);
            self.clearBulkIngestIdentityAllNewLocked();
            if (first_err) |err| return err;
        }
        finishExternalDenseBulkSessionTracked(self.async_context);
        external_session_tracked = false;
        flushDeferredExternalBulkExecutorNotificationOrTarget(
            self.async_context,
            self.executor,
            self.core.nextDerivedSequence(),
        );
        if (self.async_context.query_visibility_hook) |hook| hook.notify(.publish);
    }

    pub fn finishDenseAutoBulkIngestSessionWithOptions(self: *DB, options: backend_types.BulkIngestFinishOptions) !void {
        try self.finishDenseAutoBulkIngestSessionWithOptionsInternal(options, true);
    }

    pub fn rollDenseAutoBulkIngestSessionWithOptions(self: *DB, options: backend_types.BulkIngestFinishOptions) !void {
        try self.finishDenseAutoBulkIngestSessionWithOptionsInternal(options, true);
        try self.beginDenseAutoBulkIngestSession();
    }

    fn finishDenseAutoBulkIngestSessionWithOptionsInternal(self: *DB, options: backend_types.BulkIngestFinishOptions, notify_executor: bool) !void {
        try self.flushBulkIngestCoalescerWithSyncLevel(.write, null);
        var external_session_tracked = true;
        defer if (external_session_tracked) finishExternalDenseBulkSessionTracked(self.async_context);
        {
            lockApply(self);
            defer self.core.unlockApply();
            const resources = self.core.batchExecutionResources();
            resources.store.flushBufferedWritesWithOptions(options) catch |err| {
                self.bulk_ingest_coalescer.clear(self.alloc);
                return err;
            };
            resources.index_manager.finishDenseBulkIngestSessionsWithOptions(options) catch |err| {
                self.bulk_ingest_coalescer.clear(self.alloc);
                self.clearBulkIngestIdentityAllNewLocked();
                return err;
            };
            self.bulk_ingest_coalescer.clear(self.alloc);
            self.clearBulkIngestIdentityAllNewLocked();
        }
        finishExternalDenseBulkSessionTracked(self.async_context);
        external_session_tracked = false;
        if (notify_executor) {
            flushDeferredExternalBulkExecutorNotificationOrTarget(
                self.async_context,
                self.executor,
                self.core.nextDerivedSequence(),
            );
        }
        if (self.async_context.query_visibility_hook) |hook| hook.notify(.publish);
    }

    pub fn abortDenseAutoBulkIngestSession(self: *DB) void {
        lockApply(self);
        {
            defer self.core.unlockApply();
            const resources = self.core.batchExecutionResources();
            self.bulk_ingest_coalescer.clear(self.alloc);
            resources.index_manager.abortDenseBulkIngestSessions();
        }
        finishExternalDenseBulkSessionTracked(self.async_context);
        flushDeferredExternalBulkExecutorNotification(self.async_context, self.executor);
    }

    pub fn abortPrimaryStoreAutoBulkIngestSession(self: *DB) void {
        lockApply(self);
        {
            defer self.core.unlockApply();
            const resources = self.core.batchExecutionResources();
            self.bulk_ingest_coalescer.clear(self.alloc);
            self.clearBulkIngestIdentityAllNewLocked();
            resources.index_manager.abortDenseBulkIngestSessions();
            resources.store.abortBulkIngestSession();
        }
        finishExternalDenseBulkSessionTracked(self.async_context);
        flushDeferredExternalBulkExecutorNotification(self.async_context, self.executor);
    }

    pub fn abortBulkIngestSession(self: *DB) void {
        lockApply(self);
        {
            defer self.core.unlockApply();
            const resources = self.core.batchExecutionResources();
            self.bulk_ingest_coalescer.clear(self.alloc);
            self.clearBulkIngestIdentityAllNewLocked();
            resources.index_manager.abortAlgebraicBulkIngestSessions();
            resources.index_manager.abortDenseBulkIngestSessions();
            resources.store.abortBulkIngestSession();
        }
        finishExternalDenseBulkSessionTracked(self.async_context);
        flushDeferredExternalBulkExecutorNotification(self.async_context, self.executor);
    }

    pub fn lsmMaintenanceScore(self: *DB) u64 {
        lockApplyShared(self);
        defer self.core.unlockApplyShared();
        return @max(
            self.core.primary_store_owner.lsmMaintenanceScore(),
            self.core.index_manager.lsmMaintenanceScore(),
        );
    }

    pub fn lsmMaintenanceDebtHint(self: *DB) u64 {
        return @max(
            self.core.primary_store_owner.lsmMaintenanceDebtHint(),
            self.core.index_manager.lsmMaintenanceDebtHint(),
        );
    }

    pub fn snapshotAsyncIndexingStats(self: *DB) types.AsyncIndexingStats {
        var async_stats = self.async_context.stats.snapshot();
        async_stats.bulk_coalescing = self.bulk_ingest_coalescer.stats.snapshot();
        return async_stats;
    }

    pub fn snapshotApplyLockStats(self: *DB) apply_rw_lock_mod.ApplyRwLock.Stats {
        return self.core.apply_mutex.snapshot();
    }

    fn recordStartupOpenStats(self: *DB, profile: OpenProfile) void {
        self.async_context.stats.startup.configured_indexes.store(self.core.index_manager.count(), .monotonic);
        self.async_context.stats.startup.configured_dense_indexes.store(@intCast(self.core.index_manager.dense_indexes.items.len), .monotonic);
        self.async_context.stats.startup.configured_sparse_indexes.store(@intCast(self.core.index_manager.sparse_indexes.items.len), .monotonic);
        self.async_context.stats.startup.configured_full_text_indexes.store(@intCast(self.core.index_manager.text_indexes.items.len), .monotonic);
        self.async_context.stats.startup.configured_graph_indexes.store(@intCast(self.core.index_manager.graph_indexes.items.len), .monotonic);
        self.async_context.stats.startup.opened_indexes.store(self.core.index_manager.count(), .monotonic);
        self.async_context.stats.startup.db_open_ns.store(profile.total_ns, .monotonic);
        self.async_context.stats.startup.load_indexes_ns.store(profile.load_indexes_ns, .monotonic);

        var replay_records: u64 = 0;
        var replay_entries: u64 = 0;
        var replay_bytes: u64 = 0;
        var replay_ns: u64 = 0;
        for (self.core.index_manager.dense_indexes.items) |*entry| {
            const write_stats = entry.index.snapshotLsmWriteStats() orelse continue;
            replay_records += write_stats.wal_replay_records;
            replay_entries += write_stats.wal_replay_entries;
            replay_bytes += write_stats.wal_replay_bytes;
            replay_ns += write_stats.wal_replay_ns;
        }
        self.async_context.stats.startup.wal_replay_records.store(replay_records, .monotonic);
        self.async_context.stats.startup.wal_replay_entries.store(replay_entries, .monotonic);
        self.async_context.stats.startup.wal_replay_bytes.store(replay_bytes, .monotonic);
        self.async_context.stats.startup.wal_replay_ns.store(replay_ns, .monotonic);
    }

    pub fn snapshotLsmMaintenanceStats(self: *DB) lsm_backend_mod.Backend.MaintenanceStats {
        lockApplyShared(self);
        defer self.core.unlockApplyShared();
        return self.snapshotLsmMaintenanceStatsLocked();
    }

    pub fn trySnapshotLsmMaintenanceStats(self: *DB) ?lsm_backend_mod.Backend.MaintenanceStats {
        if (!self.core.tryLockApplyShared()) return null;
        defer self.core.unlockApplyShared();
        return self.snapshotLsmMaintenanceStatsLocked();
    }

    fn snapshotLsmMaintenanceStatsLocked(self: *DB) lsm_backend_mod.Backend.MaintenanceStats {
        var maintenance_stats = lsm_backend_mod.Backend.MaintenanceStats{};
        if (self.core.primary_store_owner.snapshotLsmMaintenanceStats()) |primary_stats| {
            lsm_backend_mod.Backend.accumulateMaintenanceStats(&maintenance_stats, primary_stats);
        }
        lsm_backend_mod.Backend.accumulateMaintenanceStats(&maintenance_stats, self.core.index_manager.snapshotLsmMaintenanceStats());
        return maintenance_stats;
    }

    pub fn snapshotPrimaryLsmWriteStatsForTest(self: *DB) ?lsm_backend_mod.Backend.WriteStats {
        lockApplyShared(self);
        defer self.core.unlockApplyShared();
        return self.core.primary_store_owner.snapshotLsmWriteStats();
    }

    pub fn snapshotLsmNativeStorageStats(self: *DB) lsm_backend_mod.NativeStorageStats {
        lockApplyShared(self);
        defer self.core.unlockApplyShared();
        return self.snapshotLsmNativeStorageStatsLocked();
    }

    pub fn trySnapshotLsmNativeStorageStats(self: *DB) ?lsm_backend_mod.NativeStorageStats {
        if (!self.core.tryLockApplyShared()) return null;
        defer self.core.unlockApplyShared();
        return self.snapshotLsmNativeStorageStatsLocked();
    }

    fn snapshotLsmNativeStorageStatsLocked(self: *DB) lsm_backend_mod.NativeStorageStats {
        var native_storage_stats = lsm_backend_mod.NativeStorageStats{};
        if (self.core.primary_store_owner.snapshotLsmNativeStorageStats()) |primary_stats| {
            native_storage_stats.fd_cache_entries +|= primary_stats.fd_cache_entries;
            native_storage_stats.fd_cache_capacity +|= primary_stats.fd_cache_capacity;
        }
        const index_stats = self.core.index_manager.snapshotLsmNativeStorageStats();
        native_storage_stats.fd_cache_entries +|= index_stats.fd_cache_entries;
        native_storage_stats.fd_cache_capacity +|= index_stats.fd_cache_capacity;
        return native_storage_stats;
    }

    pub fn runLsmMaintenanceStep(self: *DB) !bool {
        lockApply(self);
        defer self.core.unlockApply();

        const primary_score = self.core.primary_store_owner.lsmMaintenanceScore();
        const index_score = self.core.index_manager.lsmMaintenanceScore();
        if (primary_score == 0 and index_score == 0) {
            self.core.primary_store_owner.refreshLsmMaintenanceDebtHint();
            self.core.index_manager.refreshLsmMaintenanceDebtHint();
            return false;
        }
        if (primary_score >= index_score) {
            return try self.core.primary_store_owner.runLsmMaintenanceStep();
        }
        return try self.core.index_manager.runLsmMaintenanceStep();
    }

    pub fn runLsmMaintenanceStepBestEffort(self: *DB) !bool {
        if (!self.core.tryLockApplyExclusive()) return false;
        defer self.core.unlockApply();

        const primary_score = self.core.primary_store_owner.lsmMaintenanceDebtHint();
        if (primary_score > 0) {
            if (try self.core.primary_store_owner.runLsmMaintenanceStepBestEffort()) return true;
        }
        if (try self.core.index_manager.runLsmMaintenanceStepBestEffort()) return true;
        if (primary_score > 0) {
            self.core.primary_store_owner.refreshLsmMaintenanceDebtHint();
        }
        return false;
    }

    pub fn hasActiveDenseBulkWork(self: *const DB) bool {
        return asyncContextHasActiveDenseBulkWork(self.async_context);
    }

    pub fn runLsmMaintenanceUntilIdle(self: *DB) !usize {
        var steps: usize = 0;
        while (try self.runLsmMaintenanceStep()) {
            steps += 1;
        }
        return steps;
    }

    pub fn batch(self: *DB, req: types.BatchRequest) anyerror!void {
        if (benchMetricsEnabled()) {
            var profile = BatchProfile{};
            try self.batchInternal(req, &profile, .{});
            logBatchProfile(req, profile);
        } else {
            try self.batchInternal(req, null, .{});
        }
    }

    pub fn batchProfiled(self: *DB, req: types.BatchRequest, profile: *BatchProfile) anyerror!void {
        try self.batchInternal(req, profile, .{});
    }

    pub fn batchWithoutRangeValidation(self: *DB, req: types.BatchRequest) anyerror!void {
        try self.batchInternal(req, null, .{ .validate_range_ownership = false });
    }

    fn batchInternal(self: *DB, req: types.BatchRequest, profile: ?*BatchProfile, opts: BatchExecutionOptions) anyerror!void {
        if (openModeRequiresReadOnlyBackends(self.open_mode)) return error.ReadOnly;
        const total_start_ns = monotonicTimeNs();
        defer {
            if (profile) |active_profile| {
                active_profile.total_ns += monotonicTimeNs() - total_start_ns;
            }
        }

        try self.executor.failIfUnhealthy();

        lockApply(self);
        var apply_mutex_held = true;
        errdefer if (apply_mutex_held) self.core.unlockApply();

        if (self.bulk_ingest_coalescer.active and !self.flushing_bulk_ingest_coalescer) {
            if (self.bulk_ingest_coalescer.hasPending()) {
                self.core.unlockApply();
                apply_mutex_held = false;
                try self.flushBulkIngestCoalescerWithSyncLevel(req.sync_level, profile);
                lockApply(self);
                apply_mutex_held = true;
            }
        }

        const resolve_transforms_start_ns = monotonicTimeNs();
        var effective_ops = try coalesceKeyValueRequest(self, types.BatchWrite, req.writes, req.deletes, req.transforms);
        defer effective_ops.deinit(self.alloc);
        if (profile) |active_profile| recordProfileNs(profile, &active_profile.resolve_transforms_ns, resolve_transforms_start_ns);

        const merge_effective_req_start_ns = monotonicTimeNs();

        const effective_req: types.BatchRequest = .{
            .writes = effective_ops.writes,
            .deletes = effective_ops.deletes,
            .graph_writes = req.graph_writes,
            .graph_deletes = req.graph_deletes,
            .transforms = &.{},
            .predicates = req.predicates,
            .timestamp_ns = req.timestamp_ns,
            .sync_level = req.sync_level,
        };
        if (profile) |active_profile| recordProfileNs(profile, &active_profile.merge_effective_req_ns, merge_effective_req_start_ns);

        if (effective_req.predicates.len > 0) {
            const predicates_start_ns = monotonicTimeNs();
            var predicates = std.ArrayListUnmanaged(transactions_mod.VersionPredicate).empty;
            defer predicates.deinit(self.alloc);
            for (effective_req.predicates) |predicate| {
                try predicates.append(self.alloc, .{
                    .key = predicate.key,
                    .expected_version = predicate.expected_version,
                });
            }
            try self.core.checkVersionPredicates(predicates.items, null);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.predicates_ns, predicates_start_ns);
        }

        if (opts.validate_range_ownership) {
            const validate_range_start_ns = monotonicTimeNs();
            try self.core.validateBatchRangeOwnership(effective_req);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.validate_range_ns, validate_range_start_ns);
        }

        const extract_writes_start_ns = monotonicTimeNs();
        var extracted = try self.alloc.alloc(mapper.ExtractedWrite, effective_req.writes.len);
        var extracted_initialized: usize = 0;
        defer {
            for (extracted[0..extracted_initialized]) |*item| item.deinit(self.alloc);
            self.alloc.free(extracted);
        }

        var store_writes = std.ArrayListUnmanaged(docstore_mod.KVPair).empty;
        defer store_writes.deinit(self.alloc);
        var owned_store_keys = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (owned_store_keys.items) |key| self.alloc.free(key);
            owned_store_keys.deinit(self.alloc);
        }
        var owned_store_values = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (owned_store_values.items) |value| self.alloc.free(value);
            owned_store_values.deinit(self.alloc);
        }
        const vector_field_names_start_ns = monotonicTimeNs();
        const vector_store_field_names = try self.core.index_manager.vectorStoreFieldNamesAlloc(self.alloc);
        if (profile) |active_profile| recordProfileNs(profile, &active_profile.extract_vector_field_names_ns, vector_field_names_start_ns);
        defer {
            for (vector_store_field_names) |field| self.alloc.free(field);
            if (vector_store_field_names.len > 0) self.alloc.free(vector_store_field_names);
        }
        var timestamp_writes = std.ArrayListUnmanaged(docstore_mod.KVPair).empty;
        defer {
            for (timestamp_writes.items) |item| {
                self.alloc.free(@constCast(item.key));
                self.alloc.free(@constCast(item.value));
            }
            timestamp_writes.deinit(self.alloc);
        }
        var explicit_embedding_artifact_writes = std.ArrayListUnmanaged(types.BatchWrite).empty;
        defer {
            for (explicit_embedding_artifact_writes.items) |item| {
                self.alloc.free(@constCast(item.key));
                self.alloc.free(@constCast(item.value));
            }
            explicit_embedding_artifact_writes.deinit(self.alloc);
        }
        var explicit_graph_artifact_writes = std.ArrayListUnmanaged(types.BatchWrite).empty;
        defer {
            for (explicit_graph_artifact_writes.items) |item| {
                self.alloc.free(@constCast(item.key));
                self.alloc.free(@constCast(item.value));
            }
            explicit_graph_artifact_writes.deinit(self.alloc);
        }
        var delete_keys = std.ArrayListUnmanaged([]const u8).empty;
        defer delete_keys.deinit(self.alloc);
        var owned_delete_keys = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (owned_delete_keys.items) |key| self.alloc.free(key);
            owned_delete_keys.deinit(self.alloc);
        }
        var graph_artifact_clears = std.ArrayListUnmanaged(GraphArtifactClear).empty;
        defer {
            for (graph_artifact_clears.items) |*item| item.deinit(self.alloc);
            graph_artifact_clears.deinit(self.alloc);
        }
        var timestamp_delete_keys = std.ArrayListUnmanaged([]const u8).empty;
        defer {
            for (timestamp_delete_keys.items) |key| self.alloc.free(@constCast(key));
            timestamp_delete_keys.deinit(self.alloc);
        }
        var overwritten_flags = try self.alloc.alloc(bool, effective_req.writes.len);
        defer self.alloc.free(overwritten_flags);
        @memset(overwritten_flags, false);
        var overwrite_probe_entries = std.ArrayListUnmanaged(OverwriteProbeEntry).empty;
        defer overwrite_probe_entries.deinit(self.alloc);
        var identity_upsert_keys = std.ArrayListUnmanaged([]const u8).empty;
        defer identity_upsert_keys.deinit(self.alloc);
        var identity_upsert_write_indexes = std.ArrayListUnmanaged(usize).empty;
        defer identity_upsert_write_indexes.deinit(self.alloc);
        var identity_writes = std.ArrayListUnmanaged(docstore_mod.KVPair).empty;
        defer {
            for (identity_writes.items) |item| {
                self.alloc.free(@constCast(item.key));
                self.alloc.free(@constCast(item.value));
            }
            identity_writes.deinit(self.alloc);
        }

        const batch_timestamp_ns = if (effective_req.timestamp_ns != 0) effective_req.timestamp_ns else currentTimeNs();

        for (effective_req.writes, 0..) |write, i| {
            if (isMetadataKey(write.key)) {
                extracted[i] = .{
                    .cleaned_value = null,
                    .graph_writes = &.{},
                    .mentioned_graph_indexes = &.{},
                    .dense_embeddings = &.{},
                    .sparse_embeddings = &.{},
                };
                extracted_initialized += 1;
                try store_writes.append(self.alloc, .{
                    .key = write.key,
                    .value = write.value,
                });
                continue;
            }
            const mapper_extract_start_ns = monotonicTimeNs();
            extracted[i] = try mapper.extractWrite(self.alloc, write.key, write.value);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.extract_mapper_ns, mapper_extract_start_ns);
            const graph_field_extract_start_ns = monotonicTimeNs();
            try augmentExtractedWriteWithGraphFieldEdges(self, self.alloc, write.key, write.value, &extracted[i]);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.extract_graph_fields_ns, graph_field_extract_start_ns);
            const index_field_embeddings_start_ns = monotonicTimeNs();
            try self.core.index_manager.appendIndexFieldEmbeddingsToExtractedWrite(self.alloc, write.key, write.value, &extracted[i]);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.extract_index_field_embeddings_ns, index_field_embeddings_start_ns);
            extracted_initialized += 1;
            const embedding_artifacts_start_ns = monotonicTimeNs();
            for (extracted[i].dense_embeddings) |*embedding| {
                if (embedding.artifact_key != null) continue;
                embedding.artifact_key = try appendEmbeddingArtifactWrite(
                    self.alloc,
                    &explicit_embedding_artifact_writes,
                    write.key,
                    write.key,
                    embedding.index_name,
                    "_embeddings",
                    null,
                    null,
                    embedding.vector,
                );
            }
            for (extracted[i].sparse_embeddings) |*embedding| {
                if (embedding.artifact_key != null) continue;
                embedding.artifact_key = try appendSparseEmbeddingArtifactWrite(
                    self.alloc,
                    &explicit_embedding_artifact_writes,
                    write.key,
                    embedding.index_name,
                    null,
                    embedding.indices,
                    embedding.values,
                );
            }
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.extract_embedding_artifacts_ns, embedding_artifacts_start_ns);
            const graph_artifacts_start_ns = monotonicTimeNs();
            for (extracted[i].graph_writes) |graph_write| {
                try appendGraphEdgeArtifactWrite(self.alloc, &explicit_graph_artifact_writes, graph_write);
            }
            for (extracted[i].mentioned_graph_indexes) |index_name| {
                try graph_artifact_clears.append(self.alloc, .{
                    .doc_key = try self.alloc.dupe(u8, write.key),
                    .index_name = try self.alloc.dupe(u8, index_name),
                });
            }
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.extract_graph_artifacts_ns, graph_artifacts_start_ns);
            if (extracted[i].cleaned_value) |cleaned| {
                const strip_store_value_start_ns = monotonicTimeNs();
                const store_value = try strippedStoredDocumentValueAlloc(
                    self.alloc,
                    cleaned,
                    vector_store_field_names,
                    &owned_store_values,
                );
                if (profile) |active_profile| recordProfileNs(profile, &active_profile.extract_strip_store_value_ns, strip_store_value_start_ns);
                const store_key = try internal_keys.documentKeyAlloc(self.alloc, write.key);
                try owned_store_keys.append(self.alloc, store_key);
                try overwrite_probe_entries.append(self.alloc, .{
                    .key = store_key,
                    .write_index = i,
                });
                try store_writes.append(self.alloc, .{
                    .key = store_key,
                    .value = store_value,
                });
                try identity_upsert_keys.append(self.alloc, write.key);
                try identity_upsert_write_indexes.append(self.alloc, i);
                if (shouldWriteTimestamp(write.key)) {
                    const timestamp_start_ns = monotonicTimeNs();
                    const write_timestamp_ns = try resolveWriteTimestampNs(self, batch_timestamp_ns, write.value);
                    const timestamp_key = try makeTimestampKey(self.alloc, write.key);
                    const timestamp_value = try encodeTimestampValue(self.alloc, write_timestamp_ns);
                    try timestamp_writes.append(self.alloc, .{
                        .key = timestamp_key,
                        .value = timestamp_value,
                    });
                    if (profile) |active_profile| recordProfileNs(profile, &active_profile.extract_timestamp_ns, timestamp_start_ns);
                }
            }
        }
        if (profile) |active_profile| {
            active_profile.identity_upsert_keys += @intCast(identity_upsert_keys.items.len);
            active_profile.identity_delete_keys += @intCast(effective_req.deletes.len);
        }
        const identity_capacity_start_ns = monotonicTimeNs();
        if (!self.bulk_ingest_identity_all_new or effective_req.deletes.len != 0) {
            try self.failIfIdentityOrdinalExhaustedForNewUpserts(identity_upsert_keys.items);
        }
        if (profile) |active_profile| recordProfileNs(profile, &active_profile.identity_capacity_check_ns, identity_capacity_start_ns);

        var assume_all_new_identity_upserts = false;
        if (self.bulk_ingest_identity_all_new and effective_req.deletes.len == 0 and identity_upsert_keys.items.len > 0) {
            assume_all_new_identity_upserts = try self.rememberBulkIngestAllNewIdentityUpserts(identity_upsert_keys.items);
            if (!assume_all_new_identity_upserts) self.clearBulkIngestIdentityAllNewLocked();
        }

        if (!assume_all_new_identity_upserts and overwrite_probe_entries.items.len > 0) {
            const overwrite_probe_start_ns = monotonicTimeNs();
            std.sort.pdq(OverwriteProbeEntry, overwrite_probe_entries.items, {}, overwriteProbeLessThan);
            const probe_keys = try self.alloc.alloc([]const u8, overwrite_probe_entries.items.len);
            defer self.alloc.free(probe_keys);
            const probe_values = try self.alloc.alloc(?[]const u8, overwrite_probe_entries.items.len);
            defer self.alloc.free(probe_values);
            for (overwrite_probe_entries.items, 0..) |entry, i| {
                probe_keys[i] = entry.key;
            }
            var overwrite_probe_txn = try self.core.store.beginProbeTxn();
            defer overwrite_probe_txn.abort();
            try overwrite_probe_txn.getManySorted(probe_keys, probe_values);
            for (overwrite_probe_entries.items, 0..) |entry, i| {
                overwritten_flags[entry.write_index] = probe_values[i] != null;
            }
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.overwrite_probe_ns, overwrite_probe_start_ns);
        }

        for (effective_req.graph_writes) |graph_write| {
            try appendGraphEdgeArtifactWrite(self.alloc, &explicit_graph_artifact_writes, graph_write);
        }

        var changed_graph_artifact_keys = std.ArrayListUnmanaged([]u8).empty;
        defer {
            for (changed_graph_artifact_keys.items) |key| self.alloc.free(key);
            changed_graph_artifact_keys.deinit(self.alloc);
        }
        for (graph_artifact_clears.items) |clear| {
            const existing = try collectGraphArtifactsForDocIndex(self.alloc, self.core.store, clear.doc_key, clear.index_name);
            defer docstore_mod.DocStore.freeResults(self.alloc, existing);
            for (existing) |entry| {
                if (containsBatchWriteKey(explicit_graph_artifact_writes.items, entry.key)) continue;
                if (containsOwnedKey(owned_delete_keys.items, entry.key)) continue;
                const owned_key = try self.alloc.dupe(u8, entry.key);
                try owned_delete_keys.append(self.alloc, owned_key);
                try delete_keys.append(self.alloc, owned_key);
                try appendUniqueOwnedKey(self.alloc, &changed_graph_artifact_keys, entry.key);
            }
        }

        try store_writes.appendSlice(self.alloc, timestamp_writes.items);
        for (explicit_embedding_artifact_writes.items) |write| {
            try store_writes.append(self.alloc, .{
                .key = write.key,
                .value = write.value,
            });
        }
        for (explicit_graph_artifact_writes.items) |write| {
            try store_writes.append(self.alloc, .{
                .key = write.key,
                .value = write.value,
            });
            try appendUniqueOwnedKey(self.alloc, &changed_graph_artifact_keys, write.key);
        }
        for (effective_req.graph_deletes) |delete| {
            const artifact_key = try internal_keys.graphEdgeArtifactKeyAlloc(self.alloc, delete.source, delete.index_name, delete.edge_type, delete.target);
            defer self.alloc.free(artifact_key);
            if (containsBatchWriteKey(explicit_graph_artifact_writes.items, artifact_key)) continue;
            if (containsOwnedKey(owned_delete_keys.items, artifact_key)) continue;
            const owned_key = try self.alloc.dupe(u8, artifact_key);
            try owned_delete_keys.append(self.alloc, owned_key);
            try delete_keys.append(self.alloc, owned_key);
            try appendUniqueOwnedKey(self.alloc, &changed_graph_artifact_keys, artifact_key);
        }
        for (effective_req.deletes) |key| {
            const store_key = try internal_keys.documentKeyAlloc(self.alloc, key);
            try owned_delete_keys.append(self.alloc, store_key);
            try delete_keys.append(self.alloc, store_key);
            if (shouldWriteTimestamp(key)) {
                const timestamp_key = try makeTimestampKey(self.alloc, key);
                try timestamp_delete_keys.append(self.alloc, timestamp_key);
                try delete_keys.append(self.alloc, timestamp_key);
            }
        }
        if (profile) |active_profile| recordProfileNs(profile, &active_profile.extract_writes_ns, extract_writes_start_ns);

        const delete_artifacts_start_ns = monotonicTimeNs();
        const deleted_artifact_keys = try deleteEnrichmentArtifactsForBatch(self, effective_req, extracted[0..extracted_initialized]);
        defer freeOwnedKeySlice(self.alloc, deleted_artifact_keys);
        if (profile) |active_profile| recordProfileNs(profile, &active_profile.delete_artifacts_ns, delete_artifacts_start_ns);

        const use_thin_replay_fast_path =
            effective_req.sync_level != .full_text and
            effective_req.sync_level != .enrichments and
            effective_req.sync_level != .aknn and
            effective_req.sync_level != .full_index and
            !splitShadowRequiresMaterializedDerivedBatch(self);
        const include_generated_enrichment_hint = use_thin_replay_fast_path and
            self.core.hasGeneratedEnrichmentTargets();

        var precomputed_generated: PrecomputedGeneratedBatch = .{};
        defer precomputed_generated.deinit(self.alloc);
        var materialized_graph_artifact_writes = std.ArrayListUnmanaged(types.BatchWrite).empty;
        defer {
            for (materialized_graph_artifact_writes.items) |write| {
                self.alloc.free(@constCast(write.key));
                self.alloc.free(@constCast(write.value));
            }
            materialized_graph_artifact_writes.deinit(self.alloc);
        }
        if (!use_thin_replay_fast_path) {
            const precompute_generated_start_ns = monotonicTimeNs();
            precomputed_generated = try prepareGeneratedEnrichments(
                self,
                effective_req,
                extracted[0..extracted_initialized],
                generatedPrecomputeModeForSyncLevel(effective_req.sync_level),
            );

            for (precomputed_generated.artifact_writes) |write| {
                try store_writes.append(self.alloc, .{
                    .key = write.key,
                    .value = write.value,
                });
                try appendUniqueOwnedKey(self.alloc, &changed_graph_artifact_keys, write.key);
            }
            for (precomputed_generated.artifact_delete_keys) |key| {
                try delete_keys.append(self.alloc, key);
                if (internal_keys.isAssetArtifactKey(key)) {
                    try appendUniqueOwnedKey(self.alloc, &changed_graph_artifact_keys, key);
                }
            }
            try appendPrecomputedGraphSourceArtifacts(
                self,
                precomputed_generated.artifact_writes,
                precomputed_generated.artifact_delete_keys,
                &materialized_graph_artifact_writes,
                &store_writes,
                &delete_keys,
                &owned_delete_keys,
                &changed_graph_artifact_keys,
            );
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.precompute_generated_ns, precompute_generated_start_ns);
        }
        if (explicit_embedding_artifact_writes.items.len > 0 or
            explicit_graph_artifact_writes.items.len > 0 or
            materialized_graph_artifact_writes.items.len > 0 or
            precomputed_generated.artifact_writes.len > 0)
        {
            try self.core.appendArtifactPresenceMarker(&store_writes);
        }

        var sync_targets: ManagedSyncTargets = .{};
        defer sync_targets.deinit(self.alloc);
        var materialized_derived_batch: ?derived_types.DerivedBatch = null;
        defer if (materialized_derived_batch) |*materialized_batch| derived_types.deinitDerivedBatch(self.alloc, materialized_batch);
        const sequence = self.core.reserveDerivedAppendSequence();
        const identity_metadata_start_ns = monotonicTimeNs();
        var used_trusted_identity_path = false;
        if (effective_req.deletes.len != 0) {
            self.clearBulkIngestIdentityAllNewLocked();
        }
        if (self.bulk_ingest_identity_all_new and
            effective_req.deletes.len == 0 and
            identity_upsert_keys.items.len > 0 and
            (assume_all_new_identity_upserts or identityUpsertStoreWritesAreNew(identity_upsert_write_indexes.items, overwritten_flags)))
        {
            used_trusted_identity_path = try doc_identity.appendBatchIdentityMetadataAllNewTrustedStateForNamespaceAlloc(
                self.alloc,
                self.core.identity_namespace,
                sequence,
                &identity_writes,
                identity_upsert_keys.items,
                &self.bulk_ingest_identity_state,
            );
            if (!used_trusted_identity_path) self.clearBulkIngestIdentityAllNewLocked();
        }
        if (!used_trusted_identity_path) {
            try doc_identity.appendBatchIdentityMetadataForNamespaceAlloc(
                self.alloc,
                self.core.store,
                self.core.identity_namespace,
                sequence,
                &identity_writes,
                identity_upsert_keys.items,
                effective_req.deletes,
            );
        }
        if (profile) |active_profile| {
            recordProfileNs(profile, &active_profile.identity_metadata_ns, identity_metadata_start_ns);
            active_profile.identity_metadata_writes += @intCast(identity_writes.items.len);
        }
        const pending_identity_visibility_summary = try doc_identity.visibilitySummaryFromWrites(identity_writes.items);
        try store_writes.appendSlice(self.alloc, identity_writes.items);
        const build_derived_start_ns = monotonicTimeNs();
        const replay_payload = if (use_thin_replay_fast_path)
            try encodeThinReplayRecordPayload(
                self.alloc,
                effective_req,
                extracted[0..extracted_initialized],
                deleted_artifact_keys,
                changed_graph_artifact_keys.items,
                overwritten_flags,
                sequence,
                include_generated_enrichment_hint,
            )
        else blk: {
            materialized_derived_batch = try buildDerivedBatch(self.alloc, effective_req, extracted[0..extracted_initialized], deleted_artifact_keys, changed_graph_artifact_keys.items);
            for (materialized_derived_batch.?.overwritten_doc_keys) |key| self.alloc.free(@constCast(key));
            if (materialized_derived_batch.?.overwritten_doc_keys.len > 0) self.alloc.free(materialized_derived_batch.?.overwritten_doc_keys);
            materialized_derived_batch.?.overwritten_doc_keys = try buildOverwrittenDocKeys(self.alloc, effective_req.writes, overwritten_flags);
            materialized_derived_batch.?.documents = try takeOwnedSlice(derived_types.DerivedDocument, self.alloc, materialized_derived_batch.?.documents, &precomputed_generated.documents);
            materialized_derived_batch.?.dense_embeddings = try takeOwnedSlice(derived_types.DerivedDenseEmbeddingWrite, self.alloc, materialized_derived_batch.?.dense_embeddings, &precomputed_generated.dense_embeddings);
            materialized_derived_batch.?.sparse_embeddings = try takeOwnedSlice(derived_types.DerivedSparseEmbeddingWrite, self.alloc, materialized_derived_batch.?.sparse_embeddings, &precomputed_generated.sparse_embeddings);
            materialized_derived_batch.?.generated_enrichment_refs = precomputed_generated.generated_enrichment_refs;
            precomputed_generated.generated_enrichment_refs = &.{};
            materialized_derived_batch.?.sequence = sequence;
            const payload = try encodeChangeRecordPayload(&self.batchContext(), materialized_derived_batch.?, sequence);
            try attachInlineUpsertDocumentValues(self.alloc, &materialized_derived_batch.?, effective_req, extracted[0..extracted_initialized]);

            const apply_shadow_start_ns = monotonicTimeNs();
            try applyDerivedBatchToShadowIfNeeded(self, materialized_derived_batch.?);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.apply_shadow_ns, apply_shadow_start_ns);

            const collect_sync_targets_start_ns = monotonicTimeNs();
            sync_targets = try collectManagedSyncTargets(self.alloc, self.core.index_manager, materialized_derived_batch.?);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.collect_sync_targets_ns, collect_sync_targets_start_ns);
            break :blk payload;
        };
        defer self.alloc.free(replay_payload);
        if (profile) |active_profile| recordProfileNs(profile, &active_profile.build_derived_ns, build_derived_start_ns);

        const store_write_start_ns = monotonicTimeNs();
        const store_batch_options: backend_types.BatchOptions = if (opts.store_batch_options.mode != .default)
            opts.store_batch_options
        else if (self.bulk_ingest_coalescer.active)
            .{ .mode = .bulk_ingest }
        else
            .{};
        try self.core.store.putBatchWithReplayWithOptions(
            self.backend_runtime.io(),
            store_writes.items,
            delete_keys.items,
            .{
                .sequence = sequence,
                .payload = replay_payload,
            },
            store_batch_options,
        );
        if (pending_identity_visibility_summary) |summary| {
            self.identity_visibility_summary_cache = summary;
        }
        if (profile) |active_profile| {
            recordProfileNs(profile, &active_profile.store_write_ns, store_write_start_ns);
            active_profile.store_write_count += @intCast(store_writes.items.len);
            active_profile.store_delete_count += @intCast(delete_keys.items.len);
        }
        if (shouldAppendSplitDelta(self)) {
            const split_delta_start_ns = monotonicTimeNs();
            try self.core.appendSplitDelta(batch_timestamp_ns, store_writes.items, delete_keys.items);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.split_delta_ns, split_delta_start_ns);
        }

        const append_replay_journal_start_ns = monotonicTimeNs();
        self.executor.trackBacklogBytes(sequence, @intCast(replay_payload.len)) catch {};
        if (profile) |active_profile| recordProfileNs(profile, &active_profile.append_replay_journal_ns, append_replay_journal_start_ns);
        self.core.unlockApply();
        apply_mutex_held = false;
        var pressure_ctx = self.batchContext();
        const backlog_pressure_start_ns = monotonicTimeNs();
        try applyDerivedBacklogPressureContext(&pressure_ctx, sequence, effective_req.sync_level, sync_targets);
        if (profile) |active_profile| recordProfileNs(profile, &active_profile.backlog_pressure_ns, backlog_pressure_start_ns);
        const wait_sync_start_ns = monotonicTimeNs();
        if (self.executor.hasWorkers()) {
            const notify_executor_start_ns = monotonicTimeNs();
            notifyExecutorForSyncLevelWithDenseBulkDeferral(self.async_context, self.executor, effective_req.sync_level, sequence, sync_targets);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.executor_notify_ns, notify_executor_start_ns);
            const sync_wait_start_ns = monotonicTimeNs();
            try self.waitForSyncLevel(effective_req.sync_level, sequence, sync_targets);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.sync_wait_ns, sync_wait_start_ns);
        } else {
            if (syncLevelRequiresDerivedVisibility(effective_req.sync_level)) {
                const derived_apply_start_ns = monotonicTimeNs();
                if (effective_req.sync_level == .full_text) {
                    try applyDerivedBatchTargetsProfiled(self, materialized_derived_batch.?, sync_targets.full_text_indexes, profile);
                } else {
                    try applyDerivedBatchProfiled(self, materialized_derived_batch.?, profile);
                }
                if (profile) |active_profile| recordProfileNs(profile, &active_profile.derived_apply_ns, derived_apply_start_ns);
            }
            const sync_wait_start_ns = monotonicTimeNs();
            try self.waitForSyncLevel(effective_req.sync_level, sequence, sync_targets);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.sync_wait_ns, sync_wait_start_ns);
        }
        if (effective_req.sync_level == .full_index and self.text_merge_runtime == null) {
            try self.drainScheduledTextMerges();
        }
        if (profile) |active_profile| recordProfileNs(profile, &active_profile.wait_sync_ns, wait_sync_start_ns);
        if (self.enrichment_runtime) |runtime| {
            const notify_enrichment_start_ns = monotonicTimeNs();
            runtime.notifySequence(sequence);
            if (profile) |active_profile| recordProfileNs(profile, &active_profile.notify_enrichment_ns, notify_enrichment_start_ns);
        }
    }

    fn failIfIdentityOrdinalExhaustedForNewUpserts(self: *DB, doc_ids: []const []const u8) !void {
        if (doc_ids.len == 0) return;

        var txn = try self.core.store.beginProbeTxn();
        defer txn.abort();

        const raw_next = txn.get(internal_keys.identity_next_ordinal_key[0..]) catch |err| switch (err) {
            error.NotFound => return,
            else => return err,
        };
        if (raw_next.len != @sizeOf(doc_identity.DocOrdinal)) return error.InvalidDocIdentity;
        const next_ordinal = std.mem.readInt(doc_identity.DocOrdinal, raw_next[0..4], .big);
        if (next_ordinal != 0 and next_ordinal < std.math.maxInt(doc_identity.DocOrdinal)) return;

        var seen = std.StringHashMapUnmanaged(void).empty;
        defer seen.deinit(self.alloc);
        for (doc_ids) |doc_id| {
            if (seen.contains(doc_id)) continue;
            try seen.put(self.alloc, doc_id, {});
            if (try doc_identity.lookupOrdinalTxn(self.alloc, &txn, doc_id) != null) continue;
            return error.DocOrdinalExhausted;
        }
    }

    fn configureBulkIngestIdentityAllNewLocked(self: *DB) !void {
        self.clearBulkIngestIdentityAllNewLocked();
        if (!try self.primaryUserNamespaceIsEmptyLocked()) return;
        if (try doc_identity.loadAllNewTrustedStateForNamespace(self.core.store, self.core.identity_namespace)) |state| {
            self.bulk_ingest_identity_state = state;
            self.identity_visibility_summary_cache = state.visibility_summary;
            self.bulk_ingest_identity_all_new = true;
        }
    }

    fn clearBulkIngestIdentityAllNewLocked(self: *DB) void {
        self.bulk_ingest_identity_all_new = false;
        self.bulk_ingest_identity_state = .{};
        self.clearBulkIngestSeenDocKeysLocked();
    }

    fn clearBulkIngestSeenDocKeysLocked(self: *DB) void {
        var it = self.bulk_ingest_seen_doc_keys.keyIterator();
        while (it.next()) |key_ptr| self.alloc.free(@constCast(key_ptr.*));
        self.bulk_ingest_seen_doc_keys.clearRetainingCapacity();
    }

    fn primaryUserNamespaceIsEmptyLocked(self: *DB) !bool {
        var txn = try self.core.store.beginCurrentScanTxn();
        defer txn.abort();
        var cur = try txn.openCursor();
        defer cur.close();

        const lower = [_]u8{internal_keys.user_namespace};
        const first = (try cur.seekAtOrAfter(lower[0..])) orelse return true;
        return first.key.len == 0 or first.key[0] != internal_keys.user_namespace;
    }

    fn rememberBulkIngestAllNewIdentityUpserts(self: *DB, doc_ids: []const []const u8) !bool {
        var batch_seen = std.StringHashMapUnmanaged(void).empty;
        defer batch_seen.deinit(self.alloc);
        for (doc_ids) |doc_id| {
            if (self.bulk_ingest_seen_doc_keys.contains(doc_id)) return false;
            if (batch_seen.contains(doc_id)) return false;
            try batch_seen.put(self.alloc, doc_id, {});
        }

        for (doc_ids) |doc_id| {
            const owned = try self.alloc.dupe(u8, doc_id);
            errdefer self.alloc.free(owned);
            try self.bulk_ingest_seen_doc_keys.put(self.alloc, owned, {});
        }
        return true;
    }

    fn identityUpsertStoreWritesAreNew(write_indexes: []const usize, overwritten_flags: []const bool) bool {
        for (write_indexes) |write_index| {
            if (write_index >= overwritten_flags.len) return false;
            if (overwritten_flags[write_index]) return false;
        }
        return true;
    }

    fn CoalescedKeyValueRequest(comptime T: type) type {
        return struct {
            const Entry = struct {
                key: []const u8,
                value: ?[]const u8 = null,
                kind: enum { write, delete },
                owned_key: bool = false,
                owned_value: bool = false,
            };

            entries: []Entry = &.{},
            writes: []T = &.{},
            deletes: [][]const u8 = &.{},

            fn deinit(self: *@This(), alloc: Allocator) void {
                for (self.entries) |entry| {
                    if (entry.owned_key) alloc.free(@constCast(entry.key));
                    if (entry.owned_value) alloc.free(@constCast(entry.value.?));
                }
                if (self.entries.len > 0) alloc.free(self.entries);
                if (self.writes.len > 0) alloc.free(self.writes);
                if (self.deletes.len > 0) alloc.free(self.deletes);
                self.* = .{};
            }
        };
    }

    const BulkIngestCoalescer = struct {
        const Stats = struct {
            active_session: std.atomic.Value(u8) = .init(0),
            staged_keys: AtomicU64 = .init(0),
            stage_batches: AtomicU64 = .init(0),
            stage_writes: AtomicU64 = .init(0),
            stage_deletes: AtomicU64 = .init(0),
            stage_transforms: AtomicU64 = .init(0),
            flush_calls: AtomicU64 = .init(0),
            flushed_keys: AtomicU64 = .init(0),

            fn snapshot(self: *const @This()) types.BulkCoalescingStats {
                return .{
                    .active_session = self.active_session.load(.monotonic) != 0,
                    .staged_keys = self.staged_keys.load(.monotonic),
                    .stage_batches = self.stage_batches.load(.monotonic),
                    .stage_writes = self.stage_writes.load(.monotonic),
                    .stage_deletes = self.stage_deletes.load(.monotonic),
                    .stage_transforms = self.stage_transforms.load(.monotonic),
                    .flush_calls = self.flush_calls.load(.monotonic),
                    .flushed_keys = self.flushed_keys.load(.monotonic),
                };
            }
        };

        const Entry = struct {
            key: []u8,
            value: ?[]u8 = null,
            kind: enum { write, delete },
        };

        const RequestView = struct {
            writes: []types.BatchWrite = &.{},
            deletes: [][]const u8 = &.{},

            fn deinit(self: @This(), alloc: Allocator) void {
                if (self.writes.len > 0) alloc.free(self.writes);
                if (self.deletes.len > 0) alloc.free(self.deletes);
            }
        };

        active: bool = false,
        entries: std.ArrayListUnmanaged(Entry) = .empty,
        positions: std.StringHashMapUnmanaged(usize) = .empty,
        stats: Stats = .{},

        fn begin(self: *@This()) void {
            self.active = true;
            self.stats.active_session.store(1, .monotonic);
        }

        fn deinit(self: *@This(), alloc: Allocator) void {
            self.clear(alloc);
            self.entries.deinit(alloc);
            self.positions.deinit(alloc);
            self.* = .{};
        }

        fn clear(self: *@This(), alloc: Allocator) void {
            self.resetPending(alloc);
            self.active = false;
            self.stats.active_session.store(0, .monotonic);
        }

        fn resetPending(self: *@This(), alloc: Allocator) void {
            for (self.entries.items) |entry| {
                alloc.free(entry.key);
                if (entry.value) |value| alloc.free(value);
            }
            self.entries.clearRetainingCapacity();
            self.positions.clearRetainingCapacity();
            self.stats.staged_keys.store(0, .monotonic);
        }

        fn hasPending(self: *const @This()) bool {
            return self.entries.items.len > 0;
        }

        fn snapshotRequestView(self: *const @This(), alloc: Allocator) !RequestView {
            var result = RequestView{};
            errdefer result.deinit(alloc);

            var write_count: usize = 0;
            var delete_count: usize = 0;
            for (self.entries.items) |entry| {
                switch (entry.kind) {
                    .write => write_count += 1,
                    .delete => delete_count += 1,
                }
            }

            if (write_count > 0) result.writes = try alloc.alloc(types.BatchWrite, write_count);
            if (delete_count > 0) result.deletes = try alloc.alloc([]const u8, delete_count);

            var write_index: usize = 0;
            var delete_index: usize = 0;
            for (self.entries.items) |entry| {
                switch (entry.kind) {
                    .write => {
                        result.writes[write_index] = .{
                            .key = entry.key,
                            .value = entry.value.?,
                        };
                        write_index += 1;
                    },
                    .delete => {
                        result.deletes[delete_index] = entry.key;
                        delete_index += 1;
                    },
                }
            }
            return result;
        }

        fn stageBatch(self: *@This(), db: *DB, req: types.BatchRequest) !void {
            std.debug.assert(self.active);
            _ = self.stats.stage_batches.fetchAdd(1, .monotonic);
            _ = self.stats.stage_writes.fetchAdd(@intCast(req.writes.len), .monotonic);
            _ = self.stats.stage_deletes.fetchAdd(@intCast(req.deletes.len), .monotonic);
            _ = self.stats.stage_transforms.fetchAdd(@intCast(req.transforms.len), .monotonic);

            for (req.writes) |write| {
                try self.stageWrite(db.alloc, write.key, write.value);
            }
            for (req.deletes) |key| {
                try self.stageDelete(db.alloc, key);
            }
            for (req.transforms) |transform| {
                try self.stageTransform(db, transform);
            }
            self.stats.staged_keys.store(@intCast(self.entries.items.len), .monotonic);
        }

        fn stageWrite(self: *@This(), alloc: Allocator, key: []const u8, value: []const u8) !void {
            const gop = try self.positions.getOrPut(alloc, key);
            if (!gop.found_existing) {
                const owned_key = try alloc.dupe(u8, key);
                errdefer alloc.free(owned_key);
                const owned_value = try alloc.dupe(u8, value);
                errdefer alloc.free(owned_value);
                gop.key_ptr.* = owned_key;
                gop.value_ptr.* = self.entries.items.len;
                try self.entries.append(alloc, .{
                    .key = owned_key,
                    .value = owned_value,
                    .kind = .write,
                });
                return;
            }

            const entry = &self.entries.items[gop.value_ptr.*];
            if (entry.value) |existing| alloc.free(existing);
            entry.value = try alloc.dupe(u8, value);
            entry.kind = .write;
        }

        fn stageDelete(self: *@This(), alloc: Allocator, key: []const u8) !void {
            const gop = try self.positions.getOrPut(alloc, key);
            if (!gop.found_existing) {
                const owned_key = try alloc.dupe(u8, key);
                errdefer alloc.free(owned_key);
                gop.key_ptr.* = owned_key;
                gop.value_ptr.* = self.entries.items.len;
                try self.entries.append(alloc, .{
                    .key = owned_key,
                    .kind = .delete,
                });
                return;
            }

            const entry = &self.entries.items[gop.value_ptr.*];
            if (entry.value) |existing| {
                alloc.free(existing);
                entry.value = null;
            }
            entry.kind = .delete;
        }

        fn stageTransform(self: *@This(), db: *DB, transform: types.DocumentTransform) !void {
            const existing = if (self.positions.get(transform.key)) |entry_index|
                switch (self.entries.items[entry_index].kind) {
                    .write => self.entries.items[entry_index].value,
                    .delete => null,
                }
            else
                try db.get(db.alloc, transform.key);
            defer if (self.positions.get(transform.key) == null) {
                if (existing) |body| db.alloc.free(body);
            };

            const resolved = try transform_mod.resolveDocumentTransform(db.alloc, existing, transform) orelse return;
            errdefer db.alloc.free(resolved);
            try self.stageWriteOwned(db.alloc, transform.key, resolved);
        }

        fn stageWriteOwned(self: *@This(), alloc: Allocator, key: []const u8, owned_value: []u8) !void {
            const gop = try self.positions.getOrPut(alloc, key);
            if (!gop.found_existing) {
                const owned_key = try alloc.dupe(u8, key);
                errdefer alloc.free(owned_key);
                gop.key_ptr.* = owned_key;
                gop.value_ptr.* = self.entries.items.len;
                try self.entries.append(alloc, .{
                    .key = owned_key,
                    .value = owned_value,
                    .kind = .write,
                });
                return;
            }

            const entry = &self.entries.items[gop.value_ptr.*];
            if (entry.value) |existing| alloc.free(existing);
            entry.value = owned_value;
            entry.kind = .write;
        }
    };

    fn resetCoalescedEntryToDelete(comptime T: type, entry: *CoalescedKeyValueRequest(T).Entry) void {
        if (entry.owned_value) {
            // Caller frees previous owned value before switching the entry.
            entry.owned_value = false;
        }
        entry.value = null;
        entry.kind = .delete;
    }

    fn setCoalescedEntryToBorrowedWrite(comptime T: type, entry: *CoalescedKeyValueRequest(T).Entry, write: T) void {
        entry.key = write.key;
        entry.value = write.value;
        entry.kind = .write;
        entry.owned_key = false;
        entry.owned_value = false;
    }

    fn setCoalescedEntryToOwnedWrite(
        comptime T: type,
        alloc: Allocator,
        entry: *CoalescedKeyValueRequest(T).Entry,
        key: []const u8,
        value: []u8,
    ) !void {
        if (!entry.owned_key) {
            entry.key = try alloc.dupe(u8, key);
            entry.owned_key = true;
        }
        entry.value = value;
        entry.kind = .write;
        entry.owned_value = true;
    }

    fn coalesceKeyValueRequest(
        self: *DB,
        comptime T: type,
        writes: []const T,
        deletes: []const []const u8,
        transforms: []const types.DocumentTransform,
    ) !CoalescedKeyValueRequest(T) {
        var result = CoalescedKeyValueRequest(T){};
        var order = std.ArrayListUnmanaged(CoalescedKeyValueRequest(T).Entry).empty;
        errdefer {
            result.entries = order.items;
            order.items = &.{};
            order.capacity = 0;
            result.deinit(self.alloc);
        }
        defer order.deinit(self.alloc);

        var positions = std.StringHashMapUnmanaged(usize){};
        defer positions.deinit(self.alloc);

        for (writes) |write| {
            const gop = try positions.getOrPut(self.alloc, write.key);
            if (!gop.found_existing) {
                gop.value_ptr.* = order.items.len;
                try order.append(self.alloc, .{
                    .key = write.key,
                    .value = write.value,
                    .kind = .write,
                });
                continue;
            }
            const entry = &order.items[gop.value_ptr.*];
            if (entry.owned_value) self.alloc.free(@constCast(entry.value.?));
            if (entry.owned_key) self.alloc.free(@constCast(entry.key));
            setCoalescedEntryToBorrowedWrite(T, entry, write);
        }

        for (deletes) |key| {
            const gop = try positions.getOrPut(self.alloc, key);
            if (!gop.found_existing) {
                gop.value_ptr.* = order.items.len;
                try order.append(self.alloc, .{
                    .key = key,
                    .kind = .delete,
                });
                continue;
            }
            const entry = &order.items[gop.value_ptr.*];
            if (entry.owned_value) self.alloc.free(@constCast(entry.value.?));
            entry.owned_value = false;
            resetCoalescedEntryToDelete(T, entry);
        }

        for (transforms) |transform| {
            const maybe_index = positions.get(transform.key);
            const base_json = blk: {
                if (maybe_index) |entry_index| {
                    const entry = order.items[entry_index];
                    break :blk if (entry.kind == .write) entry.value.? else null;
                }
                break :blk try self.get(self.alloc, transform.key);
            };
            defer if (maybe_index == null) {
                if (base_json) |body| self.alloc.free(body);
            };

            const resolved = try transform_mod.resolveDocumentTransform(self.alloc, base_json, transform) orelse {
                if (maybe_index == null) continue;
                const entry = order.items[maybe_index.?];
                if (entry.kind == .delete) continue;
                continue;
            };
            errdefer self.alloc.free(resolved);

            const gop = try positions.getOrPut(self.alloc, transform.key);
            if (!gop.found_existing) {
                gop.value_ptr.* = order.items.len;
                try order.append(self.alloc, .{
                    .key = try self.alloc.dupe(u8, transform.key),
                    .value = resolved,
                    .kind = .write,
                    .owned_key = true,
                    .owned_value = true,
                });
                continue;
            }

            const entry = &order.items[gop.value_ptr.*];
            if (entry.owned_value) self.alloc.free(@constCast(entry.value.?));
            try setCoalescedEntryToOwnedWrite(T, self.alloc, entry, transform.key, resolved);
        }

        var write_count: usize = 0;
        var delete_count: usize = 0;
        for (order.items) |entry| {
            switch (entry.kind) {
                .write => write_count += 1,
                .delete => delete_count += 1,
            }
        }

        const final_entries = try order.toOwnedSlice(self.alloc);
        result.entries = final_entries;
        if (write_count > 0) result.writes = try self.alloc.alloc(T, write_count);
        if (delete_count > 0) result.deletes = try self.alloc.alloc([]const u8, delete_count);

        var write_index: usize = 0;
        var delete_index: usize = 0;
        for (final_entries) |entry| {
            switch (entry.kind) {
                .write => {
                    result.writes[write_index] = .{
                        .key = entry.key,
                        .value = entry.value.?,
                    };
                    write_index += 1;
                },
                .delete => {
                    result.deletes[delete_index] = entry.key;
                    delete_index += 1;
                },
            }
        }
        return result;
    }

    fn flushBulkIngestCoalescerWithSyncLevel(self: *DB, sync_level: types.SyncLevel, profile: ?*BatchProfile) anyerror!void {
        if (!self.bulk_ingest_coalescer.active or !self.bulk_ingest_coalescer.hasPending()) return;
        _ = self.bulk_ingest_coalescer.stats.flush_calls.fetchAdd(1, .monotonic);
        _ = self.bulk_ingest_coalescer.stats.flushed_keys.fetchAdd(@intCast(self.bulk_ingest_coalescer.entries.items.len), .monotonic);

        lockApply(self);
        var view = try self.bulk_ingest_coalescer.snapshotRequestView(self.alloc);
        self.core.unlockApply();
        defer view.deinit(self.alloc);

        self.flushing_bulk_ingest_coalescer = true;
        defer self.flushing_bulk_ingest_coalescer = false;

        try self.batchInternal(.{
            .writes = view.writes,
            .deletes = view.deletes,
            .sync_level = sync_level,
        }, profile, .{ .store_batch_options = .{ .mode = .bulk_ingest } });

        lockApply(self);
        defer self.core.unlockApply();
        self.bulk_ingest_coalescer.resetPending(self.alloc);
        self.bulk_ingest_coalescer.active = true;
    }

    pub fn get(self: *DB, alloc: Allocator, key: []const u8) !?[]u8 {
        const store_key = try encodeStoreLookupKeyAlloc(alloc, key);
        defer alloc.free(store_key);
        return try self.core.getStoreValue(alloc, store_key);
    }

    pub fn getGroupCreatedAtMillis(self: *DB, alloc: Allocator, group_id: u64) !?u64 {
        const key = try groupCreatedAtMetadataKeyAlloc(alloc, group_id);
        defer alloc.free(key);
        const raw = try self.get(alloc, key) orelse return null;
        defer alloc.free(raw);
        return try std.fmt.parseInt(u64, raw, 10);
    }

    pub fn ensureGroupCreatedAtMillis(self: *DB, alloc: Allocator, group_id: u64, now_ms: u64) !u64 {
        if (try self.getGroupCreatedAtMillis(alloc, group_id)) |created_at_millis| return created_at_millis;

        const key = try groupCreatedAtMetadataKeyAlloc(alloc, group_id);
        defer alloc.free(key);
        const encoded = try std.fmt.allocPrint(alloc, "{d}", .{now_ms});
        defer alloc.free(encoded);

        try self.batch(.{
            .writes = &.{
                .{
                    .key = key,
                    .value = encoded,
                },
            },
        });
        return now_ms;
    }

    pub fn getArtifact(self: *DB, alloc: Allocator, artifact_id: []const u8) !?types.ArtifactRecord {
        var artifact_ref = (try artifact_ids.decodeArtifactPublicIdAlloc(alloc, artifact_id)) orelse return error.InvalidArgument;
        errdefer artifact_ref.deinit(alloc);

        const internal_key = try artifact_ids.internalKeyForArtifactRefAlloc(alloc, artifact_ref);
        defer alloc.free(internal_key);

        const value = try self.core.getStoreValue(alloc, internal_key) orelse return null;
        errdefer alloc.free(value);

        return .{
            .id = try alloc.dupe(u8, artifact_id),
            .value = value,
            .artifact_ref = artifact_ref,
        };
    }

    pub fn getDocument(self: *DB, alloc: Allocator, key: []const u8, opts: types.LookupOptions) !?types.LookupResult {
        return try self.lookup(alloc, key, opts);
    }

    pub fn lookup(self: *DB, alloc: Allocator, key: []const u8, opts: types.LookupOptions) !?types.LookupResult {
        if (!internal_keys.isInternalUserKey(key) and (try isExpiredDocumentKey(self, alloc, key))) return null;
        const raw = try self.get(alloc, key) orelse return null;
        defer alloc.free(raw);
        const stored = try projectLookupStoredBytes(self, alloc, key, raw, opts);
        return .{ .json = stored };
    }

    pub fn getTimestamp(self: *DB, alloc: Allocator, key: []const u8) !u64 {
        if (internal_keys.isInternalUserKey(key)) return 0;
        return try self.core.readTimestamp(alloc, key);
    }

    pub fn updateRange(self: *DB, byte_range: types.ByteRange) !void {
        lockApply(self);
        defer self.core.unlockApply();
        try self.core.updateRange(byte_range);
    }

    pub fn getRange(self: *DB) types.ByteRange {
        return self.core.byteRange();
    }

    pub fn findMedianKey(self: *DB, alloc: Allocator) ![]u8 {
        const byte_range = self.getRange();
        const lower = try self.core.documentRangeLowerAlloc(byte_range.start);
        defer self.core.alloc.free(lower);
        const upper = if (byte_range.end.len > 0) try self.core.documentRangeUpperAlloc(byte_range.end) else null;
        defer if (upper) |buf| self.core.alloc.free(buf);

        const internal_key = self.core.findMedianStoreKey(alloc, lower, if (upper) |buf| buf else "", .{
            .skip_fn = &skipNonPrimaryMedianKey,
        }) catch |err| switch (err) {
            error.NotFound => return try doc_identity.findMedianDocIdAlloc(alloc, self.core.store, byte_range.start, byte_range.end),
            else => return err,
        };
        defer alloc.free(internal_key);

        return (try internal_keys.decodePrimaryDocumentKeyAlloc(alloc, internal_key)) orelse error.NotFound;
    }

    pub fn getSplitState(self: *DB, alloc: Allocator) !?types.SplitState {
        lockApplyShared(self);
        defer self.core.unlockApplyShared();
        const state = self.core.splitState() orelse return null;
        return .{
            .phase = state.phase,
            .split_key = try alloc.dupe(u8, state.split_key),
            .new_shard_id = state.new_shard_id,
            .started_at = state.started_at,
            .original_range_end = try alloc.dupe(u8, state.original_range_end),
        };
    }

    pub fn setSplitState(self: *DB, state: ?types.SplitState) !void {
        lockApply(self);
        defer self.core.unlockApply();
        if (state == null) {
            try self.core.setSplitState(null);
            return;
        }
        try self.core.setSplitState(.{
            .phase = state.?.phase,
            .split_key = state.?.split_key,
            .new_shard_id = state.?.new_shard_id,
            .started_at = state.?.started_at,
            .original_range_end = state.?.original_range_end,
        });
    }

    pub fn clearSplitState(self: *DB) !void {
        try self.setSplitState(null);
    }

