    fn resolveDocSetForIdsAlloc(self: *DB, alloc: Allocator, doc_ids: []const []const u8) !doc_set.ResolvedDocSet {
        lockApplyShared(self);
        defer self.core.unlockApplyShared();
        return try self.resolveDocSetForIdsNoLockAlloc(alloc, doc_ids);
    }

    fn resolveDocSetForIdsNoLockAlloc(self: *DB, alloc: Allocator, doc_ids: []const []const u8) !doc_set.ResolvedDocSet {
        return try self.resolveDocSetForIdsNoLockAtGenerationAlloc(alloc, doc_ids, null);
    }

    fn resolveDocSetForIdsNoLockAtGenerationAlloc(
        self: *DB,
        alloc: Allocator,
        doc_ids: []const []const u8,
        generation: ?u64,
    ) !doc_set.ResolvedDocSet {
        var txn = try self.core.store.beginProbeTxn();
        defer txn.abort();
        const resolved = try doc_identity.resolvedDocSetForIdsAtGenerationTxn(alloc, &txn, doc_ids, generation);
        self.recordResolvedDocSet(&resolved, doc_ids.len > 0 and switch (resolved) {
            .doc_keys => true,
            else => false,
        });
        return resolved;
    }

    fn resolvedDocFilterForIdsAlloc(
        self: *DB,
        include_positive: bool,
        include_doc_ids: []const []const u8,
        exclude_doc_ids: []const []const u8,
        generation: ?u64,
    ) !doc_set.ResolvedDocFilter {
        var filter = doc_set.ResolvedDocFilter{};
        errdefer filter.deinit(self.alloc);
        if (include_positive) {
            filter.include = try self.resolveDocSetForIdsNoLockAtGenerationAlloc(self.alloc, include_doc_ids, generation);
        }
        if (exclude_doc_ids.len > 0) {
            filter.exclude = try self.resolveDocSetForIdsNoLockAtGenerationAlloc(self.alloc, exclude_doc_ids, generation);
        }
        return filter;
    }

    fn docIdsForResolvedDocSetAlloc(self: *DB, alloc: Allocator, set: *const doc_set.ResolvedDocSet) !?[]const []const u8 {
        lockApplyShared(self);
        defer self.core.unlockApplyShared();
        return try self.docIdsForResolvedDocSetNoLockAlloc(alloc, set);
    }

    fn docIdsForResolvedDocSetNoLockAlloc(self: *DB, alloc: Allocator, set: *const doc_set.ResolvedDocSet) !?[]const []const u8 {
        return try self.docIdsForResolvedDocSetNoLockAtGenerationAlloc(alloc, set, null);
    }

    fn docIdsForResolvedDocSetNoLockAtGenerationAlloc(
        self: *DB,
        alloc: Allocator,
        set: *const doc_set.ResolvedDocSet,
        generation: ?u64,
    ) !?[]const []const u8 {
        switch (set.*) {
            .all => return null,
            .none => return try alloc.alloc([]const u8, 0),
            .doc_keys => |keys| return try dupeConstDocIdsAlloc(alloc, keys),
            .ordinals => |ordinals| {
                var txn = try self.core.store.beginProbeTxn();
                defer txn.abort();
                return try docIdsForOrdinalsAtGenerationTxnAlloc(alloc, &txn, ordinals, generation);
            },
            .ordinal_bitmap => |*bitmap| {
                var txn = try self.core.store.beginProbeTxn();
                defer txn.abort();
                var ordinals = std.ArrayListUnmanaged(doc_set.DocOrdinal).empty;
                defer ordinals.deinit(alloc);
                var iter = bitmap.iterator();
                while (iter.next()) |ordinal| try ordinals.append(alloc, ordinal);
                return try docIdsForOrdinalsAtGenerationTxnAlloc(alloc, &txn, ordinals.items, generation);
            },
        }
    }

    pub fn extractEnrichments(self: *DB, alloc: Allocator, writes: []const types.BatchWrite) !types.ExtractEnrichmentsResult {
        lockApplyShared(self);
        defer self.core.unlockApplyShared();

        var cleaned_writes = std.ArrayListUnmanaged(types.BatchWrite).empty;
        errdefer {
            for (cleaned_writes.items) |write| {
                alloc.free(@constCast(write.key));
                alloc.free(@constCast(write.value));
            }
            cleaned_writes.deinit(alloc);
        }
        var dense_embeddings = std.ArrayListUnmanaged(types.EnrichmentDenseEmbeddingWrite).empty;
        errdefer {
            for (dense_embeddings.items) |*embedding| embedding.deinit(alloc);
            dense_embeddings.deinit(alloc);
        }
        var sparse_embeddings = std.ArrayListUnmanaged(types.EnrichmentSparseEmbeddingWrite).empty;
        errdefer {
            for (sparse_embeddings.items) |*embedding| embedding.deinit(alloc);
            sparse_embeddings.deinit(alloc);
        }
        var graph_writes = std.ArrayListUnmanaged(types.GraphEdgeWrite).empty;
        errdefer {
            for (graph_writes.items) |*write| {
                alloc.free(@constCast(write.index_name));
                alloc.free(@constCast(write.source));
                alloc.free(@constCast(write.target));
                alloc.free(@constCast(write.edge_type));
                if (write.metadata_json.len > 0) alloc.free(@constCast(write.metadata_json));
            }
            graph_writes.deinit(alloc);
        }

        for (writes) |write| {
            var extracted = try mapper.extractWrite(alloc, write.key, write.value);
            try augmentExtractedWriteWithGraphFieldEdges(self, alloc, write.key, write.value, &extracted);
            defer extracted.deinit(alloc);

            if (extracted.cleaned_value) |cleaned| {
                try cleaned_writes.append(alloc, .{
                    .key = try alloc.dupe(u8, write.key),
                    .value = try alloc.dupe(u8, cleaned),
                });
            }
            for (extracted.dense_embeddings) |embedding| {
                const public_artifact = if (embedding.artifact_key) |artifact_key|
                    try artifact_ids.resolvePublicArtifactIdentityAlloc(alloc, artifact_key)
                else
                    null;
                defer if (public_artifact) |identity| {
                    var owned = identity;
                    owned.deinit(alloc);
                };

                try dense_embeddings.append(alloc, .{
                    .index_name = try alloc.dupe(u8, embedding.index_name),
                    .doc_key = try alloc.dupe(u8, embedding.doc_key),
                    .artifact_id = if (public_artifact) |identity| try alloc.dupe(u8, identity.id) else null,
                    .artifact_ref = if (public_artifact) |identity| try identity.artifact_ref.?.clone(alloc) else null,
                    .vector = try alloc.dupe(f32, embedding.vector),
                });
            }
            for (extracted.sparse_embeddings) |embedding| {
                try sparse_embeddings.append(alloc, .{
                    .index_name = try alloc.dupe(u8, embedding.index_name),
                    .doc_key = try alloc.dupe(u8, embedding.doc_key),
                    .indices = try alloc.dupe(u32, embedding.indices),
                    .values = try alloc.dupe(f32, embedding.values),
                });
            }
            for (extracted.graph_writes) |graph_write| {
                try graph_writes.append(alloc, .{
                    .index_name = try alloc.dupe(u8, graph_write.index_name),
                    .source = try alloc.dupe(u8, graph_write.source),
                    .target = try alloc.dupe(u8, graph_write.target),
                    .edge_type = try alloc.dupe(u8, graph_write.edge_type),
                    .weight = graph_write.weight,
                    .created_at = graph_write.created_at,
                    .updated_at = graph_write.updated_at,
                    .metadata_json = if (graph_write.metadata_json.len > 0) try alloc.dupe(u8, graph_write.metadata_json) else "",
                });
            }
        }

        return .{
            .cleaned_writes = try cleaned_writes.toOwnedSlice(alloc),
            .dense_embeddings = try dense_embeddings.toOwnedSlice(alloc),
            .sparse_embeddings = try sparse_embeddings.toOwnedSlice(alloc),
            .graph_writes = try graph_writes.toOwnedSlice(alloc),
        };
    }

    pub fn computeEnrichments(self: *DB, alloc: Allocator, writes: []const types.BatchWrite) !types.ComputeEnrichmentsResult {
        lockApplyShared(self);
        defer self.core.unlockApplyShared();

        var artifact_writes = std.ArrayListUnmanaged(types.BatchWrite).empty;
        errdefer {
            for (artifact_writes.items) |write| {
                alloc.free(@constCast(write.key));
                alloc.free(@constCast(write.value));
            }
            artifact_writes.deinit(alloc);
        }
        var documents = std.ArrayListUnmanaged(types.EnrichmentDocumentWrite).empty;
        errdefer {
            for (documents.items) |*doc| doc.deinit(alloc);
            documents.deinit(alloc);
        }
        var dense_embeddings = std.ArrayListUnmanaged(types.EnrichmentDenseEmbeddingWrite).empty;
        errdefer {
            for (dense_embeddings.items) |*embedding| embedding.deinit(alloc);
            dense_embeddings.deinit(alloc);
        }
        var failed_keys = std.ArrayListUnmanaged([]u8).empty;
        errdefer {
            for (failed_keys.items) |key| alloc.free(key);
            failed_keys.deinit(alloc);
        }

        for (writes) |write| {
            var extracted = try mapper.extractWrite(alloc, write.key, write.value);
            try augmentExtractedWriteWithGraphFieldEdges(self, alloc, write.key, write.value, &extracted);
            defer extracted.deinit(alloc);
            const cleaned = extracted.cleaned_value orelse continue;

            var explicit_dense = std.ArrayListUnmanaged(types.EnrichmentDenseEmbeddingWrite).empty;
            defer {
                for (explicit_dense.items) |*embedding| embedding.deinit(alloc);
                explicit_dense.deinit(alloc);
            }
            for (extracted.dense_embeddings) |embedding| {
                try explicit_dense.append(alloc, .{
                    .index_name = try alloc.dupe(u8, embedding.index_name),
                    .doc_key = try alloc.dupe(u8, embedding.doc_key),
                    .vector = try alloc.dupe(f32, embedding.vector),
                });
            }
            var explicit_sparse = std.ArrayListUnmanaged(types.EnrichmentSparseEmbeddingWrite).empty;
            defer {
                for (explicit_sparse.items) |*embedding| embedding.deinit(alloc);
                explicit_sparse.deinit(alloc);
            }
            for (extracted.sparse_embeddings) |embedding| {
                try explicit_sparse.append(alloc, .{
                    .index_name = try alloc.dupe(u8, embedding.index_name),
                    .doc_key = try alloc.dupe(u8, embedding.doc_key),
                    .indices = try alloc.dupe(u32, embedding.indices),
                    .values = try alloc.dupe(f32, embedding.values),
                });
            }

            const generated = try self.core.planGeneratedEnrichments(
                alloc,
                write.key,
                cleaned,
                explicit_dense.items,
                explicit_sparse.items,
            );
            defer enrichment_types.deinitGeneratedRequests(alloc, generated);

            var chunk_cache = std.ArrayListUnmanaged(ChunkCacheEntry).empty;
            defer {
                for (chunk_cache.items) |entry| {
                    alloc.free(entry.key);
                    chunker_mod.freeChunks(alloc, entry.chunks);
                }
                chunk_cache.deinit(alloc);
            }

            for (generated) |request| {
                switch (request.kind) {
                    .chunk_text => try computeChunkRequest(alloc, self, cleaned, request, &artifact_writes, &documents, &chunk_cache),
                    .dense_embedding => computeDenseRequest(alloc, self, cleaned, request, &artifact_writes, &dense_embeddings, &chunk_cache) catch |err| switch (err) {
                        error.MissingDenseEmbedder => try appendUniqueOwnedKey(alloc, &failed_keys, write.key),
                        else => return err,
                    },
                    else => {},
                }
            }
        }

        const public_artifact_writes = try externalizeArtifactWritesAlloc(alloc, try artifact_writes.toOwnedSlice(alloc));
        return .{
            .artifact_writes = public_artifact_writes,
            .documents = try documents.toOwnedSlice(alloc),
            .dense_embeddings = try dense_embeddings.toOwnedSlice(alloc),
            .failed_keys = try failed_keys.toOwnedSlice(alloc),
        };
    }

    pub fn deleteIndex(self: *DB, name: []const u8) !bool {
        self.executor.removeWorker(name);
        lockApply(self);
        defer self.core.unlockApply();
        const removed = try self.core.deleteIndex(name);
        return removed;
    }

    fn refreshManagedIndexWorkersLocked(self: *DB) !void {
        if (!self.start_index_workers) return;

        const managed_indexes = try self.core.managedIndexes(self.alloc);
        defer {
            for (managed_indexes) |index_ref| self.alloc.free(@constCast(index_ref.name));
            self.alloc.free(managed_indexes);
        }

        for (managed_indexes) |index_ref| {
            self.executor.removeWorker(index_ref.name);
        }
        for (managed_indexes) |index_ref| {
            const applied = try self.core.loadAppliedSequence(self.alloc, index_ref.name);
            try self.executor.addWorker(index_ref.name, index_ref, applied);
        }
    }

    fn resetManagedIndexAppliedSequences(self: *DB) !void {
        const managed_indexes = try self.core.managedIndexes(self.alloc);
        defer {
            for (managed_indexes) |index_ref| self.alloc.free(@constCast(index_ref.name));
            self.alloc.free(managed_indexes);
        }

        for (managed_indexes) |index_ref| {
            try self.core.saveAppliedSequence(index_ref.name, 0);
        }
    }

    fn rebaseManagedIndexAppliedSequencesIfNeeded(self: *DB) !void {
        const managed_indexes = try self.core.managedIndexes(self.alloc);
        defer {
            for (managed_indexes) |index_ref| self.alloc.free(@constCast(index_ref.name));
            self.alloc.free(managed_indexes);
        }

        var max_applied: u64 = 0;
        for (managed_indexes) |index_ref| {
            const applied = try self.core.loadAppliedSequence(self.alloc, index_ref.name);
            max_applied = @max(max_applied, applied);
        }
        if (max_applied == 0) return;

        // Applied watermarks are independent of the retained replay log. Once
        // replay entries are truncated, a valid applied watermark can be above
        // the current append floor recovered from replay metadata. Preserve the
        // watermark and advance the floor so future replay sequence allocation
        // cannot reuse already-applied sequence numbers.
        try ensureReplayFloor(self.core.store, max_applied + 1);
    }

    pub fn deleteEnrichment(self: *DB, kind: types.EnrichmentKind, name: []const u8) !bool {
        lockApply(self);
        defer self.core.unlockApply();
        return try self.core.deleteEnrichment(kind, name);
    }

    pub fn pendingWorkStats(self: *DB) db_core.PendingWorkStats {
        return .{
            .derived_target_sequence = self.core.nextDerivedSequence(),
            .has_async_indexes = self.executor.hasWorkers(),
            .enrichment = if (self.enrichment_runtime) |runtime| runtime.stats() else .{},
            .text_merge = if (self.text_merge_runtime) |runtime| runtime.statsAssumeApplyLockHeld() else self.core.index_manager.textMergeStats(),
        };
    }

    fn persistedEnrichmentStats(self: *DB) !types.EnrichmentStats {
        if (!self.core.hasGeneratedEnrichmentTargets()) return .{};
        const resources = self.core.batchExecutionResources();
        const applied = try enrichment_state.loadAppliedSequence(self.alloc, resources.store, enrichment_runtime_mod.scope_name);
        const status = try enrichment_state.loadRuntimeStatus(self.alloc, resources.store, enrichment_runtime_mod.scope_name);
        const target = @max(applied, status.target_sequence);
        return .{
            .enabled = target > 0 or status.error_count > 0 or status.retrying or status.worker_failed,
            .target_sequence = target,
            .applied_sequence = applied,
            .error_count = status.error_count,
            .retryable_error_count = status.retryable_error_count,
            .fatal_error_count = status.fatal_error_count,
            .retrying = status.retrying,
            .worker_failed = status.worker_failed,
        };
    }

    pub fn runDerivedUntil(self: *DB, sequence: u64) !void {
        if (sequence == 0) return;
        if (!self.executor.hasWorkers()) {
            try replayPendingDerivedBatches(self, null, null);
            return;
        }
        self.executor.notifySequence(sequence);
        try self.executor.waitForAll(sequence);
    }

    pub fn runDerivedUntilTargets(self: *DB, sequence: u64, index_names: []const []const u8) !void {
        if (sequence == 0 or index_names.len == 0) return;
        if (!self.executor.hasWorkers()) return;
        self.executor.notifyIndexes(sequence, index_names);
        try self.executor.waitForIndexes(sequence, index_names);
    }

    pub fn runEnrichmentUntil(self: *DB, sequence: u64) !void {
        if (sequence == 0) return;
        if (self.enrichment_runtime) |runtime| {
            runtime.notifySequence(sequence);
            try runtime.waitForApplied(sequence);
        }
    }

    pub fn runMaintenanceUntil(self: *DB, sequence: u64, sync_targets: ManagedSyncTargets) !void {
        var stable_target = sequence;
        while (true) {
            try self.runDerivedUntil(stable_target);
            try self.runEnrichmentUntil(stable_target);

            const next_target = self.core.nextDerivedSequence();
            if (next_target <= stable_target) {
                try waitForManagedIndexesApplied(self, sequence, sync_targets.all_indexes);
                return;
            }
            stable_target = next_target;
        }
    }

    pub fn runMaintenanceUntilTargets(self: *DB, sequence: u64, index_names: []const []const u8) !void {
        if (index_names.len == 0) return;
        var stable_target = sequence;
        while (true) {
            try self.runDerivedUntilTargets(stable_target, index_names);
            try self.runEnrichmentUntil(stable_target);

            const next_target = self.core.nextDerivedSequence();
            if (next_target <= stable_target) {
                try waitForManagedIndexesApplied(self, sequence, index_names);
                return;
            }
            stable_target = next_target;
        }
    }

    pub fn waitForCurrentSyncLevel(self: *DB, sync_level: types.SyncLevel) !void {
        try self.executor.failIfUnhealthy();
        const sequence = self.core.nextDerivedSequence();
        var sync_targets = try self.currentManagedSyncTargets(sync_level);
        defer sync_targets.deinit(self.alloc);
        if (self.executor.hasWorkers()) {
            notifyExecutorForSyncLevelWithDenseBulkDeferral(self.async_context, self.executor, sync_level, sequence, sync_targets);
        }
        try self.waitForSyncLevel(sync_level, sequence, sync_targets);
    }

    fn currentManagedSyncTargets(self: *DB, sync_level: types.SyncLevel) !ManagedSyncTargets {
        const managed_indexes = try self.core.managedIndexes(self.alloc);
        defer {
            for (managed_indexes) |index_ref| self.alloc.free(@constCast(index_ref.name));
            self.alloc.free(managed_indexes);
        }

        var full_text_indexes = std.ArrayListUnmanaged([]const u8).empty;
        errdefer {
            for (full_text_indexes.items) |name| self.alloc.free(@constCast(name));
            full_text_indexes.deinit(self.alloc);
        }
        var all_indexes = std.ArrayListUnmanaged([]const u8).empty;
        errdefer {
            for (all_indexes.items) |name| self.alloc.free(@constCast(name));
            all_indexes.deinit(self.alloc);
        }

        for (managed_indexes) |index_ref| {
            switch (sync_level) {
                .propose, .write => {},
                .enrichments => {},
                .full_text => {
                    if (index_ref.kind == .full_text) {
                        try appendUniqueOwnedName(self.alloc, &full_text_indexes, index_ref.name);
                        try appendUniqueOwnedName(self.alloc, &all_indexes, index_ref.name);
                    }
                },
                .aknn, .full_index => {
                    try appendUniqueOwnedName(self.alloc, &all_indexes, index_ref.name);
                    if (index_ref.kind == .full_text) {
                        try appendUniqueOwnedName(self.alloc, &full_text_indexes, index_ref.name);
                    }
                },
            }
        }

        return .{
            .full_text_indexes = try full_text_indexes.toOwnedSlice(self.alloc),
            .all_indexes = try all_indexes.toOwnedSlice(self.alloc),
        };
    }

    pub fn catchUpPendingDerivedReplay(self: *DB) !void {
        try replayPendingDerivedBatches(self, null, null);
    }

    pub fn catchUpPendingDerivedReplayWithProgress(
        self: *DB,
        progress_ctx: *anyopaque,
        progress_hook: ReplayProgressHook,
    ) !void {
        try replayPendingDerivedBatches(self, progress_ctx, progress_hook);
    }

    pub fn runUntilIdle(self: *DB) !void {
        var target_sequence = self.core.nextDerivedSequence();
        if (self.enrichment_runtime) |runtime| {
            target_sequence = @max(target_sequence, runtime.stats().target_sequence);
        }
        try self.runMaintenanceUntil(target_sequence, .{});
        _ = try self.evaluateAlgebraicAdaptiveCandidates();
        while (try self.runAlgebraicAdaptiveWork() != 0) {}
        try self.flushAppliedSequencesForIdle();
        try self.drainScheduledTextMerges();
        _ = try self.runDensePostingMaintenanceForIdle();
        _ = try self.runLsmMaintenanceUntilIdle();
    }

    pub fn runDensePostingMaintenanceForIdle(self: *DB) !usize {
        lockApply(self);
        defer self.core.unlockApply();
        return try self.core.index_manager.runDensePostingMaintenance(.{
            .max_postings_per_index = densePostingIdleMaxPostingsPerIndex(),
            .max_layout_changes_per_index = densePostingIdleMaxLayoutChangesPerIndex(),
            .max_boundary_reassignments_per_index = densePostingIdleMaxBoundaryReassignmentsPerIndex(),
        });
    }

    fn flushAppliedSequencesForIdle(self: *DB) !void {
        var seq_lock = lockAtomicWithBackoffProfiled(
            &self.async_context.applied_sequence_mutex,
            &self.async_context.stats.applied_sequence_mutex,
        );
        defer seq_lock.unlock();
        _ = try flushPendingAppliedSequencesLocked(self.async_context, true);
    }

    fn isRecoverableEmbeddingArtifactError(err: anyerror) bool {
        return switch (err) {
            error.InvalidArtifactHeader,
            error.InvalidArtifactMagic,
            error.UnsupportedArtifactCodecVersion,
            error.InvalidArtifactKind,
            error.InvalidArtifactPayload,
            error.InvalidVectorDimensions,
            error.InvalidSparseEmbedding,
            => true,
            else => false,
        };
    }

    fn freeDenseArtifactRebuildWrites(alloc: Allocator, writes: *std.ArrayListUnmanaged(mapper.DenseEmbeddingWrite)) void {
        for (writes.items) |write| {
            alloc.free(write.index_name);
            alloc.free(write.doc_key);
            if (write.parent_doc_key) |parent_doc_key| alloc.free(@constCast(parent_doc_key));
            if (write.artifact_key) |artifact_key| alloc.free(artifact_key);
            if (write.vector.len > 0) alloc.free(write.vector);
        }
        writes.clearRetainingCapacity();
    }

    fn flushDenseArtifactRebuildChunk(
        self: *DB,
        alloc: Allocator,
        writes: *std.ArrayListUnmanaged(mapper.DenseEmbeddingWrite),
    ) !void {
        defer freeDenseArtifactRebuildWrites(alloc, writes);
        if (writes.items.len == 0) return;

        for (self.core.index_manager.dense_indexes.items) |entry| {
            try self.core.index_manager.applyDenseEmbeddingWritesByNameWithOptions(
                self.core.store,
                entry.config.name,
                writes.items,
                .{ .mode = .bulk_ingest },
            );
        }
    }

    const DenseArtifactRebuildResumeHook = *const fn (ctx: *anyopaque, last_key: []const u8) anyerror!void;

    const DenseArtifactRebuildTarget = struct {
        dense_index_idx: usize,
        resume_from: ?[]u8 = null,
        artifact_target_count: u64 = 0,
        force_reset: bool = false,

        fn deinit(self: *@This(), alloc: Allocator) void {
            if (self.resume_from) |buf| alloc.free(buf);
            self.* = .{
                .dense_index_idx = 0,
            };
        }
    };

    const DenseArtifactRebuildPlan = struct {
        targets: []DenseArtifactRebuildTarget = &.{},
        target_sequence: u64 = 0,

        fn deinit(self: *@This(), alloc: Allocator) void {
            for (self.targets) |*target| target.deinit(alloc);
            if (self.targets.len > 0) alloc.free(self.targets);
            self.* = .{};
        }
    };

    const DenseArtifactTargetCounts = struct {
        per_target_index: std.AutoHashMapUnmanaged(usize, u64) = .empty,
        total_target_artifacts: u64 = 0,

        fn deinit(self: *@This(), alloc: Allocator) void {
            self.per_target_index.deinit(alloc);
            self.* = .{};
        }
    };

    fn denseIndexRebuildStatePathAlloc(self: *DB, alloc: Allocator, index_name: []const u8) ![]u8 {
        return try std.fmt.allocPrint(alloc, "{s}/indexes/{s}", .{ self.core.path, index_name });
    }

    fn denseArtifactNameForEntry(entry: anytype) []const u8 {
        return entry.embedding_name orelse entry.config.name;
    }

    fn collectDenseArtifactTargetCounts(
        self: *DB,
        alloc: Allocator,
        rebuild_targets: ?[]const DenseArtifactRebuildTarget,
    ) !DenseArtifactTargetCounts {
        var counts: DenseArtifactTargetCounts = .{};
        errdefer counts.deinit(alloc);

        var tracked_indices = std.ArrayListUnmanaged(usize).empty;
        defer tracked_indices.deinit(alloc);

        if (rebuild_targets) |targets| {
            for (targets) |target| {
                try tracked_indices.append(alloc, target.dense_index_idx);
                try counts.per_target_index.put(alloc, target.dense_index_idx, 0);
            }
        } else {
            for (self.core.index_manager.dense_indexes.items, 0..) |*entry, dense_index_idx| {
                const artifact_backed = entry.external or entry.chunk_name != null or entry.embedding_name != null;
                if (!artifact_backed) continue;
                try tracked_indices.append(alloc, dense_index_idx);
                try counts.per_target_index.put(alloc, dense_index_idx, 0);
            }
        }

        if (tracked_indices.items.len == 0) return counts;

        const lower = try self.core.documentRangeLowerAlloc("");
        defer self.core.alloc.free(lower);

        const ScanState = struct {
            alloc: Allocator,
            db: *DB,
            counts: *DenseArtifactTargetCounts,
            tracked_indices: []const usize,

            fn scanEntry(ctx: ?*anyopaque, key: []const u8, value: []const u8) anyerror!docstore_mod.DocStore.ScanAction {
                const state: *@This() = @ptrCast(@alignCast(ctx orelse return error.InvalidArgument));
                if (!internal_keys.isInternalUserKey(key)) return .@"continue";

                var artifact_ref = (try artifact_ids.decodeArtifactRefAlloc(state.alloc, key)) orelse return .@"continue";
                defer artifact_ref.deinit(state.alloc);
                if (artifact_ref.kind != .embedding) return .@"continue";

                const dims = enrichment_artifact_codec.decodeDenseEmbeddingDims(value) catch |err| {
                    if (isRecoverableEmbeddingArtifactError(err)) return .@"continue";
                    return err;
                };
                if (dims == 0) return .@"continue";

                var matched = false;
                for (state.tracked_indices) |dense_index_idx| {
                    const entry = &state.db.core.index_manager.dense_indexes.items[dense_index_idx];
                    if (!std.mem.eql(u8, denseArtifactNameForEntry(entry), artifact_ref.name)) continue;
                    if (entry.dims != dims) continue;
                    const count = state.counts.per_target_index.getPtr(dense_index_idx).?;
                    count.* += 1;
                    matched = true;
                }
                if (matched) state.counts.total_target_artifacts += 1;
                return .@"continue";
            }
        };

        var state = ScanState{
            .alloc = alloc,
            .db = self,
            .counts = &counts,
            .tracked_indices = tracked_indices.items,
        };
        try self.core.store.scanWithContext(lower, "", .{}, &state, ScanState.scanEntry);
        return counts;
    }

    fn collectDenseArtifactRebuildPlan(self: *DB, alloc: Allocator) !DenseArtifactRebuildPlan {
        const Candidate = struct {
            dense_index_idx: usize,
            persisted_resume: ?[]u8 = null,
            applied_sequence: u64,
            target_sequence: u64,
            force_reset: bool = false,

            fn deinit(candidate: *@This(), local_alloc: Allocator) void {
                if (candidate.persisted_resume) |buf| local_alloc.free(buf);
                candidate.* = .{
                    .dense_index_idx = 0,
                    .applied_sequence = 0,
                    .target_sequence = 0,
                };
            }
        };

        const recoverable_dense_integrity_errors = struct {
            fn check(err: anyerror) bool {
                return err == error.NotFound or err == error.FileNotFound or err == error.Corrupted;
            }
        };

        var targets = std.ArrayListUnmanaged(DenseArtifactRebuildTarget).empty;
        errdefer targets.deinit(alloc);

        var candidates = std.ArrayListUnmanaged(Candidate).empty;
        defer {
            for (candidates.items) |*candidate| candidate.deinit(alloc);
            candidates.deinit(alloc);
        }

        for (self.core.index_manager.dense_indexes.items, 0..) |*entry, dense_index_idx| {
            const artifact_backed = entry.external or entry.chunk_name != null or entry.embedding_name != null;
            if (!artifact_backed) continue;

            const rebuild_root_path = try self.denseIndexRebuildStatePathAlloc(alloc, entry.config.name);
            defer alloc.free(rebuild_root_path);
            const rebuild_state = backfill_state_mod.RebuildState.init(rebuild_root_path);
            const persisted_resume = try rebuild_state.check(alloc);
            errdefer if (persisted_resume) |buf| alloc.free(buf);
            const applied_sequence = try self.core.loadAppliedSequence(alloc, entry.config.name);
            const target_sequence = try self.probeDerivedReplayTargetSequence(
                alloc,
                self.core.replaySource(),
                .{
                    .name = entry.config.name,
                    .kind = .dense_vector,
                },
                applied_sequence,
            );
            if (persisted_resume == null and applied_sequence < target_sequence) continue;
            const force_reset = blk: {
                if (entry.index.stats().active_count == 0) break :blk false;
                if (@hasDecl(@TypeOf(entry.index), "validateStoredStructure")) {
                    entry.index.validateStoredStructure(alloc) catch |err| {
                        if (recoverable_dense_integrity_errors.check(err)) break :blk true;
                        return err;
                    };
                }
                break :blk false;
            };
            try candidates.append(alloc, .{
                .dense_index_idx = dense_index_idx,
                .persisted_resume = persisted_resume,
                .applied_sequence = applied_sequence,
                .target_sequence = target_sequence,
                .force_reset = force_reset,
            });
        }

        var candidate_targets = std.ArrayListUnmanaged(DenseArtifactRebuildTarget).empty;
        defer candidate_targets.deinit(alloc);
        for (candidates.items) |candidate| {
            try candidate_targets.append(alloc, .{ .dense_index_idx = candidate.dense_index_idx });
        }

        var target_counts = try self.collectDenseArtifactTargetCounts(alloc, candidate_targets.items);
        defer target_counts.deinit(alloc);

        for (candidates.items) |*candidate| {
            const dense_index_idx = candidate.dense_index_idx;
            const entry = &self.core.index_manager.dense_indexes.items[dense_index_idx];
            const artifact_target_count = target_counts.per_target_index.get(dense_index_idx) orelse 0;
            const rebuild_root_path = try self.denseIndexRebuildStatePathAlloc(alloc, entry.config.name);
            defer alloc.free(rebuild_root_path);
            const rebuild_state = backfill_state_mod.RebuildState.init(rebuild_root_path);
            const already_repaired = !candidate.force_reset and
                entry.index.stats().active_count >= artifact_target_count and
                candidate.applied_sequence >= candidate.target_sequence;

            if (candidate.persisted_resume) |buf| {
                if (artifact_target_count == 0 and !candidate.force_reset) {
                    try rebuild_state.clear();
                    continue;
                }
                if (already_repaired) {
                    try rebuild_state.clear();
                    continue;
                }
                try targets.append(alloc, .{
                    .dense_index_idx = dense_index_idx,
                    .resume_from = try alloc.dupe(u8, buf),
                    .artifact_target_count = artifact_target_count,
                    .force_reset = candidate.force_reset,
                });
                continue;
            }

            if (artifact_target_count == 0 and !candidate.force_reset) continue;
            if (!candidate.force_reset and entry.index.stats().active_count >= artifact_target_count) continue;

            try targets.append(alloc, .{
                .dense_index_idx = dense_index_idx,
                .artifact_target_count = artifact_target_count,
                .force_reset = candidate.force_reset,
            });
        }

        return .{
            .targets = try targets.toOwnedSlice(alloc),
            .target_sequence = target_counts.total_target_artifacts,
        };
    }

    fn prepareDenseArtifactRebuildPlan(self: *DB, plan: DenseArtifactRebuildPlan) !void {
        for (plan.targets) |target| {
            const entry = &self.core.index_manager.dense_indexes.items[target.dense_index_idx];
            if (target.force_reset) {
                try self.core.index_manager.resetDenseIndexForArtifactRebuild(entry.config.name);
            }
            const rebuild_root_path = try self.denseIndexRebuildStatePathAlloc(self.alloc, entry.config.name);
            defer self.alloc.free(rebuild_root_path);
            const rebuild_state = backfill_state_mod.RebuildState.init(rebuild_root_path);
            try rebuild_state.update(target.resume_from orelse "");
        }
    }

    fn finalizeDenseArtifactRebuildPlan(self: *DB, alloc: Allocator, plan: DenseArtifactRebuildPlan) !void {
        for (plan.targets) |target| {
            const entry = &self.core.index_manager.dense_indexes.items[target.dense_index_idx];
            const rebuild_root_path = try self.denseIndexRebuildStatePathAlloc(alloc, entry.config.name);
            defer alloc.free(rebuild_root_path);
            const rebuild_state = backfill_state_mod.RebuildState.init(rebuild_root_path);
            const applied_sequence = try self.core.loadAppliedSequence(alloc, entry.config.name);
            const target_sequence = try self.probeDerivedReplayTargetSequence(
                alloc,
                self.core.replaySource(),
                .{
                    .name = entry.config.name,
                    .kind = .dense_vector,
                },
                applied_sequence,
            );
            const repaired = entry.index.stats().active_count >= target.artifact_target_count and applied_sequence >= target_sequence;
            if (repaired) {
                try rebuild_state.clear();
            }
        }
    }

    fn denseArtifactWatermarkRepairNeeded(self: *DB, alloc: Allocator) !bool {
        return (try self.repairDenseArtifactAppliedSequencesFromCoverage(alloc, false)) > 0;
    }

    fn repairDenseArtifactAppliedSequencesIfCovered(self: *DB, alloc: Allocator) !usize {
        return try self.repairDenseArtifactAppliedSequencesFromCoverage(alloc, true);
    }

    fn repairDenseArtifactAppliedSequencesFromCoverage(self: *DB, alloc: Allocator, repair: bool) !usize {
        var target_counts = try self.collectDenseArtifactTargetCounts(alloc, null);
        defer target_counts.deinit(alloc);

        var repaired: usize = 0;
        for (self.core.index_manager.dense_indexes.items, 0..) |*entry, dense_index_idx| {
            const artifact_backed = entry.external or entry.chunk_name != null or entry.embedding_name != null;
            if (!artifact_backed) continue;

            const artifact_target_count = target_counts.per_target_index.get(dense_index_idx) orelse 0;
            if (artifact_target_count == 0) continue;
            if (entry.index.stats().active_count < artifact_target_count) continue;

            const applied_sequence = try self.core.loadAppliedSequence(alloc, entry.config.name);
            const target_sequence = try self.probeDerivedReplayTargetSequence(
                alloc,
                self.core.replaySource(),
                .{
                    .name = entry.config.name,
                    .kind = .dense_vector,
                },
                applied_sequence,
            );
            if (applied_sequence >= target_sequence) continue;

            repaired += 1;
            if (repair) try self.core.saveAppliedSequence(entry.config.name, target_sequence);
        }
        return repaired;
    }

    fn rebuildDenseIndexesFromStoredEmbeddingArtifacts(self: *DB, alloc: Allocator) !usize {
        return try self.rebuildDenseIndexesFromStoredEmbeddingArtifactsWithProgress(alloc, null, null);
    }

    fn rebuildDenseIndexesFromStoredEmbeddingArtifactsResumeWithProgress(
        self: *DB,
        alloc: Allocator,
        resume_from: ?[]const u8,
        rebuild_targets: ?[]const DenseArtifactRebuildTarget,
        target_sequence_override: ?u64,
        progress_ctx: ?*anyopaque,
        progress_hook: ?ReplayProgressHook,
        resume_ctx: ?*anyopaque,
        resume_hook: ?DenseArtifactRebuildResumeHook,
        rebuild_chunk_size: usize,
        rebuild_progress_interval: usize,
    ) !usize {
        const lower = try self.core.documentRangeLowerAlloc("");
        defer self.core.alloc.free(lower);

        const cache_nodes_before = try alloc.alloc(usize, self.core.index_manager.dense_indexes.items.len);
        defer alloc.free(cache_nodes_before);
        const cache_vectors_before = try alloc.alloc(usize, self.core.index_manager.dense_indexes.items.len);
        defer alloc.free(cache_vectors_before);
        for (self.core.index_manager.dense_indexes.items, 0..) |*entry, i| {
            cache_nodes_before[i] = entry.index.config.max_cached_nodes;
            cache_vectors_before[i] = entry.index.config.max_cached_vectors;
            entry.index.setCacheCaps(
                if (entry.index.config.max_cached_nodes > 0) @min(entry.index.config.max_cached_nodes, denseCatchUpStartupCacheNodes()) else 0,
                if (entry.index.config.max_cached_vectors > 0) @min(entry.index.config.max_cached_vectors, denseCatchUpStartupCacheVectors()) else 0,
            );
        }
        defer {
            for (self.core.index_manager.dense_indexes.items, 0..) |*entry, i| {
                entry.index.setCacheCaps(cache_nodes_before[i], cache_vectors_before[i]);
            }
        }

        const target_sequence = if (target_sequence_override) |value| value else blk: {
            var target_counts = try self.collectDenseArtifactTargetCounts(alloc, rebuild_targets);
            defer target_counts.deinit(alloc);
            break :blk target_counts.total_target_artifacts;
        };
        if (progress_hook != null) {
            const initial_progress: ReplayProgress = .{
                .sequence = 0,
                .target_sequence = target_sequence,
                .scanned_entries = 0,
                .applied_entries = 0,
                .active = true,
            };
            setDenseCatchUpProgress(self.async_context, initial_progress);
            try progress_hook.?(progress_ctx.?, "", initial_progress);
        }

        const ScanState = struct {
            db: *DB,
            alloc: Allocator,
            resume_from: ?[]const u8,
            target_sequence: u64,
            progress_ctx: ?*anyopaque,
            progress_hook: ?ReplayProgressHook,
            resume_ctx: ?*anyopaque,
            resume_hook: ?DenseArtifactRebuildResumeHook,
            rebuild_chunk_size: usize,
            rebuild_progress_interval: usize,
            rebuild_targets: ?[]const DenseArtifactRebuildTarget = null,
            rebuild_target_lookup: std.StringHashMapUnmanaged(usize) = .empty,
            writes: std.ArrayListUnmanaged(mapper.DenseEmbeddingWrite) = .empty,
            rebuilt: usize = 0,
            scanned_entries: usize = 0,
            last_reported_scanned_entries: usize = 0,
            last_reported_rebuilt: usize = 0,
            last_matching_key: ?[]u8 = null,
            last_flushed_key: ?[]u8 = null,

            fn deinit(state: *@This()) void {
                freeDenseArtifactRebuildWrites(state.alloc, &state.writes);
                state.writes.deinit(state.alloc);
                state.rebuild_target_lookup.deinit(state.alloc);
                if (state.last_matching_key) |buf| state.alloc.free(buf);
                if (state.last_flushed_key) |buf| state.alloc.free(buf);
            }

            fn updateOwnedKey(state: *@This(), slot: *?[]u8, key: []const u8) !void {
                if (slot.*) |buf| state.alloc.free(buf);
                slot.* = try state.alloc.dupe(u8, key);
            }

            fn rebuildTargetForIndex(
                state: *const @This(),
                index_name: []const u8,
            ) ?*const DenseArtifactRebuildTarget {
                const targets = state.rebuild_targets orelse return null;
                const target_idx = state.rebuild_target_lookup.get(index_name) orelse return null;
                return &targets[target_idx];
            }

            fn publishProgress(state: *@This(), active: bool) !void {
                const hook = state.progress_hook orelse return;
                const progress: ReplayProgress = .{
                    .sequence = @intCast(state.rebuilt),
                    .target_sequence = state.target_sequence,
                    .scanned_entries = @intCast(state.scanned_entries),
                    .applied_entries = @intCast(state.rebuilt),
                    .active = active,
                };
                state.last_reported_scanned_entries = state.scanned_entries;
                state.last_reported_rebuilt = state.rebuilt;
                setDenseCatchUpProgress(state.db.async_context, progress);
                try hook(state.progress_ctx.?, "", progress);
            }

            fn flushChunk(state: *@This(), key: []const u8) !void {
                try state.db.flushDenseArtifactRebuildChunk(state.alloc, &state.writes);
                try state.updateOwnedKey(&state.last_flushed_key, key);
                if (state.resume_hook) |hook| try hook(state.resume_ctx.?, key);
                try state.publishProgress(true);
            }

            fn scanEntry(ctx: ?*anyopaque, key: []const u8, value: []const u8) anyerror!docstore_mod.DocStore.ScanAction {
                const state: *@This() = @ptrCast(@alignCast(ctx orelse return error.InvalidArgument));
                if (!internal_keys.isInternalUserKey(key)) return .@"continue";
                if (state.resume_from) |resume_key| {
                    if (resume_key.len > 0 and std.mem.order(u8, key, resume_key) != .gt) return .@"continue";
                }

                var artifact_ref = (try artifact_ids.decodeArtifactRefAlloc(state.alloc, key)) orelse return .@"continue";
                defer artifact_ref.deinit(state.alloc);
                if (artifact_ref.kind != .embedding) return .@"continue";
                state.scanned_entries += 1;
                try state.updateOwnedKey(&state.last_matching_key, key);

                const vector = enrichment_artifact_codec.decodeDenseEmbeddingAlloc(state.alloc, value) catch |err| {
                    if (isRecoverableEmbeddingArtifactError(err)) {
                        try state.db.core.store.putBatch(&.{}, &.{key});
                        return .@"continue";
                    }
                    return err;
                };
                defer state.alloc.free(vector);
                const dims: u32 = @intCast(vector.len);
                if (dims == 0) return .@"continue";

                const consumer_indexes = state.db.core.index_manager.denseIndexesForEmbedding(state.alloc, artifact_ref.name, dims) catch |err| switch (err) {
                    error.ConflictingEnrichmentConfig => return .@"continue",
                    else => return err,
                };
                defer {
                    for (consumer_indexes) |index_name| state.alloc.free(index_name);
                    state.alloc.free(consumer_indexes);
                }
                if (consumer_indexes.len == 0) return .@"continue";

                const source_key = if (artifact_ref.source) |source| blk: {
                    var source_ref = types.ArtifactRef{
                        .document_id = try state.alloc.dupe(u8, artifact_ref.document_id),
                        .name = try state.alloc.dupe(u8, source.name),
                        .kind = source.kind,
                        .chunk_id = source.chunk_id,
                    };
                    defer source_ref.deinit(state.alloc);
                    break :blk try artifact_ids.internalKeyForArtifactRefAlloc(state.alloc, source_ref);
                } else try state.alloc.dupe(u8, artifact_ref.document_id);
                defer state.alloc.free(source_key);

                var emitted_any_target = false;
                for (consumer_indexes) |index_name| {
                    if (state.rebuild_targets) |_| {
                        const target = state.rebuildTargetForIndex(index_name) orelse continue;
                        if (target.resume_from) |target_resume| {
                            if (target_resume.len > 0 and std.mem.order(u8, key, target_resume) != .gt) continue;
                        }
                    }
                    try state.writes.append(state.alloc, .{
                        .index_name = try state.alloc.dupe(u8, index_name),
                        .doc_key = try state.alloc.dupe(u8, source_key),
                        .artifact_key = try state.alloc.dupe(u8, key),
                        .vector = &.{},
                    });
                    emitted_any_target = true;
                }
                if (emitted_any_target) {
                    state.rebuilt += 1;
                }

                if (state.progress_hook != null and
                    (state.scanned_entries - state.last_reported_scanned_entries >= state.rebuild_progress_interval or
                        state.rebuilt - state.last_reported_rebuilt >= state.rebuild_progress_interval))
                {
                    try state.publishProgress(true);
                }

                if (state.writes.items.len >= state.rebuild_chunk_size) {
                    try state.flushChunk(key);
                }
                return .@"continue";
            }
        };

        var state = ScanState{
            .db = self,
            .alloc = alloc,
            .resume_from = resume_from,
            .target_sequence = target_sequence,
            .progress_ctx = progress_ctx,
            .progress_hook = progress_hook,
            .resume_ctx = resume_ctx,
            .resume_hook = resume_hook,
            .rebuild_chunk_size = rebuild_chunk_size,
            .rebuild_progress_interval = rebuild_progress_interval,
            .rebuild_targets = rebuild_targets,
        };
        defer state.deinit();

        if (rebuild_targets) |targets| {
            for (targets, 0..) |target, target_idx| {
                const entry = &self.core.index_manager.dense_indexes.items[target.dense_index_idx];
                try state.rebuild_target_lookup.put(state.alloc, entry.config.name, target_idx);
            }
        }

        try self.core.store.scanWithContext(lower, "", .{}, &state, ScanState.scanEntry);

        if (state.writes.items.len > 0) {
            try self.flushDenseArtifactRebuildChunk(alloc, &state.writes);
        }
        if (state.last_flushed_key == null and state.last_matching_key != null) {
            try state.updateOwnedKey(&state.last_flushed_key, state.last_matching_key.?);
        }
        if (resume_hook) |hook| {
            if (state.last_flushed_key) |last_key| try hook(resume_ctx.?, last_key);
        }
        if (progress_hook != null) {
            const final_progress: ReplayProgress = .{
                .sequence = @intCast(state.rebuilt),
                .target_sequence = target_sequence,
                .scanned_entries = @intCast(state.scanned_entries),
                .applied_entries = @intCast(state.rebuilt),
                .active = false,
            };
            setDenseCatchUpProgress(self.async_context, final_progress);
            try progress_hook.?(progress_ctx.?, "", final_progress);
        }
        if (state.rebuilt == 0) return 0;
        return state.rebuilt;
    }

    fn rebuildDenseIndexesFromStoredEmbeddingArtifactsWithProgress(
        self: *DB,
        alloc: Allocator,
        progress_ctx: ?*anyopaque,
        progress_hook: ?ReplayProgressHook,
    ) !usize {
        return try self.rebuildDenseIndexesFromStoredEmbeddingArtifactsResumeWithProgress(
            alloc,
            null,
            null,
            null,
            progress_ctx,
            progress_hook,
            null,
            null,
            2048,
            128,
        );
    }

    pub fn rebuildDenseIndexesFromStoredEmbeddingArtifactsIfNeeded(self: *DB, alloc: Allocator) !usize {
        return try self.rebuildDenseIndexesFromStoredEmbeddingArtifactsIfNeededWithProgress(alloc, null, null);
    }

    pub fn hasPendingDenseArtifactRebuild(self: *DB, alloc: Allocator) !bool {
        var plan = try self.collectDenseArtifactRebuildPlan(alloc);
        defer plan.deinit(alloc);
        if (plan.targets.len > 0) return true;
        return try self.denseArtifactWatermarkRepairNeeded(alloc);
    }

    pub fn rebuildDenseIndexesFromStoredEmbeddingArtifactsIfNeededWithProgress(
        self: *DB,
        alloc: Allocator,
        progress_ctx: ?*anyopaque,
        progress_hook: ?ReplayProgressHook,
    ) !usize {
        var plan = try self.collectDenseArtifactRebuildPlan(alloc);
        defer plan.deinit(alloc);
        if (plan.targets.len == 0) return try self.repairDenseArtifactAppliedSequencesIfCovered(alloc);

        try self.prepareDenseArtifactRebuildPlan(plan);
        const ResumePersistCtx = struct {
            db: *DB,
            targets: []DenseArtifactRebuildTarget,

            fn run(ctx: *anyopaque, last_key: []const u8) !void {
                const persist: *@This() = @ptrCast(@alignCast(ctx));
                for (persist.targets) |*target| {
                    if (target.resume_from) |resume_from| {
                        if (std.mem.order(u8, last_key, resume_from) != .gt) continue;
                    }
                    const entry = &persist.db.core.index_manager.dense_indexes.items[target.dense_index_idx];
                    const rebuild_root_path = try persist.db.denseIndexRebuildStatePathAlloc(persist.db.alloc, entry.config.name);
                    defer persist.db.alloc.free(rebuild_root_path);
                    const rebuild_state = backfill_state_mod.RebuildState.init(rebuild_root_path);
                    try rebuild_state.update(last_key);
                    const owned_key = try persist.db.alloc.dupe(u8, last_key);
                    errdefer persist.db.alloc.free(owned_key);
                    if (target.resume_from) |resume_from| persist.db.alloc.free(resume_from);
                    target.resume_from = owned_key;
                }
            }
        };
        var persist_ctx = ResumePersistCtx{
            .db = self,
            .targets = plan.targets,
        };
        const rebuilt = try self.rebuildDenseIndexesFromStoredEmbeddingArtifactsResumeWithProgress(
            alloc,
            null,
            plan.targets,
            plan.target_sequence,
            progress_ctx,
            progress_hook,
            &persist_ctx,
            ResumePersistCtx.run,
            2048,
            128,
        );
        try self.finalizeDenseArtifactRebuildPlan(alloc, plan);
        _ = try self.repairDenseArtifactAppliedSequencesIfCovered(alloc);
        return rebuilt;
    }

    pub fn replayGeneratedEnrichmentsFromStoredDocs(self: *DB, alloc: Allocator) !usize {
        if (self.enrichment_runtime == null) return 0;

        const lower = try self.core.documentRangeLowerAlloc("");
        defer self.core.alloc.free(lower);
        const docs = try self.core.scanStoreRange(alloc, lower, "");
        defer docstore_mod.DocStore.freeResults(alloc, docs);
        const chunk_size: usize = 128;
        var index: usize = 0;
        var generated_ref_count: usize = 0;
        while (index < docs.len) {
            var write_count: usize = 0;
            var probe = index;
            while (probe < docs.len and write_count < chunk_size) : (probe += 1) {
                if (isPrimaryDocumentStoreKey(docs[probe].key)) write_count += 1;
            }
            if (write_count == 0) break;

            var writes = try alloc.alloc(types.BatchWrite, write_count);
            defer {
                for (writes) |write| alloc.free(@constCast(write.key));
                alloc.free(writes);
            }

            var extracted = try alloc.alloc(mapper.ExtractedWrite, write_count);
            var extracted_initialized: usize = 0;
            defer {
                for (extracted[0..extracted_initialized]) |*item| item.deinit(alloc);
                alloc.free(extracted);
            }

            var filled: usize = 0;
            while (index < docs.len and filled < write_count) : (index += 1) {
                const doc = docs[index];
                if (!isPrimaryDocumentStoreKey(doc.key)) continue;
                const raw_key = (try internal_keys.decodePrimaryDocumentKeyAlloc(alloc, doc.key)) orelse continue;
                errdefer alloc.free(raw_key);
                writes[filled] = .{
                    .key = raw_key,
                    .value = doc.value,
                };
                extracted[filled] = try mapper.extractWrite(alloc, raw_key, doc.value);
                extracted_initialized += 1;
                filled += 1;
            }

            var pending_batch = derived_types.DerivedBatch{};
            defer derived_types.deinitDerivedBatch(alloc, &pending_batch);
            try appendGeneratedEnrichments(self, &pending_batch, .{
                .writes = writes[0..filled],
                .sync_level = .write,
            }, extracted[0..filled]);
            if (pending_batch.generated_enrichment_refs.len == 0) continue;
            generated_ref_count += pending_batch.generated_enrichment_refs.len;
            const sequence = try appendDerivedBatchRecord(self, pending_batch);
            self.executor.notifySequence(sequence);
            if (self.enrichment_runtime) |runtime| runtime.notifySequence(sequence);
        }
        return generated_ref_count;
    }

    fn waitForSyncLevel(self: *DB, sync_level: types.SyncLevel, sequence: u64, sync_targets: ManagedSyncTargets) !void {
        switch (sync_level) {
            .propose, .write => try self.executor.failIfUnhealthy(),
            .enrichments => {
                try self.executor.failIfUnhealthy();
                try self.runEnrichmentUntil(sequence);
            },
            .full_text => {
                try self.runMaintenanceUntilTargets(sequence, sync_targets.full_text_indexes);
            },
            .aknn, .full_index => try self.runMaintenanceUntil(sequence, sync_targets),
        }
    }

    fn generatedPrecomputeModeForSyncLevel(sync_level: types.SyncLevel) GeneratedPrecomputeMode {
        return switch (sync_level) {
            .enrichments, .aknn, .full_index => .all,
            .full_text => .full_text_only,
            .propose, .write => .none,
        };
    }

