    try db_query_graph.applyGraphIntersection(alloc, result);
}

fn cloneNamedSetAsResult(alloc: Allocator, set: NamedResultSet, include_stored: bool) !types.SearchResult {
    return try db_query_graph.cloneNamedSetAsResult(alloc, set, include_stored);
}

fn currentTimeNs() u64 {
    return platform_clock.Clock.real().nowRealtimeNs();
}

fn makeTxnId(self: *DB) transactions_mod.TxnId {
    var txn_id: transactions_mod.TxnId = undefined;
    const now = currentTimeNs();
    const seq = self.core.nextDerivedAppendSequence();
    std.mem.writeInt(u64, txn_id[0..8], now, .little);
    std.mem.writeInt(u64, txn_id[8..16], seq, .little);
    return txn_id;
}

fn shouldWriteTimestamp(key: []const u8) bool {
    return !isMetadataKey(key) and !internal_keys.isInternalUserKey(key);
}

fn makeTimestampKey(alloc: Allocator, key: []const u8) ![]u8 {
    return try internal_keys.ttlKeyAlloc(alloc, key);
}

fn resolveWriteTimestampNs(self: *DB, fallback_timestamp_ns: u64, value_json: []const u8) !u64 {
    const schema = self.core.schema orelse return fallback_timestamp_ns;
    if (schema.ttl_duration_ns == 0) return fallback_timestamp_ns;
    return (try ttlTimestampNsFromDocumentValue(self.alloc, schema, value_json)) orelse fallback_timestamp_ns;
}

fn ttlTimestampNsFromDocumentValue(
    alloc: Allocator,
    schema: schema_mod.TableSchema,
    value_json: []const u8,
) !?u64 {
    var parsed = try std.json.parseFromSlice(std.json.Value, alloc, value_json, .{});
    defer parsed.deinit();
    const root = switch (parsed.value) {
        .object => |object| object,
        else => return null,
    };
    const ttl_value = root.get(schema.ttl_field) orelse return null;
    if (ttl_value == .null) return null;
    return try ttlTimestampNsFromJsonValue(ttl_value);
}

fn ttlTimestampNsFromJsonValue(value: std.json.Value) !u64 {
    return switch (value) {
        .integer => |integer| blk: {
            if (integer < 0) return error.InvalidArgument;
            break :blk std.math.cast(u64, integer) orelse return error.InvalidArgument;
        },
        .number_string => |text| std.fmt.parseInt(u64, std.mem.trim(u8, text, " \t\r\n"), 10) catch return error.InvalidArgument,
        .string => |text| ttlTimestampNsFromString(text),
        else => error.InvalidArgument,
    };
}

fn ttlTimestampNsFromString(text: []const u8) !u64 {
    const trimmed = std.mem.trim(u8, text, " \t\r\n");
    if (trimmed.len == 0) return error.InvalidArgument;
    if (std.fmt.parseInt(u64, trimmed, 10)) |ts| return ts else |_| {}
    if (try parsePatternRfc3339ToNs(trimmed)) |ts| return ts;
    return error.InvalidArgument;
}

fn encodeTimestampValue(alloc: Allocator, timestamp_ns: u64) ![]u8 {
    const buf = try alloc.alloc(u8, 8);
    std.mem.writeInt(u64, buf[0..8], timestamp_ns, .little);
    return buf;
}

fn ttlDurationNs(self: *DB) u64 {
    return if (self.core.schema) |schema| schema.ttl_duration_ns else 0;
}

fn isExpiredDocumentKey(self: *DB, alloc: Allocator, key: []const u8) !bool {
    const duration_ns = ttlDurationNs(self);
    if (duration_ns == 0) return false;
    const ts = try self.getTimestamp(alloc, key);
    if (ts == 0) return false;
    return ttl_mod.isExpired(ts, duration_ns, currentTimeNs());
}

fn loadDocumentTimestampsMany(self: *DB, alloc: Allocator, keys: []const []const u8) ![]u64 {
    const timestamps = try alloc.alloc(u64, keys.len);
    errdefer alloc.free(timestamps);
    @memset(timestamps, 0);
    if (keys.len == 0) return timestamps;

    const PendingTimestampLoad = struct {
        original_index: usize,
        store_key: []u8,
    };

    var pending = std.ArrayListUnmanaged(PendingTimestampLoad).empty;
    defer {
        for (pending.items) |item| alloc.free(item.store_key);
        pending.deinit(alloc);
    }

    for (keys, 0..) |key, i| {
        if (internal_keys.isInternalUserKey(key)) continue;
        try pending.append(alloc, .{
            .original_index = i,
            .store_key = try internal_keys.ttlKeyAlloc(alloc, key),
        });
    }
    if (pending.items.len == 0) return timestamps;

    std.mem.sort(PendingTimestampLoad, pending.items, {}, struct {
        fn lessThan(_: void, lhs: PendingTimestampLoad, rhs: PendingTimestampLoad) bool {
            return std.mem.order(u8, lhs.store_key, rhs.store_key) == .lt;
        }
    }.lessThan);

    const read_keys = try alloc.alloc([]const u8, pending.items.len);
    defer alloc.free(read_keys);
    const read_values = try alloc.alloc(?[]const u8, pending.items.len);
    defer alloc.free(read_values);
    @memset(read_values, null);

    for (pending.items, 0..) |item, i| read_keys[i] = item.store_key;

    var txn = try self.core.store.beginProbeTxn();
    defer txn.abort();
    try txn.getManySorted(read_keys, read_values);

    for (pending.items, 0..) |item, i| {
        const raw = read_values[i] orelse continue;
        if (raw.len != 8) continue;
        timestamps[item.original_index] = std.mem.readInt(u64, raw[0..8], .little);
    }
    return timestamps;
}

fn filterVisibleSearchHitsMany(self: *DB, alloc: Allocator, hits: []const types.SearchHit) ![]bool {
    const keep = try alloc.alloc(bool, hits.len);
    errdefer alloc.free(keep);
    @memset(keep, true);

    const duration_ns = ttlDurationNs(self);
    if (duration_ns == 0 or hits.len == 0) return keep;

    const expiry_now = currentTimeNs();
    const parent_ids = try alloc.alloc([]const u8, hits.len);
    defer alloc.free(parent_ids);

    const needs_stored = try alloc.alloc(bool, hits.len);
    defer alloc.free(needs_stored);
    @memset(needs_stored, false);

    const fallback_to_hit = try alloc.alloc(bool, hits.len);
    defer alloc.free(fallback_to_hit);
    @memset(fallback_to_hit, false);

    for (hits, 0..) |hit, i| {
        if (internal_keys.isChunkArtifactRecordKey(hit.id)) {
            const parent = (try internal_keys.decodeDocumentComponentAlloc(alloc, hit.id)) orelse {
                fallback_to_hit[i] = true;
                parent_ids[i] = hit.id;
                continue;
            };
            parent_ids[i] = parent;
            continue;
        }
        if (hit.stored_data != null) {
            parent_ids[i] = parseChunkParentIdFromStoredAlloc(alloc, hit.stored_data.?) catch {
                fallback_to_hit[i] = true;
                parent_ids[i] = hit.id;
                continue;
            };
            continue;
        }
        needs_stored[i] = true;
        parent_ids[i] = hit.id;
    }
    defer {
        for (hits, 0..) |_, i| {
            if (!needs_stored[i] and !std.mem.eql(u8, parent_ids[i], hits[i].id)) alloc.free(parent_ids[i]);
        }
    }

    var pending_indices = std.ArrayListUnmanaged(usize).empty;
    defer pending_indices.deinit(alloc);
    for (needs_stored, 0..) |needed, i| if (needed) try pending_indices.append(alloc, i);
    if (pending_indices.items.len > 0) {
        const pending_keys = try alloc.alloc([]const u8, pending_indices.items.len);
        defer alloc.free(pending_keys);
        for (pending_indices.items, 0..) |hit_index, i| pending_keys[i] = hits[hit_index].id;

        const loaded = try loadStoredSearchDocumentsMany(self, alloc, pending_keys);
        defer freeOptionalOwnedBytes(alloc, loaded);
        for (pending_indices.items, 0..) |hit_index, i| {
            const stored = loaded[i] orelse {
                fallback_to_hit[hit_index] = true;
                continue;
            };
            parent_ids[hit_index] = parseChunkParentIdFromStoredAlloc(alloc, stored) catch {
                fallback_to_hit[hit_index] = true;
                continue;
            };
        }
    }

    const timestamps = try loadDocumentTimestampsMany(self, alloc, parent_ids);
    defer alloc.free(timestamps);
    for (timestamps, 0..) |ts, i| {
        if (ts == 0) continue;
        keep[i] = !ttl_mod.isExpired(ts, duration_ns, expiry_now);
    }
    return keep;
}

fn filterExpiredSearchResult(self: *DB, alloc: Allocator, raw: types.SearchResult) !types.SearchResult {
    if (ttlDurationNs(self) == 0) return raw;
    return try db_query_result_shape.filterVisibleSearchResult(alloc, raw, .{
        .ctx = self,
        .func = isVisibleSearchHitCallback,
        .filter_many = filterVisibleSearchHitsManyCallback,
    });
