fn parsePatternRfc3339ToNs(text: []const u8) !?u64 {
    return try db_query_graph.parsePatternRfc3339ToNs(text);
}

fn buildDerivedBatch(
    alloc: Allocator,
    req: types.BatchRequest,
    extracted: []const mapper.ExtractedWrite,
    deleted_artifact_keys: []const []u8,
    changed_artifact_keys: []const []u8,
) !derived_types.DerivedBatch {
    var documents = try alloc.alloc(derived_types.DerivedDocument, req.writes.len);
    var initialized: usize = 0;
    errdefer {
        var tmp = derived_types.DerivedBatch{ .documents = documents[0..initialized] };
        derived_types.deinitDerivedBatch(alloc, &tmp);
    }

    for (req.writes, 0..) |write, i| {
        var targets = std.ArrayListUnmanaged(derived_types.DerivedTargetRef).empty;
        defer targets.deinit(alloc);

        if (extracted[i].cleaned_value != null) {
            try targets.append(alloc, .{
                .kind = .full_text,
                .index_name = try alloc.dupe(u8, "*"),
            });
        }
        for (extracted[i].dense_embeddings) |embedding| {
            try targets.append(alloc, .{
                .kind = .dense_vector,
                .index_name = try alloc.dupe(u8, embedding.index_name),
            });
        }
        for (extracted[i].sparse_embeddings) |embedding| {
            try targets.append(alloc, .{
                .kind = .sparse_vector,
                .index_name = try alloc.dupe(u8, embedding.index_name),
            });
        }
        for (extracted[i].mentioned_graph_indexes) |index_name| {
            try targets.append(alloc, .{
                .kind = .graph,
                .index_name = try alloc.dupe(u8, index_name),
            });
        }
        for (req.graph_writes) |graph_write| {
            if (std.mem.eql(u8, graph_write.source, write.key)) {
                try targets.append(alloc, .{
                    .kind = .graph,
                    .index_name = try alloc.dupe(u8, graph_write.index_name),
                });
            }
        }

        documents[i] = .{
            .key = try alloc.dupe(u8, write.key),
            .action = if (extracted[i].cleaned_value == null) .preserve_base_document else .upsert,
            .cleaned_value = null,
            .targets = try targets.toOwnedSlice(alloc),
        };
        initialized += 1;
    }

    var deleted_keys = try alloc.alloc([]const u8, req.deletes.len + deleted_artifact_keys.len);
    var deleted_initialized: usize = 0;
    errdefer {
        for (deleted_keys[0..deleted_initialized]) |key| alloc.free(key);
        alloc.free(deleted_keys);
    }
    for (req.deletes, 0..) |key, i| {
        deleted_keys[i] = try alloc.dupe(u8, key);
        deleted_initialized += 1;
    }
    for (deleted_artifact_keys) |key| {
        deleted_keys[deleted_initialized] = try alloc.dupe(u8, key);
        deleted_initialized += 1;
    }

    var overwritten_doc_keys_list = std.ArrayListUnmanaged([]const u8).empty;
    defer overwritten_doc_keys_list.deinit(alloc);
    for (req.writes, 0..) |write, i| {
        if (extracted[i].cleaned_value != null) {
            try overwritten_doc_keys_list.append(alloc, try alloc.dupe(u8, write.key));
        }
    }

    var changed_artifact_keys_list = std.ArrayListUnmanaged([]const u8).empty;
    errdefer {
        for (changed_artifact_keys_list.items) |key| alloc.free(@constCast(key));
        changed_artifact_keys_list.deinit(alloc);
    }
    for (changed_artifact_keys) |key| {
        try changed_artifact_keys_list.append(alloc, try alloc.dupe(u8, key));
    }
    for (deleted_artifact_keys) |key| {
        if (!internal_keys.isAssetArtifactKey(key) and !internal_keys.isGraphEdgeArtifactKey(key)) continue;
        try changed_artifact_keys_list.append(alloc, try alloc.dupe(u8, key));
    }

    var graph_doc_clears = std.ArrayListUnmanaged(derived_types.DerivedGraphDocClear).empty;
    errdefer {
        for (graph_doc_clears.items) |clear| {
            alloc.free(clear.key);
            for (clear.index_names) |index_name| alloc.free(index_name);
            if (clear.index_names.len > 0) alloc.free(clear.index_names);
        }
        graph_doc_clears.deinit(alloc);
    }
    for (req.writes, 0..) |write, i| {
        if (extracted[i].mentioned_graph_indexes.len == 0) continue;
        var index_names = try alloc.alloc([]const u8, extracted[i].mentioned_graph_indexes.len);
        for (extracted[i].mentioned_graph_indexes, 0..) |index_name, j| {
            index_names[j] = try alloc.dupe(u8, index_name);
        }
        try graph_doc_clears.append(alloc, .{
            .key = try alloc.dupe(u8, write.key),
            .index_names = index_names,
        });
    }

    var graph_writes = std.ArrayListUnmanaged(types.GraphEdgeWrite).empty;
    errdefer {
        for (graph_writes.items) |write| {
            alloc.free(@constCast(write.index_name));
            alloc.free(@constCast(write.source));
            alloc.free(@constCast(write.target));
            alloc.free(@constCast(write.edge_type));
            if (write.metadata_json.len > 0) alloc.free(@constCast(write.metadata_json));
        }
        graph_writes.deinit(alloc);
    }
    for (extracted) |item| {
        for (item.graph_writes) |write| {
            try graph_writes.append(alloc, .{
                .index_name = try alloc.dupe(u8, write.index_name),
                .source = try alloc.dupe(u8, write.source),
                .target = try alloc.dupe(u8, write.target),
                .edge_type = try alloc.dupe(u8, write.edge_type),
                .weight = write.weight,
                .created_at = write.created_at,
                .updated_at = write.updated_at,
                .metadata_json = if (write.metadata_json.len > 0) try alloc.dupe(u8, write.metadata_json) else "",
            });
        }
    }
    for (req.graph_writes) |write| {
        try graph_writes.append(alloc, .{
            .index_name = try alloc.dupe(u8, write.index_name),
            .source = try alloc.dupe(u8, write.source),
            .target = try alloc.dupe(u8, write.target),
            .edge_type = try alloc.dupe(u8, write.edge_type),
            .weight = write.weight,
            .created_at = write.created_at,
            .updated_at = write.updated_at,
            .metadata_json = if (write.metadata_json.len > 0) try alloc.dupe(u8, write.metadata_json) else "",
        });
    }

    var graph_deletes = std.ArrayListUnmanaged(types.GraphEdgeDelete).empty;
    errdefer {
        for (graph_deletes.items) |delete| {
            alloc.free(@constCast(delete.index_name));
            alloc.free(@constCast(delete.source));
            alloc.free(@constCast(delete.target));
            alloc.free(@constCast(delete.edge_type));
        }
        graph_deletes.deinit(alloc);
    }
    for (req.graph_deletes) |delete| {
        try graph_deletes.append(alloc, .{
            .index_name = try alloc.dupe(u8, delete.index_name),
            .source = try alloc.dupe(u8, delete.source),
            .target = try alloc.dupe(u8, delete.target),
            .edge_type = try alloc.dupe(u8, delete.edge_type),
        });
    }

    var dense_embeddings = std.ArrayListUnmanaged(derived_types.DerivedDenseEmbeddingWrite).empty;
    errdefer {
        for (dense_embeddings.items) |embedding| {
            alloc.free(embedding.index_name);
            if (embedding.parent_doc_key) |parent_doc_key| alloc.free(parent_doc_key);
            alloc.free(embedding.doc_key);
            if (embedding.artifact_key) |artifact_key| alloc.free(artifact_key);
            if (embedding.vector.len > 0) alloc.free(embedding.vector);
        }
        dense_embeddings.deinit(alloc);
    }
    for (extracted) |item| {
        for (item.dense_embeddings) |embedding| {
            try dense_embeddings.append(alloc, .{
                .index_name = try alloc.dupe(u8, embedding.index_name),
                .doc_key = try alloc.dupe(u8, embedding.doc_key),
                .artifact_key = if (embedding.artifact_key) |artifact_key| try alloc.dupe(u8, artifact_key) else null,
                .vector = if (embedding.artifact_key != null) &.{} else try alloc.dupe(f32, embedding.vector),
            });
        }
    }

    var sparse_embeddings = std.ArrayListUnmanaged(derived_types.DerivedSparseEmbeddingWrite).empty;
    errdefer {
        for (sparse_embeddings.items) |embedding| {
            alloc.free(embedding.index_name);
            alloc.free(embedding.doc_key);
            if (embedding.indices.len > 0) alloc.free(embedding.indices);
            if (embedding.values.len > 0) alloc.free(embedding.values);
        }
        sparse_embeddings.deinit(alloc);
    }
    for (extracted) |item| {
        for (item.sparse_embeddings) |embedding| {
            try sparse_embeddings.append(alloc, .{
                .index_name = try alloc.dupe(u8, embedding.index_name),
                .doc_key = try alloc.dupe(u8, embedding.doc_key),
                .artifact_key = if (embedding.artifact_key) |artifact_key| try alloc.dupe(u8, artifact_key) else null,
                .indices = try alloc.dupe(u32, embedding.indices),
                .values = try alloc.dupe(f32, embedding.values),
            });
        }
    }

    return .{
        .sequence = 0,
        .documents = documents,
        .deleted_keys = deleted_keys,
        .overwritten_doc_keys = try overwritten_doc_keys_list.toOwnedSlice(alloc),
        .changed_artifact_keys = try changed_artifact_keys_list.toOwnedSlice(alloc),
        .graph_doc_clears = try graph_doc_clears.toOwnedSlice(alloc),
        .dense_embeddings = try dense_embeddings.toOwnedSlice(alloc),
        .sparse_embeddings = try sparse_embeddings.toOwnedSlice(alloc),
        .generated_enrichment_refs = &.{},
        .graph_writes = try graph_writes.toOwnedSlice(alloc),
        .graph_deletes = try graph_deletes.toOwnedSlice(alloc),
    };
}

fn appendGeneratedEnrichments(
    self: *DB,
    batch: *derived_types.DerivedBatch,
    req: types.BatchRequest,
    extracted: []const mapper.ExtractedWrite,
) !void {
    var planned = std.ArrayListUnmanaged(enrichment_types.GeneratedEnrichmentRef).empty;
    errdefer enrichment_types.deinitGeneratedRefs(self.alloc, planned.items);

    for (req.writes, 0..) |write, i| {
        const cleaned = extracted[i].cleaned_value orelse continue;
        var explicit_dense = std.ArrayListUnmanaged(types.EnrichmentDenseEmbeddingWrite).empty;
        defer {
            for (explicit_dense.items) |*embedding| embedding.deinit(self.alloc);
            explicit_dense.deinit(self.alloc);
        }
        for (extracted[i].dense_embeddings) |embedding| {
            try explicit_dense.append(self.alloc, .{
                .index_name = try self.alloc.dupe(u8, embedding.index_name),
                .doc_key = try self.alloc.dupe(u8, embedding.doc_key),
                .vector = try self.alloc.dupe(f32, embedding.vector),
            });
        }
        var explicit_sparse = std.ArrayListUnmanaged(types.EnrichmentSparseEmbeddingWrite).empty;
        defer {
            for (explicit_sparse.items) |*embedding| embedding.deinit(self.alloc);
            explicit_sparse.deinit(self.alloc);
        }
        for (extracted[i].sparse_embeddings) |embedding| {
            try explicit_sparse.append(self.alloc, .{
                .index_name = try self.alloc.dupe(u8, embedding.index_name),
                .doc_key = try self.alloc.dupe(u8, embedding.doc_key),
                .indices = try self.alloc.dupe(u32, embedding.indices),
                .values = try self.alloc.dupe(f32, embedding.values),
            });
        }
        const generated = try self.core.planGeneratedEnrichments(
            self.alloc,
            write.key,
            cleaned,
            explicit_dense.items,
            explicit_sparse.items,
        );
        defer enrichment_types.deinitGeneratedRequests(self.alloc, generated);
        for (generated) |request| {
            try planned.append(self.alloc, try enrichment_types.requestToRef(self.alloc, request));
        }
    }

    batch.generated_enrichment_refs = try planned.toOwnedSlice(self.alloc);
}

fn deleteEnrichmentArtifactsForBatch(self: *DB, req: types.BatchRequest, extracted: []const mapper.ExtractedWrite) ![][]u8 {
    _ = extracted;
    if (!self.core.hasArtifactCleanupMaybe()) return try self.alloc.alloc([]u8, 0);

    var deleted = std.ArrayListUnmanaged([]u8).empty;
    errdefer freeOwnedKeySlice(self.alloc, deleted.items);

    for (req.deletes) |key| {
        try self.core.collectAndDeleteEnrichmentArtifactsForDocContext(self.alloc, key, &deleted);
    }
    return try deleted.toOwnedSlice(self.alloc);
}

fn collectAndDeleteEnrichmentArtifactsForDocContext(
    alloc: Allocator,
    store: *docstore_mod.DocStore,
    doc_key: []const u8,
    deleted: *std.ArrayListUnmanaged([]u8),
) !void {
    var deletes = std.ArrayListUnmanaged([]const u8).empty;
    defer deletes.deinit(alloc);
    var unrecorded_delete_keys = std.ArrayListUnmanaged([]u8).empty;
    defer {
        for (unrecorded_delete_keys.items) |key| alloc.free(key);
        unrecorded_delete_keys.deinit(alloc);
    }

    const artifact_prefix = try internal_keys.artifactRootPrefixAlloc(alloc, doc_key);
    defer alloc.free(artifact_prefix);
    try collectDeleteKeysForPrefix(alloc, store, artifact_prefix, &deletes, deleted, &unrecorded_delete_keys);

    const asset_state_prefix = try internal_keys.assetStateRootPrefixAlloc(alloc, doc_key);
    defer alloc.free(asset_state_prefix);
    try collectDeleteKeysForPrefix(alloc, store, asset_state_prefix, &deletes, null, &unrecorded_delete_keys);

    const graph_asset_state_prefix = try internal_keys.graphAssetStateRootPrefixAlloc(alloc, doc_key);
    defer alloc.free(graph_asset_state_prefix);
    try collectDeleteKeysForPrefix(alloc, store, graph_asset_state_prefix, &deletes, null, &unrecorded_delete_keys);

    if (deletes.items.len > 0) {
        try store.putBatch(&.{}, deletes.items);
    }
}

fn collectDeleteKeysForPrefix(
    alloc: Allocator,
    store: *docstore_mod.DocStore,
    prefix: []const u8,
    deletes: *std.ArrayListUnmanaged([]const u8),
    recorded: ?*std.ArrayListUnmanaged([]u8),
    unrecorded: *std.ArrayListUnmanaged([]u8),
) !void {
    const existing = try store.scanPrefix(alloc, prefix);
    defer docstore_mod.DocStore.freeResults(alloc, existing);
    for (existing) |entry| {
        const owned = try alloc.dupe(u8, entry.key);
        errdefer alloc.free(owned);
        try deletes.append(alloc, owned);
        if (recorded) |out| {
            try out.append(alloc, owned);
        } else {
            try unrecorded.append(alloc, owned);
        }
    }
}

fn collectGraphArtifactsForDocIndex(
    alloc: Allocator,
    store: *docstore_mod.DocStore,
    doc_key: []const u8,
    index_name: []const u8,
) ![]docstore_mod.OwnedKVPair {
    const prefix = try internal_keys.graphArtifactIndexPrefixAlloc(alloc, doc_key, index_name);
    defer alloc.free(prefix);
    return try store.scanPrefix(alloc, prefix);
}

fn executeDeleteBatchContext(ctx: *const BatchExecutionContext, keys: []const []const u8, sync_level: types.SyncLevel) !void {
    if (keys.len == 0) return;

    var store_writes = std.ArrayListUnmanaged(docstore_mod.KVPair).empty;
    defer store_writes.deinit(ctx.alloc);
    var identity_writes = std.ArrayListUnmanaged(docstore_mod.KVPair).empty;
    defer {
        for (identity_writes.items) |item| {
            ctx.alloc.free(@constCast(item.key));
            ctx.alloc.free(@constCast(item.value));
        }
        identity_writes.deinit(ctx.alloc);
    }
    var delete_keys = std.ArrayListUnmanaged([]const u8).empty;
    defer delete_keys.deinit(ctx.alloc);
    var timestamp_delete_keys = std.ArrayListUnmanaged([]const u8).empty;
    defer {
        for (timestamp_delete_keys.items) |key| ctx.alloc.free(@constCast(key));
        timestamp_delete_keys.deinit(ctx.alloc);
    }
    var owned_delete_keys = std.ArrayListUnmanaged([]u8).empty;
    defer {
        for (owned_delete_keys.items) |key| ctx.alloc.free(key);
        owned_delete_keys.deinit(ctx.alloc);
    }

    for (keys) |key| {
        const store_key = try internal_keys.documentKeyAlloc(ctx.alloc, key);
        try owned_delete_keys.append(ctx.alloc, store_key);
        try delete_keys.append(ctx.alloc, store_key);
        if (!shouldWriteTimestamp(key)) continue;
        const timestamp_key = try makeTimestampKey(ctx.alloc, key);
        try timestamp_delete_keys.append(ctx.alloc, timestamp_key);
        try delete_keys.append(ctx.alloc, timestamp_key);
    }

    var deleted_artifact_keys = std.ArrayListUnmanaged([]u8).empty;
    defer freeOwnedKeySlice(ctx.alloc, deleted_artifact_keys.items);
    const should_scan_artifacts = if (ctx.artifact_cleanup_maybe) |artifact_cleanup_maybe|
        artifact_cleanup_maybe.load(.acquire) or ctx.index_manager.hasGeneratedEnrichmentTargets()
    else
        true;
    if (should_scan_artifacts) {
        for (keys) |key| {
            try collectAndDeleteEnrichmentArtifactsForDocContext(ctx.alloc, ctx.store, key, &deleted_artifact_keys);
        }
    }

    const req = types.BatchRequest{
        .deletes = keys,
        .sync_level = sync_level,
    };
    var derived_batch = try buildDerivedBatch(ctx.alloc, req, &.{}, deleted_artifact_keys.items, &.{});
    defer derived_types.deinitDerivedBatch(ctx.alloc, &derived_batch);
    const sequence = ctx.store.reserveNextReplaySequence(1);
    derived_batch.sequence = sequence;
    try doc_identity.appendBatchIdentityMetadataForNamespaceAlloc(
        ctx.alloc,
        ctx.store,
        ctx.identity_namespace,
        sequence,
        &identity_writes,
        &.{},
        keys,
    );
    try store_writes.appendSlice(ctx.alloc, identity_writes.items);
    const replay_payload = try encodeChangeRecordPayload(ctx, derived_batch, sequence);
    defer ctx.alloc.free(replay_payload);
    try ctx.store.putBatchWithReplay(ctx.io, store_writes.items, delete_keys.items, .{
        .sequence = sequence,
        .payload = replay_payload,
    });
    var sync_targets = try collectManagedSyncTargets(ctx.alloc, ctx.index_manager, derived_batch);
    defer sync_targets.deinit(ctx.alloc);
    ctx.executor.trackBacklogBytes(sequence, @intCast(replay_payload.len)) catch {};
    try applyDerivedBacklogPressureContext(ctx, sequence, sync_level, sync_targets);
    if (ctx.executor.hasWorkers()) {
        notifyExecutorForSyncLevelWithDenseBulkDeferral(ctx.async_context, ctx.executor, sync_level, sequence, sync_targets);
        try waitForSyncLevelContext(ctx, sync_level, sequence, sync_targets);
    } else {
        if (syncLevelRequiresDerivedVisibility(sync_level)) {
            ctx.apply_mutex.lockExclusive();
            defer ctx.apply_mutex.unlockExclusive();
            if (sync_level == .full_text) {
                try applyDerivedBatchTargetsContext(ctx, derived_batch, sync_targets.full_text_indexes);
            } else {
                try applyDerivedBatchContext(ctx, derived_batch);
            }
        }
        try waitForSyncLevelContext(ctx, sync_level, sequence, sync_targets);
    }
    if (ctx.enrichment_runtime) |runtime| runtime.notifySequence(sequence);
}

fn deleteExpiredDocumentsFromCandidates(ctx_ptr: *anyopaque, candidates: []const ttl_runtime_mod.DeleteCandidate) !u32 {
    const ctx: *TtlCleanupContext = @ptrCast(@alignCast(ctx_ptr));
    const loaded_schema = try schema_mod.loadSchema(ctx.batch.store, ctx.batch.alloc);
    defer if (loaded_schema) |schema| schema_mod.freeSchema(ctx.batch.alloc, schema);

    const duration_ns = if (loaded_schema) |schema|
        schema.ttl_duration_ns
    else
        0;
    if (duration_ns == 0) return 0;

    const now_ns = currentTimeNs();
    var deletes = std.ArrayListUnmanaged([]const u8).empty;
    defer deletes.deinit(ctx.batch.alloc);

    for (candidates) |candidate| {
        const current_ts = (try ttl_mod.readTimestamp(ctx.batch.store, ctx.batch.alloc, candidate.key)) orelse continue;
        if (current_ts != candidate.timestamp_ns) continue;
        if (!ttl_mod.isExpiredWithGrace(current_ts, duration_ns, ctx.grace_period_ns, now_ns)) continue;
        try deletes.append(ctx.batch.alloc, candidate.key);
    }
    if (deletes.items.len == 0) return 0;

    try executeDeleteBatchContext(&ctx.batch, deletes.items, .full_index);
    return @intCast(deletes.items.len);
}

fn appendDerivedBatchRecord(self: *DB, batch: derived_types.DerivedBatch) !u64 {
    var ctx = self.batchContext();
    return try appendDerivedBatchRecordContext(&ctx, batch);
}

fn appendDerivedBatchRecordContext(ctx: *const BatchExecutionContext, batch: derived_types.DerivedBatch) !u64 {
    const sequence = ctx.store.reserveNextReplaySequence(1);
    const payload = try encodeChangeRecordPayload(ctx, batch, sequence);
    defer ctx.alloc.free(payload);
    try ctx.store.appendReplayOpaque(ctx.alloc, sequence, payload);
    ctx.executor.trackBacklogBytes(sequence, @intCast(payload.len)) catch {};
    return sequence;
}

fn encodeChangeRecordPayload(ctx: *const BatchExecutionContext, batch: derived_types.DerivedBatch, sequence: u64) ![]u8 {
    var record = try change_journal_mod.recordFromDerivedBatch(ctx.alloc, batch, sequence);
    defer change_journal_mod.deinitRecord(ctx.alloc, &record);
    return try change_journal_mod.encodeRecord(ctx.alloc, record);
}

fn applyDerivedBacklogPressureContext(ctx: *const BatchExecutionContext, sequence: u64, sync_level: types.SyncLevel, sync_targets: ManagedSyncTargets) !void {
    if (!ctx.executor.shouldThrottleBacklog()) return;
    if (sync_level == .full_text) {
        try runDerivedUntilTargetsContext(ctx, sequence, sync_targets.full_text_indexes);
        return;
    }
    if (shouldDeferBacklogPressureForExternalDenseBulk(ctx, sync_level)) return;
    runDerivedUntilContext(ctx, sequence) catch |err| switch (err) {
        error.WriterLocked, error.ReplayDocumentNotVisible => {
            ctx.executor.notifySequence(sequence);
            return;
        },
        else => return err,
    };
}

fn shouldDeferBacklogPressureForExternalDenseBulk(ctx: *const BatchExecutionContext, sync_level: types.SyncLevel) bool {
    switch (sync_level) {
        .propose, .write, .enrichments => {},
        .full_text, .aknn, .full_index => return false,
    }
    const async_context = ctx.async_context orelse return false;
    return async_context.active_external_dense_bulk_sessions.load(.acquire) != 0;
}

fn runDerivedUntilContext(ctx: *const BatchExecutionContext, sequence: u64) !void {
    if (sequence == 0) return;
    if (!ctx.executor.hasWorkers()) {
        try replayPendingDerivedBatchesContext(ctx);
        return;
    }
    ctx.executor.notifySequence(sequence);
    try ctx.executor.waitForAll(sequence);
}

fn runDerivedUntilTargetsContext(ctx: *const BatchExecutionContext, sequence: u64, index_names: []const []const u8) !void {
    if (sequence == 0 or index_names.len == 0) return;
    if (!ctx.executor.hasWorkers()) return;
    ctx.executor.notifyIndexes(sequence, index_names);
    try ctx.executor.waitForIndexes(sequence, index_names);
}

fn runEnrichmentUntilContext(ctx: *const BatchExecutionContext, sequence: u64) !void {
    if (sequence == 0) return;
    if (ctx.enrichment_runtime) |runtime| {
        runtime.notifySequence(sequence);
        try runtime.waitForApplied(sequence);
    }
}

fn runMaintenanceUntilContext(ctx: *const BatchExecutionContext, sequence: u64, sync_targets: ManagedSyncTargets) !void {
    var stable_target = sequence;
    while (true) {
        try runDerivedUntilContext(ctx, stable_target);
        try runEnrichmentUntilContext(ctx, stable_target);

        const next_target = currentReplayTargetSequenceContext(ctx);
        if (next_target <= stable_target) {
            try waitForManagedIndexesAppliedContext(ctx, sequence, sync_targets.all_indexes);
            return;
        }
        stable_target = next_target;
    }
}

fn runMaintenanceUntilTargetsContext(ctx: *const BatchExecutionContext, sequence: u64, index_names: []const []const u8) !void {
    if (index_names.len == 0) return;
    var stable_target = sequence;
    while (true) {
        try runDerivedUntilTargetsContext(ctx, stable_target, index_names);
        try runEnrichmentUntilContext(ctx, stable_target);

        const next_target = currentReplayTargetSequenceContext(ctx);
        if (next_target <= stable_target) {
            try waitForManagedIndexesAppliedContext(ctx, sequence, index_names);
            return;
        }
        stable_target = next_target;
    }
}

fn currentReplayTargetSequenceContext(ctx: *const BatchExecutionContext) u64 {
    return ctx.store.lastReplaySequence(0);
}

fn waitForSyncLevelContext(ctx: *const BatchExecutionContext, sync_level: types.SyncLevel, sequence: u64, sync_targets: ManagedSyncTargets) !void {
    switch (sync_level) {
        .propose, .write => try ctx.executor.failIfUnhealthy(),
        .enrichments => {
            try ctx.executor.failIfUnhealthy();
            try runEnrichmentUntilContext(ctx, sequence);
        },
        .full_text => {
            try runMaintenanceUntilTargetsContext(ctx, sequence, sync_targets.full_text_indexes);
        },
        .aknn, .full_index => try runMaintenanceUntilContext(ctx, sequence, sync_targets),
    }
}

fn syncLevelRequiresDerivedVisibility(sync_level: types.SyncLevel) bool {
    return switch (sync_level) {
        .propose, .write, .enrichments => false,
        .full_text, .aknn, .full_index => true,
    };
}

fn denseCatchUpFinishOptions() backend_types.BulkIngestFinishOptions {
    return .{
        .compact = false,
        .flush = true,
        .max_deferred_l0_runs = denseCatchUpDeferredL0Limit(),
        .max_deferred_hbc_leaf_splits_per_publish = denseCatchUpDeferredHbcLeafSplitsPerPublish(),
        .max_deferred_hbc_leaf_split_members_per_publish = denseCatchUpDeferredHbcLeafSplitMembersPerPublish(),
        .bulk_rebuild_hbc_leaf_min_members = denseCatchUpBulkRebuildHbcLeafMinMembers(),
    };
}

