    try db.batch(.{
        .writes = &.{
            .{ .key = "doc:a", .value = "{\"sparse\":{\"indices\":[0,2],\"values\":[0.9,0.1]},\"title\":\"alpha\"}" },
            .{ .key = "doc:b", .value = "{\"sparse\":{\"indices\":[1],\"values\":[0.9]},\"title\":\"beta\"}" },
        },
    });

    try db.addIndex(.{
