        .kind = .graph,
        .config_json = "{}",
    });

    try db.batch(.{
        .writes = &.{
            .{ .key = "doc:a", .value = "{\"title\":\"A\",\"_edges\":{\"gr_v1\":{\"links\":[{\"target\":\"doc:b\"}]}}}" },
            .{ .key = "doc:b", .value = "{\"title\":\"B\",\"_edges\":{\"gr_v1\":{\"links\":[{\"target\":\"doc:c\"}]}}}" },
