        \\    "product": {
        \\      "schema": {
        \\        "type": "object",
        \\        "additionalProperties": true,
        \\        "properties": {
        \\          "name": {
        \\            "type": "string",
        \\            "x-antfly-types": ["search_as_you_type"]
        \\          }
        \\        }
        \\      }
        \\    }
        \\  }
        \\}
