    try std.testing.expect(std.mem.indexOf(u8, result.documents[0].json, "\"body\"") == null);
}

test "db updateRange constrains index backfill" {
    const alloc = std.testing.allocator;

    var path_buf: [256]u8 = undefined;
    const path = tempPath(&path_buf);
    defer cleanupTempDir(path);

    var db = try DB.open(alloc, std.mem.span(path), .{});
    defer db.close();

    const doc_a_key = try internal_keys.documentKeyAlloc(alloc, "doc:a");
    defer alloc.free(doc_a_key);
    const doc_b_key = try internal_keys.documentKeyAlloc(alloc, "doc:b");
    defer alloc.free(doc_b_key);
    const doc_c_key = try internal_keys.documentKeyAlloc(alloc, "doc:c");
    defer alloc.free(doc_c_key);
    try db.core.store.put(doc_a_key, "{\"title\":\"alpha\"}");
    try db.core.store.put(doc_b_key, "{\"title\":\"beta\"}");
    try db.core.store.put(doc_c_key, "{\"title\":\"gamma\"}");

    try db.updateRange(.{ .start = "doc:b", .end = "doc:c\xff" });
    try db.addIndex(.{
        .name = "ft_range",
        .kind = .full_text,
        .config_json = "{\"store\":true}",
    });

    const text_index = db.core.index_manager.textIndex("ft_range").?;
    try std.testing.expectEqual(@as(u32, 2), text_index.snapshot().global_doc_count);
}

test "db dense startup catch-up defaults keep more than one cache entry" {
    try std.testing.expect(denseCatchUpStartupCacheNodes() > 1);
    try std.testing.expect(denseCatchUpStartupCacheVectors() > 1);
}

fn applyStoredSearchPatternFilters(self: *DB, alloc: Allocator, req: types.SearchRequest, result: types.SearchResult) !types.SearchResult {
    return try db_query_result_shape.applyStoredSearchPatternFilters(alloc, req, result, .{
        .ctx = self,
        .load_stored = loadStoredSearchDocumentCallback,
        .resolve_doc_set_doc_ids = DB.resolveDocSetDocIdsCallback,
        .resolve_doc_ids_to_doc_set = DB.resolveDocIdsToDocSetCallback,
    });
}

fn loadStoredSearchDocumentCallback(
    ctx: ?*anyopaque,
    alloc: Allocator,
    key: []const u8,
) anyerror!?[]u8 {
    const self: *DB = @ptrCast(@alignCast(ctx orelse return error.InvalidArgument));
    return try self.loadStoredSearchDocumentProbe(alloc, key);
}

fn loadStoredSearchDocumentManyCallback(
    ctx: ?*anyopaque,
    alloc: Allocator,
    keys: []const []const u8,
) anyerror![]?[]u8 {
    const self: *DB = @ptrCast(@alignCast(ctx orelse return error.InvalidArgument));
    return try loadStoredSearchDocumentsMany(self, alloc, keys);
}

test "relational table full-text search reconstructs stored_data from columns" {
    const alloc = std.testing.allocator;
    const table_schema_api = @import("../../schema/mod.zig");

    var path_buf: [256]u8 = undefined;
    const path = tempPath(&path_buf);
    defer cleanupTempDir(path);

    var db = try DB.open(alloc, std.mem.span(path), .{});
    defer db.close();

    // Relational schema: typed columns persisted as typed_doc_values so the
    // document is reconstructed from columns rather than the segment blob.
    const schema_json =
        \\{"version":1,"storage_mode":"relational","default_type":"row","enforce_types":true,"document_schemas":{"row":{"schema":{"type":"object","properties":{"title":{"type":"text"},"amount":{"type":"numeric"},"active":{"type":"boolean"}},"required":["title"],"additionalProperties":false}}}}
    ;
    var parsed_schema = try table_schema_api.parseValidatedTableSchema(alloc, schema_json);
    defer parsed_schema.deinit(alloc);
    const runtime_schema = try table_schema_api.deriveRuntimeTableSchema(alloc, parsed_schema);
    defer schema_mod.freeSchema(alloc, runtime_schema);
    try db.setSchema(runtime_schema);

    try db.addIndex(.{
        .name = "ft_v1",
        .kind = .full_text,
        .config_json = "{}",
    });
    try db.batch(.{
        .writes = &.{.{
            .key = "row:a",
            .value =
            \\{"title":"hello world","amount":42.5,"active":true}
            ,
        }},
        .sync_level = .full_index,
    });

    var result = try db.search(alloc, .{
        .index_name = "ft_v1",
        .query = .{ .match = .{ .field = "title", .text = "hello" } },
        .include_stored = true,
    });
    defer result.deinit();

    try std.testing.expectEqual(@as(u32, 1), result.total_hits);
    try std.testing.expect(result.hits[0].stored_data != null);

    // stored_data was reconstructed from the persisted typed columns.
    const parsed = try std.json.parseFromSlice(std.json.Value, alloc, result.hits[0].stored_data.?, .{});
    defer parsed.deinit();
    const obj = parsed.value.object;
    try std.testing.expectEqualStrings("hello world", obj.get("title").?.string);
    const amount = obj.get("amount").?;
    const amount_num: f64 = switch (amount) {
        .float => |f| f,
        .integer => |n| @floatFromInt(n),
        else => unreachable,
    };
    try std.testing.expectEqual(@as(f64, 42.5), amount_num);
    try std.testing.expect(obj.get("active").?.bool);
}
